UPDATE words SET example_en_2 = 'She was warned about plagiarism at the start of the semester.', example_ko_2 = '그녀는 학기 초에 표절에 대한 경고를 받았어요.', example_en_3 = 'He accidentally committed plagiarism by forgetting to cite a source.', example_ko_3 = '그는 출처 인용을 잊어 실수로 표절을 저질렀어요.', example_en_4 = 'Plagiarism detection tools are used by most universities now.', example_ko_4 = '표절 탐지 도구는 이제 대부분의 대학에서 사용돼요.', example_en_5 = 'She learned to properly quote and cite to avoid plagiarism.', example_ko_5 = '그녀는 표절을 피하기 위해 올바르게 인용하는 방법을 배웠어요.' WHERE id = 'w_education_B1_35';

-- C1
UPDATE words SET example_en_2 = 'She took a course on epistemology to understand how we know things.', example_ko_2 = '그녀는 우리가 어떻게 사물을 아는지 이해하기 위해 인식론 수업을 들었어요.', example_en_3 = 'Epistemology is central to research design in academic studies.', example_ko_3 = '인식론은 학문 연구 설계에서 핵심적이에요.', example_en_4 = 'He used epistemological arguments to question the validity of the data.', example_ko_4 = '그는 인식론적 주장을 사용해 데이터의 타당성에 의문을 제기했어요.', example_en_5 = 'Understanding epistemology helps researchers clarify their assumptions.', example_ko_5 = '인식론을 이해하면 연구자들이 자신의 가정을 명확히 하는 데 도움이 돼요.' WHERE id = 'w_education_C1_01';
UPDATE words SET example_en_2 = 'She explored different pedagogies for teaching language skills.', example_ko_2 = '그녀는 언어 능력을 가르치기 위한 다양한 교육학을 탐구했어요.', example_en_3 = 'His pedagogy focuses on student collaboration and active learning.', example_ko_3 = '그의 교육학은 학생 협력과 능동적 학습에 초점을 맞춰요.', example_en_4 = 'Critical pedagogy encourages students to question power structures.', example_ko_4 = '비판적 교육학은 학생들이 권력 구조에 의문을 갖도록 장려해요.', example_en_5 = 'Innovative pedagogy can make even difficult subjects accessible.', example_ko_5 = '혁신적인 교육학은 어려운 과목도 쉽게 접근할 수 있게 만들 수 있어요.' WHERE id = 'w_education_C1_02';
UPDATE words SET example_en_2 = 'She described the shift to online learning as a new pedagogical paradigm.', example_ko_2 = '그녀는 온라인 학습으로의 전환을 새로운 교육학적 패러다임으로 묘사했어요.', example_en_3 = 'Kuhn''s concept of paradigm shifts is widely applied in education.', example_ko_3 = '쿤의 패러다임 전환 개념은 교육 분야에서 널리 적용돼요.', example_en_4 = 'He challenged the dominant paradigm in educational assessment.', example_ko_4 = '그는 교육 평가에서 지배적인 패러다임에 도전했어요.', example_en_5 = 'A shift in paradigm can transform an entire field of study.', example_ko_5 = '패러다임 전환은 전체 학문 분야를 변화시킬 수 있어요.' WHERE id = 'w_education_C1_03';
UPDATE words SET example_en_2 = 'She used dialectic reasoning to explore opposing views on the topic.', example_ko_2 = '그녀는 주제에 대한 반대 견해를 탐구하기 위해 변증법적 추론을 사용했어요.', example_en_3 = 'The dialectic between tradition and innovation drives educational reform.', example_ko_3 = '전통과 혁신 사이의 변증법이 교육 개혁을 이끌어요.', example_en_4 = 'He structured his seminar as a Socratic dialectic.', example_ko_4 = '그는 세미나를 소크라테스식 변증법으로 구성했어요.', example_en_5 = 'Understanding dialectic helps students engage with complex arguments.', example_ko_5 = '변증법을 이해하면 학생들이 복잡한 주장을 다루는 데 도움이 돼요.' WHERE id = 'w_education_C1_04';
UPDATE words SET example_en_2 = 'She applied hermeneutics to interpret historical educational texts.', example_ko_2 = '그녀는 역사적인 교육 텍스트를 해석하기 위해 해석학을 적용했어요.', example_en_3 = 'Hermeneutics explores how context shapes the meaning of a text.', example_ko_3 = '해석학은 맥락이 텍스트의 의미를 어떻게 형성하는지를 탐구해요.', example_en_4 = 'He used hermeneutical analysis in his qualitative research.', example_ko_4 = '그는 질적 연구에서 해석학적 분석을 사용했어요.', example_en_5 = 'Hermeneutics reminds us that interpretation is always influenced by perspective.', example_ko_5 = '해석학은 해석이 항상 관점에 의해 영향받는다는 것을 상기시켜요.' WHERE id = 'w_education_C1_05';
UPDATE words SET example_en_2 = 'She designed lessons based on constructivism to make learning active.', example_ko_2 = '그녀는 학습을 능동적으로 만들기 위해 구성주의에 기반한 수업을 설계했어요.', example_en_3 = 'Constructivism argues that learners build knowledge through experience.', example_ko_3 = '구성주의는 학습자가 경험을 통해 지식을 구성한다고 주장해요.', example_en_4 = 'He studied Vygotsky''s influence on educational constructivism.', example_ko_4 = '그는 교육적 구성주의에 대한 비고츠키의 영향을 연구했어요.', example_en_5 = 'Constructivism supports project-based and inquiry-driven learning.', example_ko_5 = '구성주의는 프로젝트 기반 및 탐구 중심 학습을 지원해요.' WHERE id = 'w_education_C1_06';
UPDATE words SET example_en_2 = 'She questioned the positivism underlying standardized test design.', example_ko_2 = '그녀는 표준화 시험 설계의 기반이 되는 실증주의에 의문을 가졌어요.', example_en_3 = 'Positivism assumes that knowledge comes from measurable, observable facts.', example_ko_3 = '실증주의는 지식이 측정 가능하고 관찰 가능한 사실에서 비롯된다고 가정해요.', example_en_4 = 'He adopted a positivist approach in his quantitative research.', example_ko_4 = '그는 양적 연구에서 실증주의적 접근법을 채택했어요.', example_en_5 = 'Many critics argue that positivism oversimplifies human learning.', example_ko_5 = '많은 비평가들은 실증주의가 인간 학습을 지나치게 단순화한다고 주장해요.' WHERE id = 'w_education_C1_07';
UPDATE words SET example_en_2 = 'She explored the ontology behind different theories of learning.', example_ko_2 = '그녀는 다양한 학습 이론의 바탕이 되는 존재론을 탐구했어요.', example_en_3 = 'Ontology deals with the nature of being and existence.', example_ko_3 = '존재론은 존재와 실재의 본질을 다뤄요.', example_en_4 = 'He clarified his ontological position at the start of his thesis.', example_ko_4 = '그는 논문의 시작 부분에서 자신의 존재론적 입장을 명확히 했어요.', example_en_5 = 'A researcher''s ontology shapes their choice of methodology.', example_ko_5 = '연구자의 존재론은 방법론 선택을 형성해요.' WHERE id = 'w_education_C1_08';
UPDATE words SET example_en_2 = 'She questioned the axioms underlying the traditional grading system.', example_ko_2 = '그녀는 전통적인 성적 시스템의 기반이 되는 공리에 의문을 가졌어요.', example_en_3 = 'An axiom is a statement accepted as true without proof.', example_ko_3 = '공리는 증명 없이 참으로 받아들여지는 명제예요.', example_en_4 = 'He built his argument on the axiom that all students can learn.', example_ko_4 = '그는 모든 학생이 배울 수 있다는 공리 위에 자신의 주장을 세웠어요.', example_en_5 = 'Identifying hidden axioms in education reveals underlying assumptions.', example_ko_5 = '교육에서 숨겨진 공리를 파악하면 기저에 있는 가정을 드러낼 수 있어요.' WHERE id = 'w_education_C1_09';
UPDATE words SET example_en_2 = 'She used deductive reasoning to apply theory to her classroom observations.', example_ko_2 = '그녀는 이론을 교실 관찰에 적용하기 위해 연역적 추론을 사용했어요.', example_en_3 = 'Deductive logic moves from general principles to specific conclusions.', example_ko_3 = '연역 논리는 일반적인 원칙에서 특정한 결론으로 이동해요.', example_en_4 = 'He designed a deductive unit that started with a theory and tested examples.', example_ko_4 = '그는 이론으로 시작해 예시를 검증하는 연역적 단원을 설계했어요.', example_en_5 = 'Deductive and inductive methods complement each other in research.', example_ko_5 = '연역적 방법과 귀납적 방법은 연구에서 서로 보완해요.' WHERE id = 'w_education_C1_10';
UPDATE words SET example_en_2 = 'She favored an inductive approach, starting from student observations.', example_ko_2 = '그녀는 학생 관찰에서 시작하는 귀납적 접근법을 선호했어요.', example_en_3 = 'Inductive reasoning draws general principles from specific examples.', example_ko_3 = '귀납적 추론은 구체적인 예시에서 일반적인 원칙을 이끌어 내요.', example_en_4 = 'He taught students to think inductively before reaching conclusions.', example_ko_4 = '그는 학생들에게 결론에 이르기 전에 귀납적으로 생각하는 법을 가르쳤어요.', example_en_5 = 'Inductive methods are common in qualitative educational research.', example_ko_5 = '귀납적 방법은 질적 교육 연구에서 자주 사용돼요.' WHERE id = 'w_education_C1_11';
UPDATE words SET example_en_2 = 'She embedded critical thinking tasks into every lesson.', example_ko_2 = '그녀는 모든 수업에 비판적 사고 과제를 포함시켰어요.', example_en_3 = 'Critical thinking requires analyzing evidence before forming judgments.', example_ko_3 = '비판적 사고는 판단을 내리기 전에 증거를 분석하는 것이 필요해요.', example_en_4 = 'He argued that critical thinking is more important than memorizing facts.', example_ko_4 = '그는 비판적 사고가 사실 암기보다 더 중요하다고 주장했어요.', example_en_5 = 'Developing critical thinking helps students evaluate sources carefully.', example_ko_5 = '비판적 사고를 발전시키면 학생들이 출처를 신중하게 평가하는 데 도움이 돼요.' WHERE id = 'w_education_C1_12';
UPDATE words SET example_en_2 = 'She taught a useful heuristic for solving multi-step problems.', example_ko_2 = '그녀는 다단계 문제를 해결하는 데 유용한 발견적 방법을 가르쳤어요.', example_en_3 = 'Heuristics are mental shortcuts that help us make faster decisions.', example_ko_3 = '발견적 방법은 더 빠른 결정을 내리는 데 도움이 되는 정신적 지름길이에요.', example_en_4 = 'He developed a heuristic for evaluating the quality of sources.', example_ko_4 = '그는 출처의 품질을 평가하기 위한 발견적 방법을 개발했어요.', example_en_5 = 'Teaching heuristics empowers students to solve problems independently.', example_ko_5 = '발견적 방법을 가르치면 학생들이 독립적으로 문제를 해결할 수 있게 해요.' WHERE id = 'w_education_C1_13';
UPDATE words SET example_en_2 = 'She encouraged metacognition by asking students to reflect on their thinking.', example_ko_2 = '그녀는 학생들에게 자신의 사고를 되돌아보도록 하여 초인지를 장려했어요.', example_en_3 = 'Metacognition means thinking about how you think and learn.', example_ko_3 = '초인지는 자신이 어떻게 생각하고 배우는지를 생각하는 것이에요.', example_en_4 = 'He designed a journal activity to promote metacognition.', example_ko_4 = '그는 초인지를 촉진하기 위한 일지 활동을 설계했어요.', example_en_5 = 'Students with strong metacognition can adjust their study strategies.', example_ko_5 = '강한 초인지를 가진 학생들은 학습 전략을 조정할 수 있어요.' WHERE id = 'w_education_C1_14';
UPDATE words SET example_en_2 = 'She provided scaffolding to help weaker students complete the task.', example_ko_2 = '그녀는 성적이 낮은 학생들이 과제를 완성할 수 있도록 비계를 제공했어요.', example_en_3 = 'Scaffolding is gradually removed as students become more capable.', example_ko_3 = '학생들이 더 능숙해지면서 비계는 점점 제거돼요.', example_en_4 = 'He used sentence frames as scaffolding for writing tasks.', example_ko_4 = '그는 쓰기 과제에서 비계로 문장 틀을 사용했어요.', example_en_5 = 'Effective scaffolding bridges the gap between current and target skills.', example_ko_5 = '효과적인 비계는 현재 능력과 목표 능력 사이의 간극을 연결해요.' WHERE id = 'w_education_C1_15';
UPDATE words SET example_en_2 = 'She gave students autonomy to choose their own research topics.', example_ko_2 = '그녀는 학생들에게 자신의 연구 주제를 선택할 자율성을 부여했어요.', example_en_3 = 'Learner autonomy is essential for lifelong learning.', example_ko_3 = '학습자 자율성은 평생 학습에 필수적이에요.', example_en_4 = 'He designed the course to gradually increase student autonomy.', example_ko_4 = '그는 학생의 자율성을 점진적으로 높이기 위해 과정을 설계했어요.', example_en_5 = 'Developing autonomy in learning prepares students for real-world challenges.', example_ko_5 = '학습에서 자율성을 키우면 학생들이 실제 세계의 과제에 대비하게 해줘요.' WHERE id = 'w_education_C1_16';
UPDATE words SET example_en_2 = 'She studied the acculturation of international students in local schools.', example_ko_2 = '그녀는 지역 학교에서 유학생들의 문화 적응을 연구했어요.', example_en_3 = 'Acculturation describes how people adapt to a new cultural environment.', example_ko_3 = '문화 적응은 사람들이 새로운 문화 환경에 어떻게 적응하는지를 설명해요.', example_en_4 = 'He explored the challenges of acculturation in multicultural classrooms.', example_ko_4 = '그는 다문화 교실에서 문화 적응의 어려움을 탐구했어요.', example_en_5 = 'Acculturation can be a gradual process that takes years to complete.', example_ko_5 = '문화 적응은 완성하는 데 몇 년이 걸리는 점진적인 과정일 수 있어요.' WHERE id = 'w_education_C1_17';
UPDATE words SET example_en_2 = 'She used triangulation to confirm her qualitative findings.', example_ko_2 = '그녀는 질적 연구 결과를 확인하기 위해 삼각검증을 사용했어요.', example_en_3 = 'Triangulation involves combining multiple methods to improve validity.', example_ko_3 = '삼각검증은 타당성을 높이기 위해 여러 방법을 결합하는 것이에요.', example_en_4 = 'He triangulated the data using interviews, observations, and documents.', example_ko_4 = '그는 인터뷰, 관찰, 문서를 사용해 데이터를 삼각검증했어요.', example_en_5 = 'Triangulation strengthens the credibility of research findings.', example_ko_5 = '삼각검증은 연구 결과의 신뢰성을 강화해요.' WHERE id = 'w_education_C1_18';
UPDATE words SET example_en_2 = 'She practiced reflexivity by acknowledging her own biases in the study.', example_ko_2 = '그녀는 연구에서 자신의 편향을 인정함으로써 반사성을 실천했어요.', example_en_3 = 'Reflexivity requires researchers to examine how their background affects their work.', example_ko_3 = '반사성은 연구자들이 자신의 배경이 연구에 어떻게 영향을 미치는지를 검토하도록 요구해요.', example_en_4 = 'He wrote a reflexivity statement in the methodology section.', example_ko_4 = '그는 방법론 섹션에 반사성 진술을 작성했어요.', example_en_5 = 'Reflexivity is a hallmark of rigorous qualitative research.', example_ko_5 = '반사성은 엄격한 질적 연구의 특징이에요.' WHERE id = 'w_education_C1_19';
UPDATE words SET example_en_2 = 'She made her epistemological assumptions explicit in her thesis.', example_ko_2 = '그녀는 논문에서 자신의 인식론적 가정을 명시적으로 밝혔어요.', example_en_3 = 'His epistemological stance influenced his choice of research method.', example_ko_3 = '그의 인식론적 입장이 연구 방법 선택에 영향을 미쳤어요.', example_en_4 = 'Epistemological questions ask what counts as valid knowledge.', example_ko_4 = '인식론적 질문은 무엇이 유효한 지식으로 인정되는지를 묻는 것이에요.', example_en_5 = 'Epistemological differences lead to different research traditions.', example_ko_5 = '인식론적 차이는 서로 다른 연구 전통으로 이어져요.' WHERE id = 'w_education_C1_20';
UPDATE words SET example_en_2 = 'She questioned the normative assumptions in educational policy.', example_ko_2 = '그녀는 교육 정책의 규범적 가정에 의문을 가졌어요.', example_en_3 = 'Normative claims tell us what ought to be, not just what is.', example_ko_3 = '규범적 주장은 단지 사실이 무엇인지가 아니라 무엇이어야 하는지를 말해요.', example_en_4 = 'He challenged the normative view that exams measure intelligence.', example_ko_4 = '그는 시험이 지능을 측정한다는 규범적 견해에 도전했어요.', example_en_5 = 'Education is full of normative decisions about what counts as success.', example_ko_5 = '교육은 무엇이 성공인지에 대한 규범적 결정으로 가득해요.' WHERE id = 'w_education_C1_21';
UPDATE words SET example_en_2 = 'She valued praxis as the integration of theory and action in teaching.', example_ko_2 = '그녀는 교수에서 이론과 실천의 통합으로서 프락시스를 소중히 여겼어요.', example_en_3 = 'Freire''s concept of praxis connects reflection and transformative action.', example_ko_3 = '프레이리의 프락시스 개념은 성찰과 변혁적 행동을 연결해요.', example_en_4 = 'He designed a praxis-based curriculum for teacher training.', example_ko_4 = '그는 교사 연수를 위한 프락시스 기반 교육과정을 설계했어요.', example_en_5 = 'Praxis encourages educators to reflect critically on their practice.', example_ko_5 = '프락시스는 교육자들이 자신의 실천을 비판적으로 성찰하도록 장려해요.' WHERE id = 'w_education_C1_22';
UPDATE words SET example_en_2 = 'She used discourse analysis to study textbook representations of gender.', example_ko_2 = '그녀는 교과서의 젠더 표현을 연구하기 위해 담론 분석을 사용했어요.', example_en_3 = 'Discourse analysis examines how language constructs meaning and power.', example_ko_3 = '담론 분석은 언어가 어떻게 의미와 권력을 구성하는지를 살펴봐요.', example_en_4 = 'He applied discourse analysis to policy documents in education.', example_ko_4 = '그는 교육 정책 문서에 담론 분석을 적용했어요.', example_en_5 = 'Discourse analysis reveals hidden assumptions in academic texts.', example_ko_5 = '담론 분석은 학문적 텍스트의 숨겨진 가정을 드러내요.' WHERE id = 'w_education_C1_23';
UPDATE words SET example_en_2 = 'She addressed the generalisability of her case study findings.', example_ko_2 = '그녀는 사례 연구 결과의 일반화 가능성을 다뤘어요.', example_en_3 = 'Generalisability asks whether findings apply to other contexts.', example_ko_3 = '일반화 가능성은 연구 결과가 다른 맥락에도 적용되는지를 묻는 것이에요.', example_en_4 = 'He acknowledged the limited generalisability of a small qualitative study.', example_ko_4 = '그는 소규모 질적 연구의 제한된 일반화 가능성을 인정했어요.', example_en_5 = 'Improving generalisability often requires larger and more diverse samples.', example_ko_5 = '일반화 가능성을 높이려면 더 크고 다양한 표본이 필요한 경우가 많아요.' WHERE id = 'w_education_C1_24';
UPDATE words SET example_en_2 = 'She checked the validity of her assessment tool through peer review.', example_ko_2 = '그녀는 동료 검토를 통해 평가 도구의 타당성을 확인했어요.', example_en_3 = 'Validity measures whether a study actually tests what it claims to test.', example_ko_3 = '타당성은 연구가 주장하는 것을 실제로 검증하는지를 측정해요.', example_en_4 = 'He used member checking to improve the validity of his interview data.', example_ko_4 = '그는 인터뷰 데이터의 타당성을 높이기 위해 회원 검증을 사용했어요.', example_en_5 = 'Validity is essential for research to be meaningful and trustworthy.', example_ko_5 = '타당성은 연구가 의미 있고 신뢰할 수 있게 하기 위해 필수적이에요.' WHERE id = 'w_education_C1_25';
UPDATE words SET example_en_2 = 'She ran a pilot study to test the reliability of her questionnaire.', example_ko_2 = '그녀는 설문지의 신뢰성을 검증하기 위해 예비 조사를 실시했어요.', example_en_3 = 'Reliability ensures that a test produces consistent results.', example_ko_3 = '신뢰성은 검사가 일관된 결과를 생성하도록 보장해요.', example_en_4 = 'He calculated inter-rater reliability to ensure consistency.', example_ko_4 = '그는 일관성을 보장하기 위해 평가자 간 신뢰성을 계산했어요.', example_en_5 = 'High reliability is especially important in standardized testing.', example_ko_5 = '높은 신뢰성은 표준화 시험에서 특히 중요해요.' WHERE id = 'w_education_C1_26';
UPDATE words SET example_en_2 = 'She attempted replication of a landmark study in a different context.', example_ko_2 = '그녀는 다른 맥락에서 획기적인 연구를 반복 검증하려 했어요.', example_en_3 = 'Replication tests whether findings can be reproduced.', example_ko_3 = '반복 검증은 연구 결과가 재현될 수 있는지를 검증해요.', example_en_4 = 'He found that the original results did not hold up under replication.', example_ko_4 = '그는 원래 결과가 반복 검증에서 유효하지 않음을 발견했어요.', example_en_5 = 'Replication studies are essential for building robust scientific knowledge.', example_ko_5 = '반복 검증 연구는 견고한 과학 지식을 구축하는 데 필수적이에요.' WHERE id = 'w_education_C1_27';
UPDATE words SET example_en_2 = 'She only cited peer-reviewed sources in her literature review.', example_ko_2 = '그녀는 문헌 검토에서 동료 심사를 거친 출처만 인용했어요.', example_en_3 = 'Peer-reviewed articles are evaluated by experts before publication.', example_ko_3 = '동료 심사 논문은 출판 전에 전문가들에 의해 평가받아요.', example_en_4 = 'He submitted his paper to a peer-reviewed journal.', example_ko_4 = '그는 동료 심사 학술지에 논문을 제출했어요.', example_en_5 = 'The peer-reviewed publication process maintains academic standards.', example_ko_5 = '동료 심사 출판 과정은 학문적 기준을 유지해요.' WHERE id = 'w_education_C1_28';
UPDATE words SET example_en_2 = 'She developed a conceptual framework to guide her data analysis.', example_ko_2 = '그녀는 데이터 분석을 안내하기 위한 개념적 틀을 개발했어요.', example_en_3 = 'A conceptual framework links theory to a specific research study.', example_ko_3 = '개념적 틀은 이론을 특정 연구 연구와 연결해요.', example_en_4 = 'He explained his conceptual framework clearly in chapter two.', example_ko_4 = '그는 2장에서 자신의 개념적 틀을 명확히 설명했어요.', example_en_5 = 'A strong conceptual framework makes research more coherent.', example_ko_5 = '강한 개념적 틀은 연구를 더 일관성 있게 만들어요.' WHERE id = 'w_education_C1_29';
UPDATE words SET example_en_2 = 'She spent two months completing her literature review.', example_ko_2 = '그녀는 두 달 동안 문헌 검토를 완성하는 데 시간을 보냈어요.', example_en_3 = 'A literature review situates your research within existing knowledge.', example_ko_3 = '문헌 검토는 연구를 기존 지식 안에 위치시켜요.', example_en_4 = 'He identified a gap in the literature through his review.', example_ko_4 = '그는 문헌 검토를 통해 연구의 공백을 발견했어요.', example_en_5 = 'A thorough literature review demonstrates academic rigor.', example_ko_5 = '철저한 문헌 검토는 학문적 엄격성을 보여줘요.' WHERE id = 'w_education_C1_30';
UPDATE words SET example_en_2 = 'She used purposive sampling to select experienced teachers.', example_ko_2 = '그녀는 경험 많은 교사를 선택하기 위해 목적 표집을 사용했어요.', example_en_3 = 'Sampling is a key decision in any research methodology.', example_ko_3 = '표집은 모든 연구 방법론에서 핵심적인 결정이에요.', example_en_4 = 'He justified his sampling strategy in the methods section.', example_ko_4 = '그는 방법론 섹션에서 자신의 표집 전략을 정당화했어요.', example_en_5 = 'Random sampling improves the generalisability of findings.', example_ko_5 = '무작위 표집은 연구 결과의 일반화 가능성을 높여요.' WHERE id = 'w_education_C1_31';
UPDATE words SET example_en_2 = 'She had to operationalise the concept of engagement for her study.', example_ko_2 = '그녀는 연구를 위해 참여의 개념을 조작적 정의해야 했어요.', example_en_3 = 'To operationalise a concept means to define it in measurable terms.', example_ko_3 = '개념을 조작적 정의한다는 것은 측정 가능한 용어로 정의하는 것이에요.', example_en_4 = 'He operationalised learning outcomes as test scores and portfolio grades.', example_ko_4 = '그는 학습 성과를 시험 점수와 포트폴리오 점수로 조작적 정의했어요.', example_en_5 = 'Operationalising abstract ideas is one of the hardest parts of research design.', example_ko_5 = '추상적인 아이디어를 조작적 정의하는 것은 연구 설계에서 가장 어려운 부분 중 하나예요.' WHERE id = 'w_education_C1_32';
UPDATE words SET example_en_2 = 'She posits that motivation is the key driver of academic achievement.', example_ko_2 = '그녀는 동기가 학업 성취의 핵심 동인이라고 가정해요.', example_en_3 = 'Researchers posit hypotheses that are then tested with data.', example_ko_3 = '연구자들은 데이터로 검증되는 가설을 제시해요.', example_en_4 = 'He posited that the curriculum gap explains performance differences.', example_ko_4 = '그는 교육과정 격차가 성과 차이를 설명한다고 가정했어요.', example_en_5 = 'To posit something is to assert it as a starting assumption.', example_ko_5 = '무언가를 가정한다는 것은 그것을 출발 전제로 주장하는 것이에요.' WHERE id = 'w_education_C1_33';
UPDATE words SET example_en_2 = 'She needed more data to substantiate her main argument.', example_ko_2 = '그녀는 주요 주장을 뒷받침하기 위해 더 많은 데이터가 필요했어요.', example_en_3 = 'Researchers must substantiate their claims with evidence.', example_ko_3 = '연구자들은 자신의 주장을 증거로 뒷받침해야 해요.', example_en_4 = 'He substantiated his theory with three case studies.', example_ko_4 = '그는 세 가지 사례 연구로 자신의 이론을 뒷받침했어요.', example_en_5 = 'Failing to substantiate a claim weakens the overall argument.', example_ko_5 = '주장을 뒷받침하지 못하면 전체 논거가 약해져요.' WHERE id = 'w_education_C1_34';
UPDATE words SET example_en_2 = 'She provided a nuanced interpretation of the survey data.', example_ko_2 = '그녀는 설문 데이터에 대한 미묘한 해석을 제공했어요.', example_en_3 = 'A nuanced argument acknowledges complexity rather than oversimplifying.', example_ko_3 = '미묘한 주장은 지나치게 단순화하기보다는 복잡성을 인정해요.', example_en_4 = 'He gave a nuanced view of both sides of the policy debate.', example_ko_4 = '그는 정책 논쟁의 양쪽 모두에 대한 미묘한 견해를 제시했어요.', example_en_5 = 'Nuanced thinking is one of the goals of advanced education.', example_ko_5 = '미묘한 사고는 고급 교육의 목표 중 하나예요.' WHERE id = 'w_education_C1_35';

-- C2
UPDATE words SET example_en_2 = 'She taught students to use heuristics when approaching open-ended problems.', example_ko_2 = '그녀는 학생들에게 개방형 문제에 접근할 때 발견적 방법을 사용하도록 가르쳤어요.', example_en_3 = 'Heuristics help reduce cognitive load when dealing with complex decisions.', example_ko_3 = '발견적 방법은 복잡한 결정을 다룰 때 인지적 부담을 줄이는 데 도움이 돼요.', example_en_4 = 'He examined how heuristics influence student problem-solving strategies.', example_ko_4 = '그는 발견적 방법이 학생의 문제 해결 전략에 어떤 영향을 미치는지 살펴봤어요.', example_en_5 = 'Understanding heuristics allows educators to design more effective tasks.', example_ko_5 = '발견적 방법을 이해하면 교육자들이 더 효과적인 과제를 설계할 수 있어요.' WHERE id = 'w_education_C2_01';
UPDATE words SET example_en_2 = 'She used phenomenology to explore the lived experience of first-generation students.', example_ko_2 = '그녀는 첫 세대 대학생들의 생생한 경험을 탐구하기 위해 현상학을 사용했어요.', example_en_3 = 'Phenomenology focuses on how individuals experience the world.', example_ko_3 = '현상학은 개인이 세계를 어떻게 경험하는지에 초점을 맞춰요.', example_en_4 = 'He chose phenomenology because he wanted to understand meaning, not just behavior.', example_ko_4 = '그는 행동만이 아닌 의미를 이해하고 싶었기 때문에 현상학을 선택했어요.', example_en_5 = 'Phenomenological research prioritizes depth over breadth.', example_ko_5 = '현상학적 연구는 넓이보다 깊이를 우선시해요.' WHERE id = 'w_education_C2_02';
UPDATE words SET example_en_2 = 'She warned against reductionism in education research.', example_ko_2 = '그녀는 교육 연구에서 환원주의를 경계했어요.', example_en_3 = 'Reductionism tries to explain complex systems through their simplest parts.', example_ko_3 = '환원주의는 복잡한 시스템을 가장 단순한 부분을 통해 설명하려 해요.', example_en_4 = 'He argued that test-based accountability reflects a reductionist view of learning.', example_ko_4 = '그는 시험 기반 책무성이 학습에 대한 환원주의적 관점을 반영한다고 주장했어요.', example_en_5 = 'Moving beyond reductionism means embracing complexity in educational theory.', example_ko_5 = '환원주의를 넘어선다는 것은 교육 이론에서 복잡성을 받아들이는 것이에요.' WHERE id = 'w_education_C2_03';
UPDATE words SET example_en_2 = 'She assessed her hypothesis for falsifiability before the study began.', example_ko_2 = '그녀는 연구 시작 전에 가설의 반증 가능성을 평가했어요.', example_en_3 = 'Falsifiability, according to Popper, is what separates science from non-science.', example_ko_3 = '포퍼에 따르면 반증 가능성이 과학과 비과학을 구분하는 것이에요.', example_en_4 = 'He argued that some educational claims lack falsifiability.', example_ko_4 = '그는 일부 교육적 주장이 반증 가능성이 부족하다고 주장했어요.', example_en_5 = 'Falsifiability encourages researchers to design tests that could disprove theories.', example_ko_5 = '반증 가능성은 연구자들이 이론을 반증할 수 있는 검증을 설계하도록 장려해요.' WHERE id = 'w_education_C2_04';
UPDATE words SET example_en_2 = 'She grounded her methodology in an interpretivist epistemological framework.', example_ko_2 = '그녀는 해석주의적 인식론적 틀에 방법론의 기반을 두었어요.', example_en_3 = 'Epistemological assumptions shape how researchers define and measure knowledge.', example_ko_3 = '인식론적 가정은 연구자들이 지식을 어떻게 정의하고 측정하는지를 형성해요.', example_en_4 = 'He wrote a section defending his epistemological position.', example_ko_4 = '그는 자신의 인식론적 입장을 방어하는 섹션을 작성했어요.', example_en_5 = 'Differences in epistemological stance lead to very different research questions.', example_ko_5 = '인식론적 입장의 차이는 매우 다른 연구 질문으로 이어져요.' WHERE id = 'w_education_C2_05';
UPDATE words SET example_en_2 = 'She saw her community work as educational praxis in action.', example_ko_2 = '그녀는 자신의 커뮤니티 작업을 실제로 이루어지는 교육적 프락시스로 봤어요.', example_en_3 = 'Praxis bridges the theoretical and the practical in critical pedagogy.', example_ko_3 = '프락시스는 비판적 교육학에서 이론과 실천을 연결해요.', example_en_4 = 'He applied Freirean praxis to reform his curriculum.', example_ko_4 = '그는 프레이리식 프락시스를 적용해 교육과정을 개혁했어요.', example_en_5 = 'Genuine praxis transforms both the learner and the world they inhabit.', example_ko_5 = '진정한 프락시스는 학습자와 그들이 사는 세계를 모두 변화시켜요.' WHERE id = 'w_education_C2_06';
UPDATE words SET example_en_2 = 'She applied deconstruction to challenge assumptions in the curriculum.', example_ko_2 = '그녀는 교육과정의 가정에 도전하기 위해 해체를 적용했어요.', example_en_3 = 'Deconstruction reveals how texts contain contradictions and hidden meanings.', example_ko_3 = '해체는 텍스트가 어떻게 모순과 숨겨진 의미를 포함하는지를 드러내요.', example_en_4 = 'He used deconstructive reading to analyze standardized test questions.', example_ko_4 = '그는 해체적 읽기를 사용해 표준화 시험 문항을 분석했어요.', example_en_5 = 'Deconstruction encourages educators to question what they take for granted.', example_ko_5 = '해체는 교육자들이 당연시하는 것에 의문을 갖도록 장려해요.' WHERE id = 'w_education_C2_07';
UPDATE words SET example_en_2 = 'She used a semiotic approach to analyze visual materials in textbooks.', example_ko_2 = '그녀는 기호론적 접근법을 사용해 교과서의 시각 자료를 분석했어요.', example_en_3 = 'Semiotic analysis explores how signs and symbols create meaning.', example_ko_3 = '기호론적 분석은 기호와 상징이 어떻게 의미를 생성하는지를 탐구해요.', example_en_4 = 'He studied the semiotic dimensions of classroom language use.', example_ko_4 = '그는 교실 언어 사용의 기호론적 차원을 연구했어요.', example_en_5 = 'A semiotic lens reveals meaning layers that other methods might miss.', example_ko_5 = '기호론적 렌즈는 다른 방법이 놓칠 수 있는 의미 층을 드러내요.' WHERE id = 'w_education_C2_08';
UPDATE words SET example_en_2 = 'She drew on poststructuralism to question fixed categories in education.', example_ko_2 = '그녀는 교육에서 고정된 범주에 의문을 제기하기 위해 후기구조주의를 활용했어요.', example_en_3 = 'Poststructuralism challenges the idea that meaning is stable and universal.', example_ko_3 = '후기구조주의는 의미가 안정적이고 보편적이라는 생각에 도전해요.', example_en_4 = 'He explored poststructuralist perspectives in his educational philosophy course.', example_ko_4 = '그는 교육철학 수업에서 후기구조주의적 관점을 탐구했어요.', example_en_5 = 'Poststructuralism encourages openness to multiple and shifting meanings.', example_ko_5 = '후기구조주의는 다양하고 변화하는 의미에 대한 개방성을 장려해요.' WHERE id = 'w_education_C2_09';
UPDATE words SET example_en_2 = 'She critiqued modern schooling for echoing the rigidity of medieval scholasticism.', example_ko_2 = '그녀는 현대 교육이 중세 스콜라주의의 경직성을 반영한다고 비판했어요.', example_en_3 = 'Scholasticism used logical argument to reconcile faith and reason.', example_ko_3 = '스콜라주의는 논리적 논증을 사용해 신앙과 이성을 조화시켰어요.', example_en_4 = 'He traced the roots of university education back to scholasticism.', example_ko_4 = '그는 대학 교육의 뿌리를 스콜라주의까지 거슬러 올라갔어요.', example_en_5 = 'Some argue that current exam culture reflects a modern form of scholasticism.', example_ko_5 = '일부에서는 현재의 시험 문화가 현대적 형태의 스콜라주의를 반영한다고 주장해요.' WHERE id = 'w_education_C2_10';
UPDATE words SET example_en_2 = 'She declared her ontological stance at the beginning of her research.', example_ko_2 = '그녀는 연구 시작 부분에 자신의 존재론적 입장을 밝혔어요.', example_en_3 = 'Ontological questions ask what kinds of things exist in the world.', example_ko_3 = '존재론적 질문은 세계에 어떤 종류의 것들이 존재하는지를 묻는 것이에요.', example_en_4 = 'He made an ontological distinction between knowledge and belief.', example_ko_4 = '그는 지식과 믿음 사이에 존재론적 구별을 했어요.', example_en_5 = 'Ontological assumptions inform how researchers conceptualize their subject.', example_ko_5 = '존재론적 가정은 연구자들이 연구 주제를 어떻게 개념화하는지에 영향을 줘요.' WHERE id = 'w_education_C2_11';
UPDATE words SET example_en_2 = 'She explored intersubjectivity as a basis for collaborative learning.', example_ko_2 = '그녀는 협력 학습의 기반으로서 상호주관성을 탐구했어요.', example_en_3 = 'Intersubjectivity describes the shared understanding between people.', example_ko_3 = '상호주관성은 사람들 사이의 공유된 이해를 설명해요.', example_en_4 = 'He argued that learning is fundamentally intersubjective.', example_ko_4 = '그는 학습이 근본적으로 상호주관적이라고 주장했어요.', example_en_5 = 'Building intersubjectivity in class creates a shared learning culture.', example_ko_5 = '수업에서 상호주관성을 구축하면 공유된 학습 문화가 만들어져요.' WHERE id = 'w_education_C2_12';
UPDATE words SET example_en_2 = 'She critiqued logocentrism in Western educational traditions.', example_ko_2 = '그녀는 서구 교육 전통에서 로고스 중심주의를 비판했어요.', example_en_3 = 'Logocentrism privileges reason and verbal logic over other ways of knowing.', example_ko_3 = '로고스 중심주의는 다른 인식 방식보다 이성과 언어적 논리를 우선시해요.', example_en_4 = 'He used Derrida''s critique of logocentrism to analyze curriculum design.', example_ko_4 = '그는 데리다의 로고스 중심주의 비판을 사용해 교육과정 설계를 분석했어요.', example_en_5 = 'Challenging logocentrism opens space for embodied and visual learning.', example_ko_5 = '로고스 중심주의에 도전하면 체화된 학습과 시각적 학습을 위한 공간이 열려요.' WHERE id = 'w_education_C2_13';
UPDATE words SET example_en_2 = 'She referenced Kant''s concept of the noumenon to discuss limits of knowledge.', example_ko_2 = '그녀는 지식의 한계를 논하기 위해 칸트의 누메논 개념을 언급했어요.', example_en_3 = 'The noumenon refers to the thing-in-itself, beyond human perception.', example_ko_3 = '누메논은 인간의 인식 너머에 있는 사물 자체를 가리켜요.', example_en_4 = 'He argued that some aspects of learning remain noumenal, beyond direct observation.', example_ko_4 = '그는 학습의 일부 측면은 직접 관찰 너머의 누메논적인 것으로 남는다고 주장했어요.', example_en_5 = 'Kant''s noumenon challenges the idea that we can fully know external reality.', example_ko_5 = '칸트의 누메논은 우리가 외부 현실을 완전히 알 수 있다는 생각에 도전해요.' WHERE id = 'w_education_C2_14';
UPDATE words SET example_en_2 = 'She examined teleology in educational policy by asking about its ultimate aims.', example_ko_2 = '그녀는 교육 정책의 궁극적인 목적을 물음으로써 목적론을 살펴봤어요.', example_en_3 = 'Teleology explains things in terms of their final purpose or goal.', example_ko_3 = '목적론은 사물의 최종 목적이나 목표의 관점에서 설명해요.', example_en_4 = 'He questioned the teleological assumptions behind outcome-based education.', example_ko_4 = '그는 성과 기반 교육의 목적론적 가정에 의문을 가졌어요.', example_en_5 = 'A teleological view of education sees it as a means to a specific end.', example_ko_5 = '교육에 대한 목적론적 관점은 교육을 특정 목적을 위한 수단으로 봐요.' WHERE id = 'w_education_C2_15';
UPDATE words SET example_en_2 = 'She used intertextuality to show how textbooks reference each other.', example_ko_2 = '그녀는 상호텍스트성을 사용해 교과서들이 서로 어떻게 참조하는지를 보여줬어요.', example_en_3 = 'Intertextuality describes how texts draw meaning from other texts.', example_ko_3 = '상호텍스트성은 텍스트가 어떻게 다른 텍스트에서 의미를 이끌어 내는지를 설명해요.', example_en_4 = 'He applied intertextuality to analyze the sources students use in writing.', example_ko_4 = '그는 학생들이 글쓰기에서 사용하는 출처를 분석하기 위해 상호텍스트성을 적용했어요.', example_en_5 = 'Intertextuality enriches reading by connecting texts across time and culture.', example_ko_5 = '상호텍스트성은 시간과 문화를 초월해 텍스트를 연결함으로써 읽기를 풍부하게 해요.' WHERE id = 'w_education_C2_16';
UPDATE words SET example_en_2 = 'She discussed moral relativism in the context of multicultural education.', example_ko_2 = '그녀는 다문화 교육의 맥락에서 도덕적 상대주의를 논의했어요.', example_en_3 = 'Relativism holds that truth and values depend on context and culture.', example_ko_3 = '상대주의는 진리와 가치가 맥락과 문화에 따라 달라진다고 주장해요.', example_en_4 = 'He critiqued epistemic relativism for undermining objective knowledge.', example_ko_4 = '그는 객관적 지식을 약화시킨다는 이유로 인식론적 상대주의를 비판했어요.', example_en_5 = 'A relativist approach to education respects diverse ways of knowing.', example_ko_5 = '교육에 대한 상대주의적 접근법은 다양한 인식 방식을 존중해요.' WHERE id = 'w_education_C2_17';
UPDATE words SET example_en_2 = 'She applied dialectical materialism to analyze class inequalities in schooling.', example_ko_2 = '그녀는 변증법적 유물론을 적용해 교육에서의 계급 불평등을 분석했어요.', example_en_3 = 'Dialectical materialism combines Hegel''s dialectic with a material view of history.', example_ko_3 = '변증법적 유물론은 헤겔의 변증법과 역사에 대한 유물론적 관점을 결합해요.', example_en_4 = 'He used dialectical materialism to critique educational inequality.', example_ko_4 = '그는 변증법적 유물론을 사용해 교육 불평등을 비판했어요.', example_en_5 = 'Dialectical materialism sees education as shaped by economic forces.', example_ko_5 = '변증법적 유물론은 교육이 경제적 힘에 의해 형성된다고 봐요.' WHERE id = 'w_education_C2_18';
UPDATE words SET example_en_2 = 'She introduced aporia as a starting point for philosophical inquiry in class.', example_ko_2 = '그녀는 수업에서 철학적 탐구의 출발점으로 아포리아를 소개했어요.', example_en_3 = 'Aporia describes a state of genuine puzzlement or logical deadlock.', example_ko_3 = '아포리아는 진정한 당혹감 또는 논리적 막힘의 상태를 묘사해요.', example_en_4 = 'He used aporia as a pedagogical strategy to motivate deeper thinking.', example_ko_4 = '그는 더 깊은 사고를 유발하기 위한 교육학적 전략으로 아포리아를 사용했어요.', example_en_5 = 'The Socratic method often leads students deliberately into aporia.', example_ko_5 = '소크라테스식 방법은 종종 학생들을 의도적으로 아포리아로 이끌어요.' WHERE id = 'w_education_C2_19';
UPDATE words SET example_en_2 = 'She applied Bakhtin''s concept of heteroglossia to multilingual classrooms.', example_ko_2 = '그녀는 다언어 교실에 바흐친의 이질어 개념을 적용했어요.', example_en_3 = 'Heteroglossia refers to the coexistence of multiple voices and registers.', example_ko_3 = '이질어는 다양한 목소리와 표현 방식의 공존을 말해요.', example_en_4 = 'He used heteroglossia to analyze student writing that mixed formal and informal styles.', example_ko_4 = '그는 형식적, 비형식적 문체가 혼합된 학생 글쓰기를 분석하기 위해 이질어를 사용했어요.', example_en_5 = 'Embracing heteroglossia in education values linguistic diversity.', example_ko_5 = '교육에서 이질어를 수용하는 것은 언어적 다양성을 소중히 여기는 것이에요.' WHERE id = 'w_education_C2_20';
UPDATE words SET example_en_2 = 'She used abductive reasoning to form a theory from surprising observations.', example_ko_2 = '그녀는 놀라운 관찰에서 이론을 형성하기 위해 귀추 추론을 사용했어요.', example_en_3 = 'Abduction infers the best explanation for a given set of facts.', example_ko_3 = '귀추는 주어진 사실에 대한 최선의 설명을 추론해요.', example_en_4 = 'He introduced abduction as a third form of reasoning alongside induction and deduction.', example_ko_4 = '그는 귀납과 연역 옆에 세 번째 추론 형태로 귀추를 소개했어요.', example_en_5 = 'Abductive reasoning is especially useful in qualitative research.', example_ko_5 = '귀추 추론은 질적 연구에서 특히 유용해요.' WHERE id = 'w_education_C2_21';
UPDATE words SET example_en_2 = 'She argued that phronesis, or practical wisdom, is an educational goal.', example_ko_2 = '그녀는 프로네시스, 즉 실천적 지혜가 교육의 목표라고 주장했어요.', example_en_3 = 'Phronesis is Aristotle''s term for wise judgment in practical situations.', example_ko_3 = '프로네시스는 실제 상황에서의 현명한 판단에 대한 아리스토텔레스의 용어예요.', example_en_4 = 'He designed experiential learning activities to cultivate phronesis.', example_ko_4 = '그는 프로네시스를 기르기 위해 체험 학습 활동을 설계했어요.', example_en_5 = 'Phronesis cannot be taught directly but is developed through experience.', example_ko_5 = '프로네시스는 직접 가르칠 수 없지만 경험을 통해 발전해요.' WHERE id = 'w_education_C2_22';
UPDATE words SET example_en_2 = 'She described the first year of university as a liminal phase for students.', example_ko_2 = '그녀는 대학 첫 해를 학생들의 전이적 단계로 묘사했어요.', example_en_3 = 'Liminality captures the in-between state during periods of transition.', example_ko_3 = '전이성은 전환의 시기 동안 중간 상태를 포착해요.', example_en_4 = 'He explored how liminality affects the identity development of students.', example_ko_4 = '그는 전이성이 학생들의 정체성 발달에 어떻게 영향을 미치는지 탐구했어요.', example_en_5 = 'Liminal spaces in education can be uncomfortable but deeply transformative.', example_ko_5 = '교육의 전이 공간은 불편할 수 있지만 깊이 변화시키는 힘이 있어요.' WHERE id = 'w_education_C2_23';
UPDATE words SET example_en_2 = 'She analyzed how hegemony shapes what counts as legitimate knowledge in schools.', example_ko_2 = '그녀는 헤게모니가 학교에서 무엇이 합법적인 지식으로 인정되는지를 어떻게 형성하는지 분석했어요.', example_en_3 = 'Hegemony in education maintains dominant cultural values through curriculum.', example_ko_3 = '교육에서 헤게모니는 교육과정을 통해 지배적인 문화적 가치를 유지해요.', example_en_4 = 'He drew on Gramsci''s concept of hegemony to critique schooling.', example_ko_4 = '그는 그람시의 헤게모니 개념을 활용해 교육을 비판했어요.', example_en_5 = 'Challenging hegemony in education means including marginalized knowledges.', example_ko_5 = '교육에서 헤게모니에 도전하는 것은 소외된 지식을 포함시키는 것을 의미해요.' WHERE id = 'w_education_C2_24';
UPDATE words SET example_en_2 = 'She played the role of interlocutor in the philosophical seminar.', example_ko_2 = '그녀는 철학 세미나에서 대화 상대의 역할을 했어요.', example_en_3 = 'An interlocutor is someone who takes part in a dialogue or discussion.', example_ko_3 = '대화 상대는 대화나 토론에 참여하는 사람이에요.', example_en_4 = 'He positioned himself as an interlocutor between theory and practice.', example_ko_4 = '그는 이론과 실천 사이의 대화 상대로 자신을 위치시켰어요.', example_en_5 = 'A skilled interlocutor draws out deeper thinking in others.', example_ko_5 = '숙련된 대화 상대는 다른 사람들의 더 깊은 사고를 이끌어 내요.' WHERE id = 'w_education_C2_25';
UPDATE words SET example_en_2 = 'She assessed the verisimilitude of case study accounts in qualitative research.', example_ko_2 = '그녀는 질적 연구에서 사례 연구 설명의 그럴듯함을 평가했어요.', example_en_3 = 'Verisimilitude refers to how believable or lifelike a representation is.', example_ko_3 = '그럴듯함은 표현이 얼마나 믿을 수 있거나 실제처럼 보이는지를 말해요.', example_en_4 = 'He used rich description to enhance the verisimilitude of his account.', example_ko_4 = '그는 풍부한 묘사를 사용해 자신의 설명의 그럴듯함을 높였어요.', example_en_5 = 'Verisimilitude in ethnography helps readers judge whether findings ring true.', example_ko_5 = '문화기술지에서 그럴듯함은 독자들이 연구 결과가 진실처럼 들리는지 판단하는 데 도움을 줘요.' WHERE id = 'w_education_C2_26';
UPDATE words SET example_en_2 = 'She studied Foucault''s notion of the episteme to understand knowledge formation.', example_ko_2 = '그녀는 지식 형성을 이해하기 위해 푸코의 에피스테메 개념을 연구했어요.', example_en_3 = 'An episteme is the underlying framework that makes knowledge possible.', example_ko_3 = '에피스테메는 지식을 가능하게 하는 기저의 틀이에요.', example_en_4 = 'He applied the concept of episteme to examine shifts in educational thinking.', example_ko_4 = '그는 교육적 사고의 변화를 살펴보기 위해 에피스테메 개념을 적용했어요.', example_en_5 = 'Each historical era has its own episteme that shapes what can be known.', example_ko_5 = '각 역사적 시대는 무엇이 알려질 수 있는지를 형성하는 자신만의 에피스테메를 가져요.' WHERE id = 'w_education_C2_27';
UPDATE words SET example_en_2 = 'She used bricolage as a metaphor for how students build knowledge from varied sources.', example_ko_2 = '그녀는 학생들이 다양한 출처에서 지식을 어떻게 구축하는지의 은유로 브리콜라주를 사용했어요.', example_en_3 = 'Bricolage describes creative use of whatever is available.', example_ko_3 = '브리콜라주는 이용 가능한 것을 창의적으로 사용하는 것을 설명해요.', example_en_4 = 'He applied bricolage as a methodological strategy in his research.', example_ko_4 = '그는 연구에서 방법론적 전략으로 브리콜라주를 적용했어요.', example_en_5 = 'In education, bricolage can describe interdisciplinary or creative learning.', example_ko_5 = '교육에서 브리콜라주는 학제간 또는 창의적 학습을 묘사할 수 있어요.' WHERE id = 'w_education_C2_28';
UPDATE words SET example_en_2 = 'She described how cultural assumptions become sedimented in teaching practice.', example_ko_2 = '그녀는 문화적 가정이 어떻게 교수 실천에 침전되는지를 설명했어요.', example_en_3 = 'Sedimentation refers to the layering of habits and norms over time.', example_ko_3 = '침전은 시간이 지나면서 습관과 규범이 축적되는 것을 말해요.', example_en_4 = 'He explored how sedimentation of colonial thinking affects curriculum content.', example_ko_4 = '그는 식민지적 사고의 침전이 어떻게 교육과정 내용에 영향을 미치는지 탐구했어요.', example_en_5 = 'Disrupting sedimented patterns requires conscious effort and reflection.', example_ko_5 = '침전된 패턴을 방해하려면 의식적인 노력과 성찰이 필요해요.' WHERE id = 'w_education_C2_29';
UPDATE words SET example_en_2 = 'She used Deleuze''s rhizome metaphor to describe non-linear learning.', example_ko_2 = '그녀는 비선형 학습을 설명하기 위해 들뢰즈의 리좀 은유를 사용했어요.', example_en_3 = 'A rhizome grows in many directions without a fixed center or root.', example_ko_3 = '리좀은 고정된 중심이나 뿌리 없이 여러 방향으로 자라요.', example_en_4 = 'He applied the rhizome concept to rethink curriculum as open and connected.', example_ko_4 = '그는 리좀 개념을 적용해 교육과정을 개방적이고 연결된 것으로 재구상했어요.', example_en_5 = 'Rhizomatic learning challenges the idea of a single correct learning path.', example_ko_5 = '리좀적 학습은 하나의 올바른 학습 경로라는 생각에 도전해요.' WHERE id = 'w_education_C2_30';
UPDATE words SET example_en_2 = 'She observed that academic debates often degenerate into logomachy.', example_ko_2 = '그녀는 학문적 논쟁이 종종 언쟁으로 전락한다고 관찰했어요.', example_en_3 = 'Logomachy is a dispute about the meaning or use of words.', example_ko_3 = '언쟁은 단어의 의미나 사용에 관한 논쟁이에요.', example_en_4 = 'He warned that the seminar could become logomachy unless grounded in evidence.', example_ko_4 = '그는 증거에 기반하지 않으면 세미나가 언쟁이 될 수 있다고 경고했어요.', example_en_5 = 'Moving beyond logomachy requires agreeing on shared definitions.', example_ko_5 = '언쟁을 넘어서려면 공유된 정의에 합의해야 해요.' WHERE id = 'w_education_C2_31';
UPDATE words SET example_en_2 = 'She described the foundational course as propaedeutic to advanced study.', example_ko_2 = '그녀는 기초 과목을 고급 연구를 위한 예비 과정으로 묘사했어요.', example_en_3 = 'Propaedeutic knowledge prepares students for deeper engagement with a subject.', example_ko_3 = '예비 지식은 학생들이 주제를 더 깊이 탐구할 수 있도록 준비시켜요.', example_en_4 = 'He designed a propaedeutic module to bridge gaps in prior knowledge.', example_ko_4 = '그는 사전 지식의 격차를 메우기 위한 예비 모듈을 설계했어요.', example_en_5 = 'A good propaedeutic course builds both skills and confidence.', example_ko_5 = '좋은 예비 과정은 능력과 자신감을 모두 키워요.' WHERE id = 'w_education_C2_32';
UPDATE words SET example_en_2 = 'She described drama-based learning as producing catharsis in students.', example_ko_2 = '그녀는 드라마 기반 학습이 학생들에게 카타르시스를 일으킨다고 묘사했어요.', example_en_3 = 'Catharsis refers to the emotional release that follows intense engagement.', example_ko_3 = '카타르시스는 강렬한 참여 후에 오는 감정적 해방을 말해요.', example_en_4 = 'He used Aristotle''s concept of catharsis to analyze storytelling in education.', example_ko_4 = '그는 교육에서 스토리텔링을 분석하기 위해 아리스토텔레스의 카타르시스 개념을 사용했어요.', example_en_5 = 'Cathartic learning experiences can be transformative for students.', example_ko_5 = '카타르시스적 학습 경험은 학생들에게 변혁적일 수 있어요.' WHERE id = 'w_education_C2_33';
UPDATE words SET example_en_2 = 'She discussed Descartes'' cogito as the foundation of modern rationalism.', example_ko_2 = '그녀는 데카르트의 코기토를 현대 합리주의의 기반으로 논의했어요.', example_en_3 = 'The cogito, ''I think, therefore I am,'' is central to Western philosophy.', example_ko_3 = '''나는 생각한다, 고로 나는 존재한다''라는 코기토는 서구 철학의 핵심이에요.', example_en_4 = 'He applied the cogito to questions of AI consciousness in education.', example_ko_4 = '그는 교육에서 AI 의식 문제에 코기토를 적용했어요.', example_en_5 = 'Understanding the cogito helps students engage with rationalist philosophy.', example_ko_5 = '코기토를 이해하면 학생들이 합리주의 철학에 참여하는 데 도움이 돼요.' WHERE id = 'w_education_C2_34';
UPDATE words SET example_en_2 = 'She referenced Plato''s anamnesis to discuss innate knowledge.', example_ko_2 = '그녀는 타고난 지식을 논하기 위해 플라톤의 상기론을 언급했어요.', example_en_3 = 'Anamnesis suggests that learning is really a process of recollecting.', example_ko_3 = '상기론은 학습이 실제로 기억을 떠올리는 과정이라고 시사해요.', example_en_4 = 'He used anamnesis as a metaphor for the rediscovery of prior knowledge.', example_ko_4 = '그는 사전 지식의 재발견에 대한 은유로 상기론을 사용했어요.', example_en_5 = 'Plato''s anamnesis challenges the view that knowledge is only acquired through experience.', example_ko_5 = '플라톤의 상기론은 지식이 경험을 통해서만 획득된다는 견해에 도전해요.' WHERE id = 'w_education_C2_35';
-- ── environment ──
-- EngCat · Environment topic · words example sentences (examples 2-5)
-- A1 words

UPDATE words SET example_en_2 = 'The old tree in our garden gives us shade in summer.', example_ko_2 = '정원에 있는 오래된 나무가 여름에 그늘을 만들어 줘요.', example_en_3 = 'We planted a tree to celebrate Earth Day.', example_ko_3 = '지구의 날을 기념하여 나무 한 그루를 심었어요.', example_en_4 = 'Some trees can live for hundreds of years.', example_ko_4 = '어떤 나무들은 수백 년 동안 살 수 있어요.', example_en_5 = 'The tree provides a home for many birds and insects.', example_ko_5 = '그 나무는 많은 새와 곤충들에게 집이 되어 줘요.' WHERE id = 'w_environment_A1_01';
UPDATE words SET example_en_2 = 'Please don''t waste water when you brush your teeth.', example_ko_2 = '양치질할 때 물을 낭비하지 마세요.', example_en_3 = 'The water in this river is very clear and clean.', example_ko_3 = '이 강의 물은 매우 맑고 깨끗해요.', example_en_4 = 'We use water for drinking, cooking, and washing.', example_ko_4 = '우리는 마시고, 요리하고, 씻는 데 물을 사용해요.', example_en_5 = 'Turn off the tap so we don''t waste water.', example_ko_5 = '물을 낭비하지 않도록 수도꼭지를 잠가 주세요.' WHERE id = 'w_environment_A1_02';
UPDATE words SET example_en_2 = 'The air in the mountains feels so fresh and clean.', example_ko_2 = '산속의 공기는 정말 상쾌하고 깨끗하게 느껴져요.', example_en_3 = 'We need clean air to stay healthy.', example_ko_3 = '건강을 유지하려면 깨끗한 공기가 필요해요.', example_en_4 = 'Cars and factories can pollute the air around us.', example_ko_4 = '자동차와 공장은 주변 공기를 오염시킬 수 있어요.', example_en_5 = 'Open the window to let fresh air into the room.', example_ko_5 = '창문을 열어 방 안에 신선한 공기가 들어오게 해 주세요.' WHERE id = 'w_environment_A1_03';
UPDATE words SET example_en_2 = 'We should keep our parks clean for everyone to enjoy.', example_ko_2 = '모두가 즐길 수 있도록 공원을 깨끗하게 유지해야 해요.', example_en_3 = 'The volunteers helped to clean up the beach last weekend.', example_ko_3 = '지난 주말에 봉사자들이 해변을 청소하는 것을 도왔어요.', example_en_4 = 'It feels good to have a clean and tidy home.', example_ko_4 = '깨끗하고 정돈된 집을 갖는 것은 기분 좋은 일이에요.', example_en_5 = 'Drinking clean water is very important for your health.', example_ko_5 = '깨끗한 물을 마시는 것은 건강에 매우 중요해요.' WHERE id = 'w_environment_A1_04';
UPDATE words SET example_en_2 = 'Spending time in nature can help reduce stress.', example_ko_2 = '자연 속에서 시간을 보내면 스트레스를 줄이는 데 도움이 돼요.', example_en_3 = 'Many people visit national parks to enjoy nature.', example_ko_3 = '많은 사람들이 자연을 즐기기 위해 국립공원을 방문해요.', example_en_4 = 'We must protect nature for future generations.', example_ko_4 = '미래 세대를 위해 자연을 보호해야 해요.', example_en_5 = 'The documentary showed the beauty of nature around the world.', example_ko_5 = '그 다큐멘터리는 전 세계 자연의 아름다움을 보여 주었어요.' WHERE id = 'w_environment_A1_05';
UPDATE words SET example_en_2 = 'The sun rises in the east and sets in the west.', example_ko_2 = '태양은 동쪽에서 떠서 서쪽으로 져요.', example_en_3 = 'Too much sun can burn your skin, so wear sunscreen.', example_ko_3 = '햇빛을 너무 많이 쬐면 피부가 탈 수 있으니 자외선 차단제를 바르세요.', example_en_4 = 'Solar panels use energy from the sun to make electricity.', example_ko_4 = '태양 전지판은 태양의 에너지를 이용해 전기를 만들어요.', example_en_5 = 'The sunlight came through the window and warmed the room.', example_ko_5 = '햇빛이 창문을 통해 들어와 방을 따뜻하게 해 주었어요.' WHERE id = 'w_environment_A1_06';
UPDATE words SET example_en_2 = 'The earth is the only planet we know that has life.', example_ko_2 = '지구는 우리가 아는 유일하게 생명체가 있는 행성이에요.', example_en_3 = 'We must take care of the earth for future generations.', example_ko_3 = '미래 세대를 위해 지구를 돌봐야 해요.', example_en_4 = 'The earth orbits around the sun once a year.', example_ko_4 = '지구는 일 년에 한 번 태양 주위를 공전해요.', example_en_5 = 'Astronauts can see the whole earth from space.', example_ko_5 = '우주비행사들은 우주에서 지구 전체를 볼 수 있어요.' WHERE id = 'w_environment_A1_07';
UPDATE words SET example_en_2 = 'Eating more green vegetables is good for your health.', example_ko_2 = '녹색 채소를 더 많이 먹는 것은 건강에 좋아요.', example_en_3 = 'The hills were covered in green grass after the rain.', example_ko_3 = '비가 온 후 언덕은 녹색 풀로 덮였어요.', example_en_4 = 'She painted the garden wall green to match the plants.', example_ko_4 = '그녀는 식물과 어울리도록 정원 담장을 녹색으로 칠했어요.', example_en_5 = 'Going green means making choices that help the environment.', example_ko_5 = '친환경적으로 산다는 것은 환경에 도움이 되는 선택을 한다는 뜻이에요.' WHERE id = 'w_environment_A1_08';
UPDATE words SET example_en_2 = 'I water my plant every two days so it stays healthy.', example_ko_2 = '식물이 건강하게 자라도록 이틀에 한 번씩 물을 줘요.', example_en_3 = 'This plant needs a lot of sunlight to grow well.', example_ko_3 = '이 식물은 잘 자라려면 햇빛이 많이 필요해요.', example_en_4 = 'A plant makes its own food from sunlight and water.', example_ko_4 = '식물은 햇빛과 물로 스스로 먹이를 만들어요.', example_en_5 = 'Even a small plant can brighten up a room.', example_ko_5 = '작은 식물 하나도 방을 밝게 해줄 수 있어요.' WHERE id = 'w_environment_A1_09';
UPDATE words SET example_en_2 = 'My favourite animal is the dolphin because it is so clever.', example_ko_2 = '제가 가장 좋아하는 동물은 돌고래인데, 정말 영리하기 때문이에요.', example_en_3 = 'Every animal needs food, water, and shelter to survive.', example_ko_3 = '모든 동물은 살아남기 위해 먹이, 물, 그리고 피신처가 필요해요.', example_en_4 = 'We must not disturb wild animals in their natural habitat.', example_ko_4 = '야생 동물들의 자연 서식지에서 그들을 방해해서는 안 돼요.', example_en_5 = 'The zoo helps to protect endangered animals from extinction.', example_ko_5 = '동물원은 멸종 위기에 처한 동물들을 보호하는 데 도움을 줘요.' WHERE id = 'w_environment_A1_10';
UPDATE words SET example_en_2 = 'She picked a flower from the garden for her mother.', example_ko_2 = '그녀는 어머니를 위해 정원에서 꽃을 한 송이 꺾었어요.', example_en_3 = 'Bees collect nectar from flowers to make honey.', example_ko_3 = '벌들은 꿀을 만들기 위해 꽃에서 꿀을 모아요.', example_en_4 = 'These flowers only bloom in spring.', example_ko_4 = '이 꽃들은 봄에만 피어요.', example_en_5 = 'The park is full of colourful flowers in the summer.', example_ko_5 = '여름이 되면 공원은 알록달록한 꽃으로 가득 차요.' WHERE id = 'w_environment_A1_11';
UPDATE words SET example_en_2 = 'The sky turned orange and pink at sunset.', example_ko_2 = '일몰 때 하늘이 주황색과 분홍색으로 물들었어요.', example_en_3 = 'There was not a single cloud in the sky this morning.', example_ko_3 = '오늘 아침에는 하늘에 구름 한 점도 없었어요.', example_en_4 = 'Birds fly high in the sky searching for food.', example_ko_4 = '새들은 먹이를 찾아 하늘 높이 날아요.', example_en_5 = 'You can see millions of stars in the sky on a clear night.', example_ko_5 = '맑은 밤에는 하늘에서 수백만 개의 별을 볼 수 있어요.' WHERE id = 'w_environment_A1_12';
UPDATE words SET example_en_2 = 'The rain made the garden smell fresh and earthy.', example_ko_2 = '비가 내린 후 정원에서 신선하고 흙냄새가 났어요.', example_en_3 = 'Don''t forget to take an umbrella; it might rain today.', example_ko_3 = '오늘 비가 올 수도 있으니 우산을 가져가는 것을 잊지 마세요.', example_en_4 = 'Heavy rain flooded the streets in the city centre.', example_ko_4 = '폭우로 도심 거리가 침수되었어요.', example_en_5 = 'Rain is essential for plants and crops to grow.', example_ko_5 = '비는 식물과 농작물이 자라는 데 꼭 필요해요.' WHERE id = 'w_environment_A1_13';
UPDATE words SET example_en_2 = 'The snow covered the mountains in a white blanket.', example_ko_2 = '눈이 산을 하얀 이불처럼 덮었어요.', example_en_3 = 'Children love to play in the snow during winter.', example_ko_3 = '아이들은 겨울에 눈 속에서 노는 것을 좋아해요.', example_en_4 = 'The snow melted quickly when the temperature rose.', example_ko_4 = '기온이 오르자 눈이 빠르게 녹았어요.', example_en_5 = 'Too much snow can make driving very dangerous.', example_ko_5 = '눈이 너무 많이 오면 운전이 매우 위험해질 수 있어요.' WHERE id = 'w_environment_A1_14';
UPDATE words SET example_en_2 = 'The children sat on a big rock beside the river.', example_ko_2 = '아이들은 강가의 큰 바위 위에 앉았어요.', example_en_3 = 'The rock was covered in green moss from the damp air.', example_ko_3 = '그 바위는 습한 공기 때문에 녹색 이끼로 덮여 있었어요.', example_en_4 = 'Scientists study layers of rock to learn about Earth''s history.', example_ko_4 = '과학자들은 지구의 역사를 알아내기 위해 암석층을 연구해요.', example_en_5 = 'We skipped rocks across the surface of the lake.', example_ko_5 = '우리는 호수 표면에 돌멩이를 던지며 물수제비를 뜨었어요.' WHERE id = 'w_environment_A1_15';
UPDATE words SET example_en_2 = 'The sea is home to thousands of different species of fish.', example_ko_2 = '바다는 수천 종의 다양한 물고기가 사는 곳이에요.', example_en_3 = 'Rising temperatures are causing serious damage to the sea.', example_ko_3 = '기온 상승으로 바다가 심각한 피해를 입고 있어요.', example_en_4 = 'The sea looked calm and beautiful in the early morning light.', example_ko_4 = '이른 아침 햇빛 아래 바다는 잔잔하고 아름다웠어요.', example_en_5 = 'Plastic waste is one of the biggest threats to the sea.', example_ko_5 = '플라스틱 폐기물은 바다에 대한 가장 큰 위협 중 하나예요.' WHERE id = 'w_environment_A1_16';
UPDATE words SET example_en_2 = 'We watched the fish swim in the clear water of the stream.', example_ko_2 = '우리는 맑은 개울물 속을 헤엄치는 물고기를 바라보았어요.', example_en_3 = 'Salmon swim upstream to lay their eggs every year.', example_ko_3 = '연어는 매년 알을 낳기 위해 강 상류로 거슬러 올라가요.', example_en_4 = 'Overfishing is a serious problem in many parts of the ocean.', example_ko_4 = '남획은 바다 많은 지역에서 심각한 문제예요.', example_en_5 = 'The fish in this lake have been affected by water pollution.', example_ko_5 = '이 호수의 물고기들은 수질 오염의 영향을 받았어요.' WHERE id = 'w_environment_A1_17';
UPDATE words SET example_en_2 = 'The bird sang a beautiful song from the top of the tree.', example_ko_2 = '새가 나무 꼭대기에서 아름다운 노래를 불렀어요.', example_en_3 = 'Many birds migrate south for the winter every year.', example_ko_3 = '많은 새들이 매년 겨울을 나기 위해 남쪽으로 이동해요.', example_en_4 = 'The loss of trees reduces the habitat available for birds.', example_ko_4 = '나무가 줄어들면 새들이 살 수 있는 서식지도 줄어들어요.', example_en_5 = 'We put up a bird feeder in our garden to help local wildlife.', example_ko_5 = '우리는 지역 야생동물을 돕기 위해 정원에 새 모이통을 설치했어요.' WHERE id = 'w_environment_A1_18';
UPDATE words SET example_en_2 = 'A single leaf fell from the tree and landed in the pond.', example_ko_2 = '나뭇잎 한 장이 나무에서 떨어져 연못에 내려앉았어요.', example_en_3 = 'The leaves of the trees turn red and orange in autumn.', example_ko_3 = '가을이 되면 나무의 잎들이 빨간색과 주황색으로 변해요.', example_en_4 = 'Fallen leaves can be composted to make natural fertiliser.', example_ko_4 = '낙엽을 퇴비로 만들어 천연 비료로 사용할 수 있어요.', example_en_5 = 'The leaf was so delicate that I could see through it.', example_ko_5 = '그 잎사귀는 너무 얇아서 비쳐 보일 정도였어요.' WHERE id = 'w_environment_A1_19';
UPDATE words SET example_en_2 = 'The sheep grazed on the green grass in the field.', example_ko_2 = '양들이 들판의 푸른 풀을 뜯어 먹었어요.', example_en_3 = 'Walking barefoot on the grass feels wonderful.', example_ko_3 = '잔디 위를 맨발로 걷는 것은 정말 기분 좋아요.', example_en_4 = 'The gardener cut the grass short before the summer party.', example_ko_4 = '정원사는 여름 파티 전에 잔디를 짧게 깎았어요.', example_en_5 = 'Grass and other plants release oxygen into the air.', example_ko_5 = '잔디와 다른 식물들은 공기 중으로 산소를 방출해요.' WHERE id = 'w_environment_A1_20';
UPDATE words SET example_en_2 = 'The wind carried the seeds of the dandelion far away.', example_ko_2 = '바람이 민들레 씨앗을 멀리 날려 보냈어요.', example_en_3 = 'A strong wind blew the leaves off the trees in the park.', example_ko_3 = '강한 바람이 공원의 나무에서 잎들을 날려 보냈어요.', example_en_4 = 'Wind turbines convert the energy of the wind into electricity.', example_ko_4 = '풍력 터빈은 바람의 에너지를 전기로 변환해요.', example_en_5 = 'The wind felt cool and refreshing on such a hot day.', example_ko_5 = '이렇게 더운 날에는 바람이 시원하고 상쾌하게 느껴져요.' WHERE id = 'w_environment_A1_21';
UPDATE words SET example_en_2 = 'Fire requires oxygen, fuel, and heat to keep burning.', example_ko_2 = '불이 계속 타려면 산소, 연료, 열이 필요해요.', example_en_3 = 'Wildfires can destroy thousands of hectares of forest in days.', example_ko_3 = '산불은 며칠 만에 수천 헥타르의 숲을 태워 버릴 수 있어요.', example_en_4 = 'Never leave a fire unattended when you are camping outdoors.', example_ko_4 = '야외에서 캠핑할 때 불을 절대 방치하지 마세요.', example_en_5 = 'The campfire gave us warmth and light on the cold night.', example_ko_5 = '모닥불은 추운 밤에 우리에게 온기와 불빛을 주었어요.' WHERE id = 'w_environment_A1_22';
UPDATE words SET example_en_2 = 'Fine sand feels soft and warm under your feet at the beach.', example_ko_2 = '해변에서 고운 모래는 발아래서 부드럽고 따뜻하게 느껴져요.', example_en_3 = 'The desert is mostly made of sand and rocks.', example_ko_3 = '사막은 대부분 모래와 바위로 이루어져 있어요.', example_en_4 = 'The children built sandcastles on the beach all afternoon.', example_ko_4 = '아이들은 오후 내내 해변에서 모래성을 쌓았어요.', example_en_5 = 'Sand dunes are formed when wind blows sand into piles.', example_ko_5 = '모래 언덕은 바람이 모래를 쌓아 올릴 때 형성돼요.' WHERE id = 'w_environment_A1_23';
UPDATE words SET example_en_2 = 'The lake was perfectly still and reflected the mountains.', example_ko_2 = '호수는 완전히 잔잔하여 산을 그대로 비추고 있었어요.', example_en_3 = 'We went rowing on the lake on Sunday afternoon.', example_ko_3 = '우리는 일요일 오후에 호수에서 노를 저었어요.', example_en_4 = 'Pollution from farms can make lake water unsafe to drink.', example_ko_4 = '농장에서 나오는 오염물질이 호수 물을 마시기에 안전하지 않게 만들 수 있어요.', example_en_5 = 'The lake freezes over in winter and children skate on it.', example_ko_5 = '호수는 겨울에 얼고 아이들은 그 위에서 스케이트를 타요.' WHERE id = 'w_environment_A1_24';
UPDATE words SET example_en_2 = 'Climbing the mountain took us about four hours each way.', example_ko_2 = '산을 오르는 데 왕복 각각 약 네 시간이 걸렸어요.', example_en_3 = 'Many rare plants and animals live on the mountain.', example_ko_3 = '많은 희귀 식물과 동물들이 산에 살고 있어요.', example_en_4 = 'The mountain peak was covered in snow all year round.', example_ko_4 = '산 정상은 일 년 내내 눈으로 덮여 있었어요.', example_en_5 = 'The view from the top of the mountain was absolutely breathtaking.', example_ko_5 = '산 정상에서 바라본 경치는 정말 숨이 막힐 정도로 아름다웠어요.' WHERE id = 'w_environment_A1_25';
UPDATE words SET example_en_2 = 'Dark clouds gathered in the sky before the storm.', example_ko_2 = '폭풍이 오기 전에 하늘에 먹구름이 모였어요.', example_en_3 = 'The clouds blocked out the sun and made the day cooler.', example_ko_3 = '구름이 태양을 가려 날씨가 서늘해졌어요.', example_en_4 = 'I love watching clouds change shape as they move across the sky.', example_ko_4 = '구름이 하늘을 가로질러 이동하며 모양이 바뀌는 것을 바라보는 것을 좋아해요.', example_en_5 = 'High clouds often mean that rain is on the way.', example_ko_5 = '높은 구름이 끼면 곧 비가 올 것이라는 신호인 경우가 많아요.' WHERE id = 'w_environment_A1_26';
UPDATE words SET example_en_2 = 'Sunlight gives us warmth and light energy every day.', example_ko_2 = '햇빛은 우리에게 매일 온기와 빛 에너지를 주어요.', example_en_3 = 'The light from the lamp was not bright enough to read by.', example_ko_3 = '램프의 빛이 책을 읽기에 충분히 밝지 않았어요.', example_en_4 = 'Turn off the lights when you leave a room to save energy.', example_ko_4 = '에너지를 절약하기 위해 방에서 나올 때 불을 끄세요.', example_en_5 = 'LED lights use much less energy than traditional bulbs.', example_ko_5 = 'LED 조명은 기존 전구보다 훨씬 적은 에너지를 사용해요.' WHERE id = 'w_environment_A1_27';
UPDATE words SET example_en_2 = 'The forest was dark and mysterious at night.', example_ko_2 = '밤에 숲은 어둡고 신비로웠어요.', example_en_3 = 'It gets dark very early in winter in northern countries.', example_ko_3 = '북쪽 나라들은 겨울에 매우 일찍 어두워져요.', example_en_4 = 'Switch on the light so we can see in the dark room.', example_ko_4 = '어두운 방에서 볼 수 있도록 불을 켜 주세요.', example_en_5 = 'Pollution from city lights makes the sky too dark to see stars.', example_ko_5 = '도시의 빛 공해로 하늘이 너무 밝아 별을 보기 어려워요.' WHERE id = 'w_environment_A1_28';
UPDATE words SET example_en_2 = 'It was so hot that we stayed in the shade all afternoon.', example_ko_2 = '너무 더워서 우리는 오후 내내 그늘에 있었어요.', example_en_3 = 'Hot weather can be dangerous for elderly people and children.', example_ko_3 = '더운 날씨는 노인과 어린이에게 위험할 수 있어요.', example_en_4 = 'The desert is extremely hot during the day and cold at night.', example_ko_4 = '사막은 낮에는 매우 덥고 밤에는 추워요.', example_en_5 = 'Climate change is making heatwaves more frequent and intense.', example_ko_5 = '기후 변화로 폭염이 더 자주, 더 강하게 발생하고 있어요.' WHERE id = 'w_environment_A1_29';
UPDATE words SET example_en_2 = 'The cold wind came down from the mountains in the evening.', example_ko_2 = '저녁에 산에서 차가운 바람이 불어 내려왔어요.', example_en_3 = 'Cold weather causes rivers and lakes to freeze over.', example_ko_3 = '추운 날씨로 강과 호수가 얼어붙어요.', example_en_4 = 'Polar bears are adapted to survive in cold environments.', example_ko_4 = '북극곰은 추운 환경에서 생존할 수 있도록 적응되어 있어요.', example_en_5 = 'Drinking cold water is refreshing on a very hot day.', example_ko_5 = '매우 더운 날에 차가운 물을 마시면 기분이 상쾌해져요.' WHERE id = 'w_environment_A1_30';
UPDATE words SET example_en_2 = 'Seeds need good soil and sunlight to grow out of the ground.', example_ko_2 = '씨앗이 땅 위로 자라려면 좋은 흙과 햇빛이 필요해요.', example_en_3 = 'The earthquake shook the ground and caused buildings to crack.', example_ko_3 = '지진이 땅을 흔들어 건물에 균열이 생겼어요.', example_en_4 = 'Fallen leaves decompose and return nutrients to the ground.', example_ko_4 = '낙엽은 분해되어 영양분을 땅으로 되돌려 보내요.', example_en_5 = 'The ground was frozen solid during the long winter months.', example_ko_5 = '긴 겨울 동안 땅이 꽁꽁 얼어 있었어요.' WHERE id = 'w_environment_A1_31';
UPDATE words SET example_en_2 = 'The river flows from the mountains down to the sea.', example_ko_2 = '강은 산에서 바다로 흘러 내려가요.', example_en_3 = 'Many towns were built near rivers for easy access to water.', example_ko_3 = '많은 마을이 물을 쉽게 구하기 위해 강 근처에 세워졌어요.', example_en_4 = 'Industrial waste has polluted the river and harmed wildlife.', example_ko_4 = '산업 폐기물이 강을 오염시키고 야생동물에게 해를 끼쳤어요.', example_en_5 = 'We spent the afternoon fishing by the river with our family.', example_ko_5 = '우리는 가족과 함께 강가에서 오후 내내 낚시를 했어요.' WHERE id = 'w_environment_A1_32';
UPDATE words SET example_en_2 = 'The forest is home to deer, foxes, and many kinds of birds.', example_ko_2 = '숲에는 사슴, 여우, 그리고 다양한 종류의 새들이 살아요.', example_en_3 = 'Deforestation is destroying large areas of the world''s forests.', example_ko_3 = '삼림 벌채로 전 세계 숲의 넓은 지역이 파괴되고 있어요.', example_en_4 = 'Walking through the forest in the morning is very peaceful.', example_ko_4 = '아침에 숲속을 걷는 것은 매우 평화로워요.', example_en_5 = 'Forests help to regulate the climate by absorbing carbon dioxide.', example_ko_5 = '숲은 이산화탄소를 흡수해 기후 조절을 도와요.' WHERE id = 'w_environment_A1_33';
UPDATE words SET example_en_2 = 'Rich soil contains many nutrients that help plants to grow.', example_ko_2 = '비옥한 흙에는 식물이 자라는 데 도움이 되는 영양분이 많이 들어 있어요.', example_en_3 = 'Using too many chemicals can damage the soil over time.', example_ko_3 = '화학물질을 너무 많이 사용하면 시간이 지나면서 토양이 손상될 수 있어요.', example_en_4 = 'Composting kitchen waste helps to improve the quality of soil.', example_ko_4 = '음식물 쓰레기를 퇴비로 만들면 토양의 질을 개선하는 데 도움이 돼요.', example_en_5 = 'Healthy soil is essential for growing the food we eat.', example_ko_5 = '건강한 토양은 우리가 먹는 식물을 재배하는 데 꼭 필요해요.' WHERE id = 'w_environment_A1_34';
UPDATE words SET example_en_2 = 'The ground became wet and muddy after the heavy rain.', example_ko_2 = '폭우 후 땅이 젖어 진흙탕이 되었어요.', example_en_3 = 'My shoes got wet because I walked through a puddle.', example_ko_3 = '웅덩이를 걸어 지나가는 바람에 신발이 젖었어요.', example_en_4 = 'Wet weather is good for the garden but makes commuting difficult.', example_ko_4 = '젖은 날씨는 정원에는 좋지만 출퇴근을 어렵게 만들어요.', example_en_5 = 'The wet forest floor was covered in fallen leaves and mushrooms.', example_ko_5 = '젖은 숲 바닥은 낙엽과 버섯으로 뒤덮여 있었어요.' WHERE id = 'w_environment_A1_35';

