UPDATE words SET example_en_2 = 'You can recycle glass, paper, and most plastic containers.', example_ko_2 = '유리, 종이, 그리고 대부분의 플라스틱 용기는 재활용할 수 있어요.', example_en_3 = 'Recycling saves energy and reduces the amount of waste in landfills.', example_ko_3 = '재활용은 에너지를 절약하고 매립지의 쓰레기 양을 줄여 줘요.', example_en_4 = 'Our local council provides separate bins for recycling.', example_ko_4 = '우리 지역 위원회에서는 재활용을 위한 별도의 쓰레기통을 제공해요.', example_en_5 = 'It is easy to recycle once you know which bin to use.', example_ko_5 = '어떤 쓰레기통을 사용해야 하는지 알면 재활용은 쉬워요.' WHERE id = 'w_environment_A2_01';
UPDATE words SET example_en_2 = 'Air pollution from factories affects the health of people nearby.', example_ko_2 = '공장에서 나오는 대기 오염은 주변 사람들의 건강에 영향을 미쳐요.', example_en_3 = 'Water pollution is a serious issue in many developing countries.', example_ko_3 = '수질 오염은 많은 개발도상국에서 심각한 문제예요.', example_en_4 = 'Noise pollution in big cities can disrupt sleep and increase stress.', example_ko_4 = '대도시의 소음 공해는 수면을 방해하고 스트레스를 높일 수 있어요.', example_en_5 = 'Reducing pollution should be a priority for every government.', example_ko_5 = '오염을 줄이는 것은 모든 정부의 우선 과제가 되어야 해요.' WHERE id = 'w_environment_A2_02';
UPDATE words SET example_en_2 = 'Solar and wind power are clean sources of renewable energy.', example_ko_2 = '태양광과 풍력은 깨끗한 재생 에너지 원천이에요.', example_en_3 = 'We need to reduce the amount of energy we use every day.', example_ko_3 = '우리는 매일 사용하는 에너지의 양을 줄여야 해요.', example_en_4 = 'Turn off appliances at the plug to save energy at home.', example_ko_4 = '가정에서 에너지를 절약하려면 플러그에서 가전제품의 전원을 끄세요.', example_en_5 = 'Switching to green energy can help reduce your carbon footprint.', example_ko_5 = '친환경 에너지로 전환하면 탄소 발자국을 줄이는 데 도움이 돼요.' WHERE id = 'w_environment_A2_03';
UPDATE words SET example_en_2 = 'Food waste is a huge problem in many wealthy countries.', example_ko_2 = '음식물 낭비는 많은 부유한 나라에서 큰 문제예요.', example_en_3 = 'Try to reduce waste by buying only what you need.', example_ko_3 = '필요한 것만 구매해서 쓰레기를 줄이도록 노력해 보세요.', example_en_4 = 'Electronic waste contains harmful chemicals that damage the environment.', example_ko_4 = '전자 폐기물에는 환경을 해치는 유해 화학물질이 들어 있어요.', example_en_5 = 'The city created a plan to reduce waste by 30 percent in five years.', example_ko_5 = '시에서는 5년 안에 폐기물을 30퍼센트 줄이는 계획을 세웠어요.' WHERE id = 'w_environment_A2_04';
UPDATE words SET example_en_2 = 'Solar energy is generated by capturing the heat and light of the sun.', example_ko_2 = '태양에너지는 태양의 열과 빛을 포착하여 생성돼요.', example_en_3 = 'Many countries are investing in solar technology to reduce emissions.', example_ko_3 = '많은 나라들이 배출량을 줄이기 위해 태양에너지 기술에 투자하고 있어요.', example_en_4 = 'Solar power is becoming more affordable for ordinary households.', example_ko_4 = '태양광 발전은 일반 가정에게도 점점 더 저렴해지고 있어요.', example_en_5 = 'Installing solar panels can significantly reduce your electricity bill.', example_ko_5 = '태양 전지판을 설치하면 전기 요금을 크게 줄일 수 있어요.' WHERE id = 'w_environment_A2_05';
UPDATE words SET example_en_2 = 'It is our responsibility to protect the natural world.', example_ko_2 = '자연을 보호하는 것은 우리의 책임이에요.', example_en_3 = 'The government passed a new law to protect endangered species.', example_ko_3 = '정부는 멸종 위기에 처한 종들을 보호하기 위해 새로운 법을 통과시켰어요.', example_en_4 = 'We can all do simple things every day to protect the environment.', example_ko_4 = '우리 모두 환경을 보호하기 위해 매일 간단한 일들을 할 수 있어요.', example_en_5 = 'Reusable bags help protect the ocean from plastic pollution.', example_ko_5 = '재사용 가능한 가방은 바다를 플라스틱 오염으로부터 보호하는 데 도움이 돼요.' WHERE id = 'w_environment_A2_06';
UPDATE words SET example_en_2 = 'Try to reduce your plastic use by carrying a reusable water bottle.', example_ko_2 = '재사용 가능한 물병을 들고 다녀서 플라스틱 사용을 줄여 보세요.', example_en_3 = 'Reducing meat consumption can lower your carbon footprint significantly.', example_ko_3 = '육류 섭취를 줄이면 탄소 발자국을 크게 낮출 수 있어요.', example_en_4 = 'The company aimed to reduce its energy use by 20 percent this year.', example_ko_4 = '그 회사는 올해 에너지 사용량을 20퍼센트 줄이는 것을 목표로 했어요.', example_en_5 = 'Small steps to reduce waste every day can make a big difference.', example_ko_5 = '매일 쓰레기를 줄이기 위한 작은 노력들이 큰 변화를 만들 수 있어요.' WHERE id = 'w_environment_A2_07';
UPDATE words SET example_en_2 = 'You can reuse glass jars as containers for storing food.', example_ko_2 = '유리병을 식품 보관 용기로 재사용할 수 있어요.', example_en_3 = 'Reuse paper bags instead of throwing them away after one use.', example_ko_3 = '종이 봉투를 한 번 쓰고 버리는 대신 재사용해 보세요.', example_en_4 = 'Reusing items reduces the demand for new products and materials.', example_ko_4 = '물건을 재사용하면 새 제품과 재료에 대한 수요가 줄어들어요.', example_en_5 = 'Repair and reuse your clothes rather than throwing them away.', example_ko_5 = '옷을 버리는 대신 수선하고 재사용해 보세요.' WHERE id = 'w_environment_A2_08';
UPDATE words SET example_en_2 = 'Single-use plastic bags are now banned in many countries.', example_ko_2 = '일회용 비닐봉지는 이제 많은 나라에서 금지되었어요.', example_en_3 = 'Plastic bottles can take hundreds of years to break down.', example_ko_3 = '플라스틱 병은 분해되는 데 수백 년이 걸릴 수 있어요.', example_en_4 = 'Plastic pollution in the ocean harms sea life and ecosystems.', example_ko_4 = '바다의 플라스틱 오염은 해양 생물과 생태계에 해를 끼쳐요.', example_en_5 = 'Choosing products with less plastic packaging is an easy green step.', example_ko_5 = '플라스틱 포장재가 적은 제품을 선택하는 것은 쉬운 친환경 실천이에요.' WHERE id = 'w_environment_A2_09';
UPDATE words SET example_en_2 = 'Throwing garbage into the sea causes serious harm to marine life.', example_ko_2 = '바다에 쓰레기를 버리면 해양 생물에게 심각한 피해를 줘요.', example_en_3 = 'We should always put our garbage in the correct bin.', example_ko_3 = '쓰레기는 항상 올바른 쓰레기통에 버려야 해요.', example_en_4 = 'Garbage left on the street makes the neighbourhood look untidy.', example_ko_4 = '거리에 버려진 쓰레기는 동네를 지저분하게 만들어요.', example_en_5 = 'Sorting your garbage correctly helps recycling centres work more efficiently.', example_ko_5 = '쓰레기를 올바르게 분류하면 재활용 센터가 더 효율적으로 운영될 수 있어요.' WHERE id = 'w_environment_A2_10';
UPDATE words SET example_en_2 = 'Electric cars produce no exhaust emissions when driven.', example_ko_2 = '전기차는 운행 중에 배기가스를 전혀 배출하지 않아요.', example_en_3 = 'The city is adding more electric buses to its public transport system.', example_ko_3 = '그 도시는 대중교통 시스템에 전기버스를 더 추가하고 있어요.', example_en_4 = 'Using electric appliances reduces the need to burn fossil fuels.', example_ko_4 = '전기 기기를 사용하면 화석 연료를 태울 필요성이 줄어들어요.', example_en_5 = 'The government offers discounts to encourage people to buy electric vehicles.', example_ko_5 = '정부는 사람들이 전기차를 구매하도록 장려하기 위해 할인을 제공해요.' WHERE id = 'w_environment_A2_11';
UPDATE words SET example_en_2 = 'Cigarette smoke pollutes the air and harms everyone nearby.', example_ko_2 = '담배 연기는 공기를 오염시키고 주변 모든 사람에게 해를 끼쳐요.', example_en_3 = 'Black smoke from old diesel engines is a sign of air pollution.', example_ko_3 = '낡은 디젤 엔진에서 나오는 검은 연기는 대기 오염의 징표예요.', example_en_4 = 'The factory reduced its smoke emissions after receiving a large fine.', example_ko_4 = '그 공장은 큰 벌금을 받은 후 연기 배출량을 줄였어요.', example_en_5 = 'Wildfire smoke can travel thousands of kilometres and affect air quality.', example_ko_5 = '산불 연기는 수천 킬로미터를 이동해 공기의 질에 영향을 미칠 수 있어요.' WHERE id = 'w_environment_A2_12';
UPDATE words SET example_en_2 = 'Many household cleaning products contain toxic chemicals.', example_ko_2 = '많은 가정용 세정제에는 독성 화학물질이 들어 있어요.', example_en_3 = 'Toxic waste must be stored and disposed of very carefully.', example_ko_3 = '독성 폐기물은 매우 신중하게 보관하고 처리해야 해요.', example_en_4 = 'The factory was shut down after releasing toxic gases into the river.', example_ko_4 = '그 공장은 강에 독성 가스를 방류한 후 폐쇄되었어요.', example_en_5 = 'You should always read labels to avoid buying toxic products.', example_ko_5 = '독성 제품을 구매하지 않으려면 항상 라벨을 읽어보세요.' WHERE id = 'w_environment_A2_13';
UPDATE words SET example_en_2 = 'Do not litter — always use a bin for your rubbish.', example_ko_2 = '쓰레기를 함부로 버리지 마세요 — 항상 쓰레기통을 이용해 주세요.', example_en_3 = 'Littering in parks is not only illegal but also disrespectful.', example_ko_3 = '공원에서 쓰레기를 함부로 버리는 것은 불법일 뿐만 아니라 무례한 행동이에요.', example_en_4 = 'Volunteers cleaned up the litter along the riverside on Sunday.', example_ko_4 = '봉사자들이 일요일에 강변의 쓰레기를 청소했어요.', example_en_5 = 'Even small pieces of litter can harm birds and animals.', example_ko_5 = '작은 쓰레기 조각도 새와 동물에게 해를 끼칠 수 있어요.' WHERE id = 'w_environment_A2_14';
UPDATE words SET example_en_2 = 'We can save water by taking shorter showers.', example_ko_2 = '샤워 시간을 줄여서 물을 절약할 수 있어요.', example_en_3 = 'Switching off the lights helps save electricity and money.', example_ko_3 = '불을 끄면 전기와 돈을 절약하는 데 도움이 돼요.', example_en_4 = 'Save energy by only running the washing machine when it is full.', example_ko_4 = '세탁기를 가득 찼을 때만 돌려서 에너지를 절약하세요.', example_en_5 = 'Buying second-hand items is a great way to save resources.', example_ko_5 = '중고 물건을 구매하는 것은 자원을 절약하는 훌륭한 방법이에요.' WHERE id = 'w_environment_A2_15';
UPDATE words SET example_en_2 = 'I prefer to buy natural products that don''t contain artificial chemicals.', example_ko_2 = '저는 인공 화학물질이 들어 있지 않은 천연 제품을 선호해요.', example_en_3 = 'Natural light is better for your eyes than artificial lighting.', example_ko_3 = '자연광은 인공 조명보다 눈에 더 좋아요.', example_en_4 = 'Using natural materials in buildings is more sustainable long term.', example_ko_4 = '건물에 천연 재료를 사용하는 것이 장기적으로 더 지속 가능해요.', example_en_5 = 'The garden has been planted with natural wildflowers to attract bees.', example_ko_5 = '정원에 벌을 끌어들이기 위해 야생화를 자연스럽게 심었어요.' WHERE id = 'w_environment_A2_16';
UPDATE words SET example_en_2 = 'Fresh water is a limited natural resource that we must protect.', example_ko_2 = '담수는 우리가 보호해야 할 제한된 천연 자원이에요.', example_en_3 = 'Oil is a non-renewable resource that will eventually run out.', example_ko_3 = '석유는 결국 고갈될 재생 불가능한 자원이에요.', example_en_4 = 'We must manage our natural resources carefully to avoid waste.', example_ko_4 = '낭비를 막기 위해 천연 자원을 신중하게 관리해야 해요.', example_en_5 = 'Solar and wind energy are resources that will never run out.', example_ko_5 = '태양과 바람 에너지는 절대 고갈되지 않는 자원이에요.' WHERE id = 'w_environment_A2_17';
UPDATE words SET example_en_2 = 'Flooding can cause serious damage to homes and infrastructure.', example_ko_2 = '홍수는 주택과 기반시설에 심각한 피해를 줄 수 있어요.', example_en_3 = 'The oil spill caused lasting damage to the local ecosystem.', example_ko_3 = '기름 유출은 지역 생태계에 지속적인 피해를 일으켰어요.', example_en_4 = 'Air pollution can damage the lungs of people who breathe it in.', example_ko_4 = '대기 오염은 그것을 흡입하는 사람들의 폐를 손상시킬 수 있어요.', example_en_5 = 'The damage caused by deforestation takes decades to reverse.', example_ko_5 = '삼림 벌채로 인한 피해를 복구하는 데는 수십 년이 걸려요.' WHERE id = 'w_environment_A2_18';
UPDATE words SET example_en_2 = 'The river looks dirty because of chemical waste from the factory.', example_ko_2 = '공장의 화학 폐기물 때문에 강이 더러워 보여요.', example_en_3 = 'Dirty air caused by pollution is linked to many serious illnesses.', example_ko_3 = '오염으로 인한 더러운 공기는 많은 심각한 질병과 연관되어 있어요.', example_en_4 = 'It is unpleasant to swim in a dirty lake full of rubbish.', example_ko_4 = '쓰레기가 가득한 더러운 호수에서 수영하는 것은 불쾌해요.', example_en_5 = 'We must stop dirty industries from polluting our clean waterways.', example_ko_5 = '더러운 산업이 깨끗한 수로를 오염시키는 것을 막아야 해요.' WHERE id = 'w_environment_A2_19';
UPDATE words SET example_en_2 = 'You can plant vegetables in your garden to reduce food miles.', example_ko_2 = '식품 운송 거리를 줄이기 위해 정원에 채소를 심을 수 있어요.', example_en_3 = 'Community groups often plant trees to green their local area.', example_ko_3 = '지역 사회 단체들은 지역을 녹화하기 위해 종종 나무를 심어요.', example_en_4 = 'Plant a tree this year as your gift to the planet.', example_ko_4 = '올해 지구를 위한 선물로 나무 한 그루를 심어 보세요.', example_en_5 = 'Planting wildflowers helps to support bees and other pollinators.', example_ko_5 = '야생화를 심으면 벌과 다른 수분 매개자들을 도울 수 있어요.' WHERE id = 'w_environment_A2_20';
UPDATE words SET example_en_2 = 'Replacing old light bulbs with LEDs can save a lot of energy.', example_ko_2 = '오래된 전구를 LED로 교체하면 많은 에너지를 절약할 수 있어요.', example_en_3 = 'A broken light bulb should be disposed of safely as it contains glass.', example_ko_3 = '깨진 전구는 유리가 들어 있으므로 안전하게 처리해야 해요.', example_en_4 = 'The invention of the light bulb changed the way humans live and work.', example_ko_4 = '전구의 발명은 인간의 생활 방식과 일하는 방식을 바꾸었어요.', example_en_5 = 'LED light bulbs last much longer than traditional incandescent bulbs.', example_ko_5 = 'LED 전구는 기존 백열전구보다 훨씬 오래 사용할 수 있어요.' WHERE id = 'w_environment_A2_21';
UPDATE words SET example_en_2 = 'Remember to turn off the tap while you are brushing your teeth.', example_ko_2 = '양치질할 때 수도꼭지를 잠그는 것을 기억하세요.', example_en_3 = 'A dripping tap can waste hundreds of litres of water a year.', example_ko_3 = '수도꼭지에서 물이 새면 연간 수백 리터의 물이 낭비될 수 있어요.', example_en_4 = 'Check your taps regularly to ensure they do not leak and waste water.', example_ko_4 = '물이 새지 않도록 정기적으로 수도꼭지를 점검하세요.', example_en_5 = 'Fixing a leaking tap is one of the simplest ways to save water.', example_ko_5 = '새는 수도꼭지를 고치는 것은 물을 절약하는 가장 간단한 방법 중 하나예요.' WHERE id = 'w_environment_A2_22';
UPDATE words SET example_en_2 = 'Taking public transport instead of driving helps reduce air pollution.', example_ko_2 = '운전 대신 대중교통을 이용하면 대기 오염을 줄이는 데 도움이 돼요.', example_en_3 = 'Good public transport encourages people to leave their cars at home.', example_ko_3 = '좋은 대중교통 시스템은 사람들이 차를 집에 두도록 유도해요.', example_en_4 = 'Investing in public transport is key to building greener cities.', example_ko_4 = '대중교통에 투자하는 것은 더 친환경적인 도시를 만드는 열쇠예요.', example_en_5 = 'Public transport reduces the number of cars on the road and cuts emissions.', example_ko_5 = '대중교통은 도로의 차량 수를 줄이고 배출량을 감소시켜요.' WHERE id = 'w_environment_A2_23';
UPDATE words SET example_en_2 = 'We spent the morning cleaning up plastic waste from the beach.', example_ko_2 = '우리는 오전 내내 해변에서 플라스틱 폐기물을 청소하며 보냈어요.', example_en_3 = 'The beach was closed after an oil spill damaged the coastline.', example_ko_3 = '기름 유출로 해안선이 훼손된 후 해변이 폐쇄되었어요.', example_en_4 = 'Tourists should always leave the beach cleaner than they found it.', example_ko_4 = '관광객들은 항상 해변을 처음 왔을 때보다 더 깨끗하게 두고 떠나야 해요.', example_en_5 = 'Beach clean-up events bring communities together to protect the ocean.', example_ko_5 = '해변 청소 행사는 지역 사회가 함께 바다를 보호하는 기회가 돼요.' WHERE id = 'w_environment_A2_24';
UPDATE words SET example_en_2 = 'National parks are established to protect wildlife and natural landscapes.', example_ko_2 = '국립공원은 야생동물과 자연경관을 보호하기 위해 설립돼요.', example_en_3 = 'Urban expansion is destroying the habitats of local wildlife.', example_ko_3 = '도시 확장으로 지역 야생동물의 서식지가 파괴되고 있어요.', example_en_4 = 'Wildlife corridors help animals move safely between areas of habitat.', example_ko_4 = '야생동물 통로는 동물들이 서식지 사이를 안전하게 이동하는 데 도움을 줘요.', example_en_5 = 'We must protect wildlife before more species are lost forever.', example_ko_5 = '더 많은 종이 영원히 사라지기 전에 야생동물을 보호해야 해요.' WHERE id = 'w_environment_A2_25';
UPDATE words SET example_en_2 = 'Please put your rubbish in the bin provided in the park.', example_ko_2 = '공원에 비치된 쓰레기통에 쓰레기를 넣어 주세요.', example_en_3 = 'Some rubbish takes thousands of years to break down in a landfill.', example_ko_3 = '일부 쓰레기는 매립지에서 분해되는 데 수천 년이 걸려요.', example_en_4 = 'Separating your rubbish makes recycling much easier and more efficient.', example_ko_4 = '쓰레기를 분리하면 재활용이 훨씬 쉽고 효율적이 돼요.', example_en_5 = 'Reducing the amount of rubbish we produce starts with buying less.', example_ko_5 = '우리가 만들어 내는 쓰레기의 양을 줄이는 것은 덜 구매하는 것에서 시작해요.' WHERE id = 'w_environment_A2_26';
UPDATE words SET example_en_2 = 'Compost is a natural fertiliser made from rotting food and plant material.', example_ko_2 = '퇴비는 썩은 음식과 식물 재료로 만든 천연 비료예요.', example_en_3 = 'Making compost at home helps to reduce the amount of waste you produce.', example_ko_3 = '집에서 퇴비를 만들면 발생하는 쓰레기의 양을 줄이는 데 도움이 돼요.', example_en_4 = 'Vegetable peelings, coffee grounds, and eggshells are great for compost.', example_ko_4 = '채소 껍질, 커피 찌꺼기, 달걀 껍데기는 퇴비에 좋아요.', example_en_5 = 'Adding compost to your garden soil helps plants to grow more strongly.', example_ko_5 = '정원 흙에 퇴비를 추가하면 식물이 더 튼튼하게 자라는 데 도움이 돼요.' WHERE id = 'w_environment_A2_27';
UPDATE words SET example_en_2 = 'The flood damaged hundreds of homes in the low-lying areas.', example_ko_2 = '홍수로 저지대에 있는 수백 채의 집이 피해를 입었어요.', example_en_3 = 'Heavy rain caused the river to overflow and flood the fields.', example_ko_3 = '폭우로 강이 넘쳐 들판이 침수되었어요.', example_en_4 = 'Climate change is making floods more frequent and more severe.', example_ko_4 = '기후 변화로 홍수가 더 자주, 더 심하게 발생하고 있어요.', example_en_5 = 'The government built flood barriers to protect the town from flooding.', example_ko_5 = '정부는 마을을 홍수로부터 보호하기 위해 홍수 방벽을 세웠어요.' WHERE id = 'w_environment_A2_28';
UPDATE words SET example_en_2 = 'The storm knocked down trees and cut off electricity for many homes.', example_ko_2 = '폭풍이 나무를 쓰러뜨리고 많은 가정의 전기를 끊어 버렸어요.', example_en_3 = 'Storms are becoming stronger and more frequent due to climate change.', example_ko_3 = '기후 변화로 인해 폭풍이 더 강해지고 더 자주 발생하고 있어요.', example_en_4 = 'The coastal town was badly damaged by a powerful storm last winter.', example_ko_4 = '지난 겨울 강력한 폭풍으로 해안 마을이 심하게 피해를 입었어요.', example_en_5 = 'Always prepare an emergency kit in case a storm cuts your power.', example_ko_5 = '폭풍으로 전력이 끊길 경우를 대비해 항상 비상 키트를 준비해 두세요.' WHERE id = 'w_environment_A2_29';
UPDATE words SET example_en_2 = 'The temperature of the oceans is rising due to global warming.', example_ko_2 = '지구 온난화로 인해 해양의 온도가 상승하고 있어요.', example_en_3 = 'Scientists monitor the temperature of the atmosphere to track climate change.', example_ko_3 = '과학자들은 기후 변화를 추적하기 위해 대기 온도를 모니터링해요.', example_en_4 = 'A rise in global temperature of just two degrees can have serious consequences.', example_ko_4 = '전 세계 기온이 단 2도만 올라도 심각한 결과를 초래할 수 있어요.', example_en_5 = 'Check the temperature forecast before you go hiking in the mountains.', example_ko_5 = '산에 등산하러 가기 전에 기온 예보를 확인하세요.' WHERE id = 'w_environment_A2_30';
UPDATE words SET example_en_2 = 'Fresh air and exercise are essential for good physical health.', example_ko_2 = '신선한 공기와 운동은 좋은 신체 건강을 위해 꼭 필요해요.', example_en_3 = 'This spring water tastes so fresh and clean straight from the source.', example_ko_3 = '이 샘물은 수원에서 바로 마시면 정말 신선하고 깨끗한 맛이 나요.', example_en_4 = 'Buy fresh, locally grown produce to reduce your environmental impact.', example_ko_4 = '환경에 미치는 영향을 줄이기 위해 신선하고 지역에서 재배된 농산물을 구매하세요.', example_en_5 = 'A fresh coat of paint made the old building look much better.', example_ko_5 = '새로운 페인트칠로 오래된 건물이 훨씬 좋아 보였어요.' WHERE id = 'w_environment_A2_31';
UPDATE words SET example_en_2 = 'The prolonged drought has dried up rivers and harmed farmers.', example_ko_2 = '장기적인 가뭄으로 강이 말라버리고 농부들이 피해를 입었어요.', example_en_3 = 'Drought conditions are becoming more common in many parts of Africa.', example_ko_3 = '가뭄 상황이 아프리카의 많은 지역에서 더 일반적이 되고 있어요.', example_en_4 = 'Conserving water is especially important during periods of drought.', example_ko_4 = '가뭄 기간에는 물 절약이 특히 중요해요.', example_en_5 = 'Drought can lead to food shortages and force people to migrate.', example_ko_5 = '가뭄은 식량 부족을 초래하고 사람들이 이주하도록 만들 수 있어요.' WHERE id = 'w_environment_A2_32';
UPDATE words SET example_en_2 = 'The ocean covers more than 70 percent of the Earth''s surface.', example_ko_2 = '바다는 지구 표면의 70퍼센트 이상을 덮고 있어요.', example_en_3 = 'Plastic waste in the ocean is a growing threat to marine life.', example_ko_3 = '바다의 플라스틱 폐기물은 해양 생물에 대한 점점 커지는 위협이에요.', example_en_4 = 'The ocean absorbs a large amount of the carbon dioxide we produce.', example_ko_4 = '바다는 우리가 생산하는 이산화탄소의 상당량을 흡수해요.', example_en_5 = 'Rising ocean temperatures are causing coral reefs to bleach and die.', example_ko_5 = '해양 온도 상승으로 산호초가 탈색되어 죽어가고 있어요.' WHERE id = 'w_environment_A2_33';
UPDATE words SET example_en_2 = 'Protecting the environment is a shared responsibility for everyone.', example_ko_2 = '환경을 보호하는 것은 모두가 함께 나눠야 할 책임이에요.', example_en_3 = 'The environment cannot recover if we continue damaging it so quickly.', example_ko_3 = '우리가 계속 이렇게 빠르게 환경을 훼손한다면 환경은 회복될 수 없어요.', example_en_4 = 'Small changes in behaviour can have a big impact on the environment.', example_ko_4 = '행동의 작은 변화들이 환경에 큰 영향을 미칠 수 있어요.', example_en_5 = 'Schools teach children about the environment to build future green habits.', example_ko_5 = '학교에서는 아이들에게 미래의 친환경 습관을 기르기 위해 환경에 대해 가르쳐요.' WHERE id = 'w_environment_A2_34';
UPDATE words SET example_en_2 = 'Burning fossil fuels releases large amounts of carbon dioxide and other gases.', example_ko_2 = '화석 연료를 태우면 많은 양의 이산화탄소와 다른 가스들이 방출돼요.', example_en_3 = 'Many countries are trying to reduce their dependence on imported fuel.', example_ko_3 = '많은 나라들이 수입 연료에 대한 의존도를 줄이려고 노력하고 있어요.', example_en_4 = 'Electric vehicles do not use fuel and produce no direct exhaust emissions.', example_ko_4 = '전기차는 연료를 사용하지 않으며 직접적인 배기가스를 배출하지 않아요.', example_en_5 = 'Investing in renewable energy helps countries reduce their fuel costs over time.', example_ko_5 = '재생 에너지에 투자하면 국가들이 시간이 지남에 따라 연료 비용을 줄이는 데 도움이 돼요.' WHERE id = 'w_environment_A2_35';

-- B1 words

UPDATE words SET example_en_2 = 'Climate change is causing more extreme weather events around the world.', example_ko_2 = '기후 변화로 인해 전 세계에서 더 극단적인 기상 현상이 발생하고 있어요.', example_en_3 = 'We all have a role to play in addressing climate change.', example_ko_3 = '우리 모두 기후 변화에 대응하는 데 역할을 맡고 있어요.', example_en_4 = 'The Paris Agreement aims to limit the effects of climate change.', example_ko_4 = '파리 협약은 기후 변화의 영향을 제한하는 것을 목표로 해요.', example_en_5 = 'Young people are increasingly worried about the effects of climate change.', example_ko_5 = '젊은이들은 기후 변화의 영향에 대해 점점 더 걱정하고 있어요.' WHERE id = 'w_environment_B1_01';
UPDATE words SET example_en_2 = 'Trees absorb carbon from the atmosphere as they grow.', example_ko_2 = '나무는 자라면서 대기에서 탄소를 흡수해요.', example_en_3 = 'We need to find ways to capture and store carbon underground.', example_ko_3 = '탄소를 포집해 지하에 저장하는 방법을 찾아야 해요.', example_en_4 = 'Countries are setting carbon reduction targets to meet climate goals.', example_ko_4 = '각 나라들은 기후 목표를 달성하기 위해 탄소 감축 목표를 설정하고 있어요.', example_en_5 = 'The carbon stored in forests is released when they are burned.', example_ko_5 = '숲에 저장된 탄소는 불에 타면 방출돼요.' WHERE id = 'w_environment_B1_02';
UPDATE words SET example_en_2 = 'Transport is one of the biggest sources of greenhouse gas emissions.', example_ko_2 = '교통수단은 온실가스 배출의 가장 큰 원인 중 하나예요.', example_en_3 = 'New regulations will force factories to cut their emissions significantly.', example_ko_3 = '새로운 규제는 공장들이 배출량을 크게 줄이도록 강제할 거예요.', example_en_4 = 'The emissions from a single long-haul flight are very significant.', example_ko_4 = '장거리 비행 한 번의 배출량은 매우 상당해요.', example_en_5 = 'Switching to electric cars would dramatically reduce urban emissions.', example_ko_5 = '전기차로 전환하면 도시 배출량을 크게 줄일 수 있어요.' WHERE id = 'w_environment_B1_03';
UPDATE words SET example_en_2 = 'A sustainable lifestyle means using only what the planet can provide.', example_ko_2 = '지속 가능한 생활 방식은 지구가 제공할 수 있는 것만 사용한다는 뜻이에요.', example_en_3 = 'Companies are under pressure to adopt more sustainable business practices.', example_ko_3 = '기업들은 더 지속 가능한 사업 방식을 채택하라는 압박을 받고 있어요.', example_en_4 = 'Sustainable agriculture protects soil and water for future generations.', example_ko_4 = '지속 가능한 농업은 미래 세대를 위해 토양과 물을 보호해요.', example_en_5 = 'Sustainable tourism means visiting places without damaging the environment.', example_ko_5 = '지속 가능한 관광은 환경을 해치지 않고 장소를 방문한다는 뜻이에요.' WHERE id = 'w_environment_B1_04';
UPDATE words SET example_en_2 = 'Wind and solar are renewable sources of electricity that never run out.', example_ko_2 = '풍력과 태양광은 절대 고갈되지 않는 재생 가능한 전력 원천이에요.', example_en_3 = 'Investment in renewable technology has grown significantly in recent years.', example_ko_3 = '최근 몇 년 동안 재생 기술에 대한 투자가 크게 증가했어요.', example_en_4 = 'Switching to renewable energy is essential for reaching net zero.', example_ko_4 = '재생 에너지로 전환하는 것은 탄소 중립을 달성하는 데 필수적이에요.', example_en_5 = 'Many countries now generate a significant share of electricity from renewable sources.', example_ko_5 = '많은 나라들이 이제 전력의 상당 부분을 재생 가능 에너지원에서 생산해요.' WHERE id = 'w_environment_B1_05';
UPDATE words SET example_en_2 = 'The destruction of habitats is threatening many delicate ecosystems.', example_ko_2 = '서식지 파괴가 많은 섬세한 생태계를 위협하고 있어요.', example_en_3 = 'A healthy ecosystem provides clean water, air, and food for all living things.', example_ko_3 = '건강한 생태계는 모든 생물에게 깨끗한 물, 공기, 그리고 먹이를 제공해요.', example_en_4 = 'Introducing non-native species can severely disrupt a local ecosystem.', example_ko_4 = '비원산 종을 도입하면 지역 생태계가 심각하게 교란될 수 있어요.', example_en_5 = 'Marine ecosystems are highly sensitive to changes in water temperature.', example_ko_5 = '해양 생태계는 수온 변화에 매우 민감해요.' WHERE id = 'w_environment_B1_06';
UPDATE words SET example_en_2 = 'Biodiversity refers to the variety of all living things on Earth.', example_ko_2 = '생물 다양성은 지구상의 모든 생물의 다양성을 말해요.', example_en_3 = 'High biodiversity makes an ecosystem more resilient to disturbance.', example_ko_3 = '높은 생물 다양성은 생태계를 교란에 더 잘 견딜 수 있게 해요.', example_en_4 = 'Deforestation is one of the greatest threats to global biodiversity.', example_ko_4 = '삼림 벌채는 전 세계 생물 다양성에 대한 가장 큰 위협 중 하나예요.', example_en_5 = 'Protecting biodiversity means protecting the future of life on Earth.', example_ko_5 = '생물 다양성을 보호하는 것은 지구 생명의 미래를 보호하는 것이에요.' WHERE id = 'w_environment_B1_07';
UPDATE words SET example_en_2 = 'Many animals are losing their habitat due to urban expansion.', example_ko_2 = '도시 확장으로 많은 동물들이 서식지를 잃고 있어요.', example_en_3 = 'Protecting natural habitat is the most effective way to conserve species.', example_ko_3 = '자연 서식지를 보호하는 것이 종을 보전하는 가장 효과적인 방법이에요.', example_en_4 = 'The wetland provides a vital habitat for migratory birds.', example_ko_4 = '습지는 철새들에게 중요한 서식지를 제공해요.', example_en_5 = 'Creating wildlife corridors can help connect fragmented habitats.', example_ko_5 = '야생동물 통로를 만들면 분산된 서식지를 연결하는 데 도움이 돼요.' WHERE id = 'w_environment_B1_08';
UPDATE words SET example_en_2 = 'Conservation efforts have helped the whale population to recover.', example_ko_2 = '보전 노력 덕분에 고래 개체 수가 회복되었어요.', example_en_3 = 'Water conservation is especially important in regions with little rainfall.', example_ko_3 = '물 보전은 강수량이 적은 지역에서 특히 중요해요.', example_en_4 = 'Conservation of natural resources is essential for long-term human wellbeing.', example_ko_4 = '천연 자원 보전은 인간의 장기적인 안녕을 위해 필수적이에요.', example_en_5 = 'The conservation programme has successfully protected several endangered species.', example_ko_5 = '그 보전 프로그램은 여러 멸종 위기 종들을 성공적으로 보호했어요.' WHERE id = 'w_environment_B1_09';
UPDATE words SET example_en_2 = 'Deforestation in the Amazon is happening at an alarming rate.', example_ko_2 = '아마존에서의 삼림 벌채가 놀라운 속도로 진행되고 있어요.', example_en_3 = 'Deforestation releases the carbon stored in trees back into the atmosphere.', example_ko_3 = '삼림 벌채는 나무에 저장된 탄소를 대기 중으로 다시 방출해요.', example_en_4 = 'Many communities are trying to stop deforestation in their local areas.', example_ko_4 = '많은 지역 사회들이 자신들의 지역에서 삼림 벌채를 막으려고 노력하고 있어요.', example_en_5 = 'Reducing demand for beef is one way to slow down deforestation.', example_ko_5 = '쇠고기 수요를 줄이는 것은 삼림 벌채를 늦추는 한 가지 방법이에요.' WHERE id = 'w_environment_B1_10';
UPDATE words SET example_en_2 = 'Methane and nitrous oxide are powerful greenhouse gases.', example_ko_2 = '메탄과 아산화질소는 강력한 온실가스예요.', example_en_3 = 'The main source of greenhouse gas emissions is the burning of fossil fuels.', example_ko_3 = '온실가스 배출의 주요 원인은 화석 연료 연소예요.', example_en_4 = 'Reducing greenhouse gas emissions is the key challenge of our time.', example_ko_4 = '온실가스 배출을 줄이는 것이 우리 시대의 핵심 과제예요.', example_en_5 = 'Agriculture contributes a significant portion of total greenhouse gas emissions.', example_ko_5 = '농업은 전체 온실가스 배출량의 상당 부분을 차지해요.' WHERE id = 'w_environment_B1_11';
UPDATE words SET example_en_2 = 'Global warming is causing sea levels to rise and glaciers to melt.', example_ko_2 = '지구 온난화로 인해 해수면이 상승하고 빙하가 녹고 있어요.', example_en_3 = 'Scientists have been warning about the risks of global warming for decades.', example_ko_3 = '과학자들은 수십 년 동안 지구 온난화의 위험성에 대해 경고해 왔어요.', example_en_4 = 'Global warming affects weather patterns, agriculture, and biodiversity.', example_ko_4 = '지구 온난화는 기상 패턴, 농업, 생물 다양성에 영향을 미쳐요.', example_en_5 = 'Limiting global warming to 1.5 degrees requires urgent and ambitious action.', example_ko_5 = '지구 온난화를 1.5도로 제한하려면 긴급하고 야심찬 행동이 필요해요.' WHERE id = 'w_environment_B1_12';
UPDATE words SET example_en_2 = 'Carbon dioxide is produced when fossil fuels are burned.', example_ko_2 = '화석 연료가 연소될 때 이산화탄소가 생성돼요.', example_en_3 = 'The concentration of carbon dioxide in the atmosphere is rising every year.', example_ko_3 = '대기 중 이산화탄소 농도가 매년 증가하고 있어요.', example_en_4 = 'Forests play a critical role in absorbing carbon dioxide from the air.', example_ko_4 = '숲은 공기 중에서 이산화탄소를 흡수하는 데 중요한 역할을 해요.', example_en_5 = 'Reducing carbon dioxide levels is essential for stabilising the climate.', example_ko_5 = '이산화탄소 수준을 낮추는 것은 기후를 안정시키는 데 필수적이에요.' WHERE id = 'w_environment_B1_13';
UPDATE words SET example_en_2 = 'Investment in renewable energy has created millions of new jobs globally.', example_ko_2 = '재생 에너지에 대한 투자가 전 세계적으로 수백만 개의 새로운 일자리를 창출했어요.', example_en_3 = 'Renewable energy now provides a growing share of the world''s electricity.', example_ko_3 = '재생 에너지는 이제 전 세계 전력의 증가하는 비중을 공급하고 있어요.', example_en_4 = 'The transition to renewable energy must happen as quickly as possible.', example_ko_4 = '재생 에너지로의 전환은 가능한 한 빨리 이루어져야 해요.', example_en_5 = 'Governments are offering subsidies to encourage investment in renewable energy.', example_ko_5 = '정부들은 재생 에너지 투자를 장려하기 위해 보조금을 제공하고 있어요.' WHERE id = 'w_environment_B1_14';
UPDATE words SET example_en_2 = 'Your carbon footprint includes all the emissions caused by your daily life.', example_ko_2 = '탄소 발자국에는 일상생활로 인한 모든 배출량이 포함돼요.', example_en_3 = 'Flying less is one of the most effective ways to reduce your carbon footprint.', example_ko_3 = '비행기를 덜 타는 것이 탄소 발자국을 줄이는 가장 효과적인 방법 중 하나예요.', example_en_4 = 'Eating a plant-based diet can significantly lower your carbon footprint.', example_ko_4 = '식물성 식단을 먹으면 탄소 발자국을 크게 낮출 수 있어요.', example_en_5 = 'There are online calculators to help you measure your carbon footprint.', example_ko_5 = '탄소 발자국을 측정하는 데 도움이 되는 온라인 계산기가 있어요.' WHERE id = 'w_environment_B1_15';
UPDATE words SET example_en_2 = 'There are estimated to be over eight million species on Earth.', example_ko_2 = '지구에는 800만 종 이상의 생물이 있는 것으로 추정돼요.', example_en_3 = 'Each species plays a unique role in maintaining a balanced ecosystem.', example_ko_3 = '각 종은 균형 잡힌 생태계를 유지하는 데 고유한 역할을 해요.', example_en_4 = 'When a species goes extinct, its role in the ecosystem is lost forever.', example_ko_4 = '종이 멸종하면 생태계에서 그 종의 역할이 영원히 사라져요.', example_en_5 = 'Scientists are discovering new species even as others are disappearing.', example_ko_5 = '과학자들은 다른 종들이 사라지는 동안에도 새로운 종들을 발견하고 있어요.' WHERE id = 'w_environment_B1_16';
UPDATE words SET example_en_2 = 'The giant panda is endangered due to the destruction of its bamboo habitat.', example_ko_2 = '자이언트 판다는 대나무 서식지 파괴로 멸종 위기에 처해 있어요.', example_en_3 = 'Many marine species are now endangered because of ocean pollution.', example_ko_3 = '많은 해양 종들이 바다 오염 때문에 현재 멸종 위기에 처해 있어요.', example_en_4 = 'The government listed the tiger as an endangered species to protect it.', example_ko_4 = '정부는 호랑이를 보호하기 위해 멸종 위기종으로 지정했어요.', example_en_5 = 'Illegal hunting and habitat loss are the main reasons species become endangered.', example_ko_5 = '불법 사냥과 서식지 손실이 종이 멸종 위기에 처하는 주요 이유예요.' WHERE id = 'w_environment_B1_17';
UPDATE words SET example_en_2 = 'A solar panel on the roof can generate electricity for the whole house.', example_ko_2 = '지붕에 설치된 태양 전지판으로 집 전체에 전기를 공급할 수 있어요.', example_en_3 = 'The price of solar panels has fallen dramatically over the past decade.', example_ko_3 = '지난 10년 동안 태양 전지판 가격이 크게 하락했어요.', example_en_4 = 'Countries with lots of sunshine are investing heavily in solar panels.', example_ko_4 = '햇빛이 풍부한 나라들은 태양 전지판에 많은 투자를 하고 있어요.', example_en_5 = 'Solar panels need very little maintenance once they have been installed.', example_ko_5 = '태양 전지판은 설치된 후 유지 보수가 거의 필요하지 않아요.' WHERE id = 'w_environment_B1_18';
UPDATE words SET example_en_2 = 'The wind turbine generates electricity without producing any emissions.', example_ko_2 = '풍력 터빈은 어떤 배출도 없이 전기를 생산해요.', example_en_3 = 'Large wind turbines can be seen spinning slowly on the hills.', example_ko_3 = '언덕에서 큰 풍력 터빈이 천천히 돌아가는 것을 볼 수 있어요.', example_en_4 = 'Offshore wind turbines can generate electricity without taking up land.', example_ko_4 = '해상 풍력 터빈은 땅을 차지하지 않고 전기를 생산할 수 있어요.', example_en_5 = 'Building more wind turbines will help us reduce our reliance on fossil fuels.', example_ko_5 = '더 많은 풍력 터빈을 건설하면 화석 연료 의존도를 줄이는 데 도움이 될 거예요.' WHERE id = 'w_environment_B1_19';
UPDATE words SET example_en_2 = 'Coal, oil, and gas are all types of fossil fuel.', example_ko_2 = '석탄, 석유, 천연가스는 모두 화석 연료의 종류예요.', example_en_3 = 'Burning fossil fuel releases carbon dioxide that was stored for millions of years.', example_ko_3 = '화석 연료를 태우면 수백만 년 동안 저장된 이산화탄소가 방출돼요.', example_en_4 = 'Many countries are trying to phase out their use of fossil fuel.', example_ko_4 = '많은 나라들이 화석 연료 사용을 단계적으로 줄이려고 노력하고 있어요.', example_en_5 = 'The world''s dependence on fossil fuel is one of the root causes of climate change.', example_ko_5 = '화석 연료에 대한 세계의 의존은 기후 변화의 근본 원인 중 하나예요.' WHERE id = 'w_environment_B1_20';
UPDATE words SET example_en_2 = 'The iceberg was so huge that most of it was hidden below the water.', example_ko_2 = '그 빙산은 너무 커서 대부분이 수면 아래에 숨겨져 있었어요.', example_en_3 = 'Icebergs break off from glaciers as the ice melts.', example_ko_3 = '빙하가 녹으면서 빙산이 빙하에서 분리돼요.', example_en_4 = 'Warmer ocean temperatures are causing icebergs to melt faster than before.', example_ko_4 = '따뜻해진 해양 온도로 인해 빙산이 이전보다 더 빠르게 녹고 있어요.', example_en_5 = 'Melting icebergs contribute to rising sea levels around the world.', example_ko_5 = '녹는 빙산은 전 세계 해수면 상승에 기여해요.' WHERE id = 'w_environment_B1_21';
UPDATE words SET example_en_2 = 'The polar ice caps are melting at an unprecedented rate.', example_ko_2 = '극지방 빙모가 전례 없는 속도로 녹고 있어요.', example_en_3 = 'When glaciers melt, the water flows into the sea and raises sea levels.', example_ko_3 = '빙하가 녹으면 물이 바다로 흘러 들어가 해수면을 높여요.', example_en_4 = 'Snow and ice melt faster when the temperature rises above zero.', example_ko_4 = '기온이 영도 이상으로 올라가면 눈과 얼음이 더 빨리 녹아요.', example_en_5 = 'Scientists track how quickly glaciers melt to monitor global warming.', example_ko_5 = '과학자들은 지구 온난화를 모니터링하기 위해 빙하가 얼마나 빨리 녹는지 추적해요.' WHERE id = 'w_environment_B1_22';
UPDATE words SET example_en_2 = 'The atmosphere contains the air we breathe and protects us from the sun.', example_ko_2 = '대기는 우리가 숨 쉬는 공기를 담고 있으며 태양으로부터 우리를 보호해요.', example_en_3 = 'Greenhouse gases trap heat in the atmosphere and warm the planet.', example_ko_3 = '온실가스는 대기 중에 열을 가두어 지구를 따뜻하게 해요.', example_en_4 = 'Carbon dioxide levels in the atmosphere are higher now than ever before.', example_ko_4 = '대기 중 이산화탄소 수준은 지금이 역사상 가장 높아요.', example_en_5 = 'Pollution from industry is changing the chemical composition of the atmosphere.', example_ko_5 = '산업 오염이 대기의 화학적 구성을 변화시키고 있어요.' WHERE id = 'w_environment_B1_23';
UPDATE words SET example_en_2 = 'Organic food is grown without the use of artificial chemicals or pesticides.', example_ko_2 = '유기농 식품은 인공 화학물질이나 농약을 사용하지 않고 재배돼요.', example_en_3 = 'Buying organic produce supports farmers who protect the soil and water.', example_ko_3 = '유기농 농산물을 구매하면 토양과 물을 보호하는 농부들을 지지하는 거예요.', example_en_4 = 'Organic farming uses natural methods to manage pests and improve soil health.', example_ko_4 = '유기농 농업은 해충을 관리하고 토양 건강을 개선하기 위해 자연적인 방법을 사용해요.', example_en_5 = 'Switching to organic products can help reduce chemical pollution in waterways.', example_ko_5 = '유기농 제품으로 전환하면 수로의 화학 오염을 줄이는 데 도움이 돼요.' WHERE id = 'w_environment_B1_24';
UPDATE words SET example_en_2 = 'Sending food waste to a landfill releases methane, a powerful greenhouse gas.', example_ko_2 = '음식물 쓰레기를 매립지에 보내면 강력한 온실가스인 메탄이 방출돼요.', example_en_3 = 'Many cities are running out of space for new landfills.', example_ko_3 = '많은 도시들이 새 매립지를 위한 공간이 부족해지고 있어요.', example_en_4 = 'Reducing waste is better for the environment than sending it to a landfill.', example_ko_4 = '쓰레기를 매립지에 보내는 것보다 쓰레기를 줄이는 것이 환경에 더 좋아요.', example_en_5 = 'Composting diverts organic waste from landfills and reduces emissions.', example_ko_5 = '퇴비화는 유기 폐기물을 매립지에서 다른 곳으로 전환하고 배출량을 줄여요.' WHERE id = 'w_environment_B1_25';
UPDATE words SET example_en_2 = 'Certain chemicals in aerosol sprays are harmful to the ozone layer.', example_ko_2 = '에어로졸 스프레이의 일부 화학물질은 오존층에 해로워요.', example_en_3 = 'The ozone layer protects Earth from harmful ultraviolet radiation.', example_ko_3 = '오존층은 지구를 해로운 자외선으로부터 보호해요.', example_en_4 = 'International agreements have helped the ozone layer to slowly recover.', example_ko_4 = '국제 협약 덕분에 오존층이 천천히 회복되고 있어요.', example_en_5 = 'Without the ozone layer, life on Earth would be very difficult.', example_ko_5 = '오존층이 없다면 지구에서의 생명은 매우 어려울 거예요.' WHERE id = 'w_environment_B1_26';
UPDATE words SET example_en_2 = 'Rising ocean temperatures are causing coral reefs to bleach and die.', example_ko_2 = '해양 온도 상승으로 산호초가 탈색되어 죽어가고 있어요.', example_en_3 = 'Coral reefs provide habitat for approximately 25 percent of all marine species.', example_ko_3 = '산호초는 모든 해양 종의 약 25퍼센트에 서식지를 제공해요.', example_en_4 = 'Protecting coral reefs requires reducing both pollution and global warming.', example_ko_4 = '산호초를 보호하려면 오염과 지구 온난화를 동시에 줄여야 해요.', example_en_5 = 'Tourists are asked not to touch the coral reef as it is very fragile.', example_ko_5 = '산호초는 매우 섬세하므로 관광객들에게 만지지 말 것을 요청해요.' WHERE id = 'w_environment_B1_27';
UPDATE words SET example_en_2 = 'If sea levels continue to rise, many coastal cities will be flooded.', example_ko_2 = '해수면이 계속 상승한다면 많은 해안 도시들이 침수될 거예요.', example_en_3 = 'Scientists are closely monitoring changes in sea level around the world.', example_ko_3 = '과학자들은 전 세계 해수면 변화를 면밀히 모니터링하고 있어요.', example_en_4 = 'Melting ice sheets in Greenland and Antarctica are raising sea level.', example_ko_4 = '그린란드와 남극 대륙의 빙상이 녹아 해수면이 상승하고 있어요.', example_en_5 = 'Low-lying island nations face serious risks from rising sea level.', example_ko_5 = '저지대 섬나라들은 해수면 상승으로 심각한 위험에 처해 있어요.' WHERE id = 'w_environment_B1_28';
UPDATE words SET example_en_2 = 'Mountain glaciers provide fresh water to millions of people downstream.', example_ko_2 = '산 빙하는 하류의 수백만 명의 사람들에게 담수를 공급해요.', example_en_3 = 'The glacier has retreated several kilometres over the past fifty years.', example_ko_3 = '빙하가 지난 50년 동안 몇 킬로미터나 후퇴했어요.', example_en_4 = 'Scientists measure the volume of a glacier to track how fast it is melting.', example_ko_4 = '과학자들은 빙하가 얼마나 빨리 녹는지 추적하기 위해 빙하의 부피를 측정해요.', example_en_5 = 'Many glaciers that existed fifty years ago have now completely disappeared.', example_ko_5 = '50년 전에 존재했던 많은 빙하가 이제 완전히 사라졌어요.' WHERE id = 'w_environment_B1_29';
UPDATE words SET example_en_2 = 'Reforestation programmes can help restore lost biodiversity to an area.', example_ko_2 = '재조림 프로그램은 지역의 잃어버린 생물 다양성을 회복하는 데 도움이 돼요.', example_en_3 = 'Millions of trees have been planted as part of a national reforestation effort.', example_ko_3 = '전국적인 재조림 노력의 일환으로 수백만 그루의 나무가 심어졌어요.', example_en_4 = 'Reforestation is an important tool for absorbing carbon from the atmosphere.', example_ko_4 = '재조림은 대기 중 탄소를 흡수하는 중요한 수단이에요.', example_en_5 = 'Communities are joining together to support large-scale reforestation projects.', example_ko_5 = '지역 사회들이 대규모 재조림 프로젝트를 지원하기 위해 힘을 합치고 있어요.' WHERE id = 'w_environment_B1_30';
UPDATE words SET example_en_2 = 'Acid rain damages forests, lakes, and the buildings in cities.', example_ko_2 = '산성비는 숲, 호수, 그리고 도시의 건물을 손상시켜요.', example_en_3 = 'Acid rain is caused by sulphur dioxide and nitrogen oxide emissions from industry.', example_ko_3 = '산성비는 산업에서 배출되는 이산화황과 질소산화물에 의해 발생해요.', example_en_4 = 'Legislation to reduce emissions has helped lower the occurrence of acid rain.', example_ko_4 = '배출량을 줄이기 위한 법률이 산성비 발생을 줄이는 데 도움이 되었어요.', example_en_5 = 'The effects of acid rain on ecosystems can last for many decades.', example_ko_5 = '산성비가 생태계에 미치는 영향은 수십 년 동안 지속될 수 있어요.' WHERE id = 'w_environment_B1_31';
UPDATE words SET example_en_2 = 'Pesticides used in farming can run off into rivers and harm wildlife.', example_ko_2 = '농업에 사용되는 농약이 강으로 유출되어 야생동물에게 해를 끼칠 수 있어요.', example_en_3 = 'The use of pesticides has declined as more farmers switch to organic methods.', example_ko_3 = '더 많은 농부들이 유기농법으로 전환하면서 농약 사용이 줄어들었어요.', example_en_4 = 'Some pesticides remain in the soil for years after they have been applied.', example_ko_4 = '일부 농약은 사용 후 수년 동안 토양에 남아 있어요.', example_en_5 = 'Bees are particularly vulnerable to the effects of certain pesticides.', example_ko_5 = '벌들은 특정 농약의 영향에 특히 취약해요.' WHERE id = 'w_environment_B1_32';
UPDATE words SET example_en_2 = 'The water cycle moves water from the ocean to the sky and back to Earth.', example_ko_2 = '물의 순환은 물을 바다에서 하늘로, 그리고 다시 지구로 이동시켜요.', example_en_3 = 'Disrupting the water cycle can lead to floods and droughts in different regions.', example_ko_3 = '물의 순환이 교란되면 다른 지역에서 홍수와 가뭄이 발생할 수 있어요.', example_en_4 = 'Deforestation can disrupt the local water cycle and reduce rainfall.', example_ko_4 = '삼림 벌채는 지역 물의 순환을 교란하고 강수량을 줄일 수 있어요.', example_en_5 = 'Understanding the water cycle is essential for managing water resources wisely.', example_ko_5 = '물의 순환을 이해하는 것은 수자원을 현명하게 관리하는 데 필수적이에요.' WHERE id = 'w_environment_B1_33';
UPDATE words SET example_en_2 = 'Overpopulation puts enormous pressure on natural resources and ecosystems.', example_ko_2 = '인구 과잉은 천연 자원과 생태계에 엄청난 압박을 가해요.', example_en_3 = 'Rapid overpopulation in urban areas creates serious environmental challenges.', example_ko_3 = '도시 지역의 급격한 인구 과잉은 심각한 환경 문제를 만들어 내요.', example_en_4 = 'Managing overpopulation requires access to education and family planning.', example_ko_4 = '인구 과잉을 관리하려면 교육과 가족 계획에 대한 접근이 필요해요.', example_en_5 = 'Overpopulation increases demand for land, energy, water, and food.', example_ko_5 = '인구 과잉은 토지, 에너지, 물, 식량에 대한 수요를 높여요.' WHERE id = 'w_environment_B1_34';
UPDATE words SET example_en_2 = 'The company pledged to become carbon neutral by the end of the decade.', example_ko_2 = '그 회사는 이번 십 년이 끝날 때까지 탄소 중립이 되겠다고 약속했어요.', example_en_3 = 'Being carbon neutral means balancing the amount of carbon you emit and absorb.', example_ko_3 = '탄소 중립이란 배출하는 탄소의 양과 흡수하는 양의 균형을 맞춘다는 뜻이에요.', example_en_4 = 'Planting trees and using renewable energy can help a company become carbon neutral.', example_ko_4 = '나무를 심고 재생 에너지를 사용하면 기업이 탄소 중립이 되는 데 도움이 돼요.', example_en_5 = 'Achieving carbon neutral status requires both reducing and offsetting emissions.', example_ko_5 = '탄소 중립 지위를 달성하려면 배출량을 줄이고 상쇄해야 해요.' WHERE id = 'w_environment_B1_35';

-- B2 words

UPDATE words SET example_en_2 = 'Climate mitigation involves actions that reduce the sources of greenhouse gases.', example_ko_2 = '기후 완화는 온실가스 원인을 줄이는 행동을 포함해요.', example_en_3 = 'Mitigation strategies include switching to renewable energy and protecting forests.', example_ko_3 = '완화 전략에는 재생 에너지로 전환하고 숲을 보호하는 것이 포함돼요.', example_en_4 = 'Mitigation alone is not enough; we also need to adapt to existing changes.', example_ko_4 = '완화만으로는 충분하지 않아요. 기존 변화에도 적응해야 해요.', example_en_5 = 'Early mitigation is far less costly than dealing with the consequences later.', example_ko_5 = '조기 완화는 나중에 결과를 처리하는 것보다 훨씬 비용이 적게 들어요.' WHERE id = 'w_environment_B2_01';
UPDATE words SET example_en_2 = 'Adaptation to climate change includes building flood defences and drought-resistant crops.', example_ko_2 = '기후 변화 적응에는 홍수 방어 시설 건설과 가뭄 저항성 작물 개발이 포함돼요.', example_en_3 = 'Developing nations need financial support for adaptation to climate impacts.', example_ko_3 = '개발도상국들은 기후 영향에 대한 적응을 위해 재정 지원이 필요해요.', example_en_4 = 'Community adaptation plans can reduce the damage caused by extreme weather.', example_ko_4 = '지역 사회 적응 계획은 극단적인 기상 현상으로 인한 피해를 줄일 수 있어요.', example_en_5 = 'Adaptation measures must be integrated into national development strategies.', example_ko_5 = '적응 조치는 국가 개발 전략에 통합되어야 해요.' WHERE id = 'w_environment_B2_02';
UPDATE words SET example_en_2 = 'Desertification is turning productive farmland into barren desert.', example_ko_2 = '사막화가 생산적인 농지를 황량한 사막으로 만들고 있어요.', example_en_3 = 'Overgrazing and deforestation are major causes of desertification.', example_ko_3 = '과잉 방목과 삼림 벌채는 사막화의 주요 원인이에요.', example_en_4 = 'Desertification threatens the food security of millions of people.', example_ko_4 = '사막화는 수백만 명의 식량 안보를 위협해요.', example_en_5 = 'Planting drought-resistant trees can help slow the spread of desertification.', example_ko_5 = '가뭄에 강한 나무를 심으면 사막화 확산을 늦추는 데 도움이 돼요.' WHERE id = 'w_environment_B2_03';
UPDATE words SET example_en_2 = 'Ozone depletion allows more ultraviolet radiation to reach the Earth''s surface.', example_ko_2 = '오존 고갈은 더 많은 자외선이 지구 표면에 도달하도록 해요.', example_en_3 = 'The Montreal Protocol helped slow ozone depletion by banning harmful chemicals.', example_ko_3 = '몬트리올 의정서는 유해 화학물질을 금지하여 오존 고갈을 늦추는 데 도움이 되었어요.', example_en_4 = 'Ozone depletion over the poles increases the risk of skin cancer.', example_ko_4 = '극지방 위의 오존 고갈은 피부암 위험을 높여요.', example_en_5 = 'Scientists continue to monitor ozone depletion levels with satellites.', example_ko_5 = '과학자들은 위성으로 오존 고갈 수준을 계속 모니터링하고 있어요.' WHERE id = 'w_environment_B2_04';
UPDATE words SET example_en_2 = 'Heavy metals are persistent toxins that accumulate in the food chain.', example_ko_2 = '중금속은 먹이 사슬에 축적되는 지속성 독소예요.', example_en_3 = 'Industrial toxins released into waterways can poison wildlife and humans.', example_ko_3 = '수로로 방류된 산업 독소는 야생동물과 인간을 독살할 수 있어요.', example_en_4 = 'Environmental toxins have been linked to developmental problems in children.', example_ko_4 = '환경 독소는 아동의 발달 문제와 관련이 있는 것으로 밝혀졌어요.', example_en_5 = 'Stricter regulations on industrial toxins are needed to protect public health.', example_ko_5 = '공중 보건을 보호하기 위해 산업 독소에 대한 더 엄격한 규제가 필요해요.' WHERE id = 'w_environment_B2_05';
UPDATE words SET example_en_2 = 'The greenhouse effect is a natural process that keeps the Earth warm enough to support life.', example_ko_2 = '온실 효과는 지구가 생명을 유지할 만큼 따뜻하게 해주는 자연 과정이에요.', example_en_3 = 'Human activities have intensified the greenhouse effect, leading to global warming.', example_ko_3 = '인간 활동이 온실 효과를 강화하여 지구 온난화를 초래하고 있어요.', example_en_4 = 'Without any greenhouse effect, the Earth would be too cold for life.', example_ko_4 = '온실 효과가 없다면 지구는 생명이 살기에 너무 추울 거예요.', example_en_5 = 'Reducing emissions is essential to limit the enhanced greenhouse effect.', example_ko_5 = '강화된 온실 효과를 제한하려면 배출량을 줄이는 것이 필수적이에요.' WHERE id = 'w_environment_B2_06';
UPDATE words SET example_en_2 = 'Biodegradable packaging breaks down naturally and does not pollute the environment.', example_ko_2 = '생분해성 포장재는 자연적으로 분해되어 환경을 오염시키지 않아요.', example_en_3 = 'Not all products labelled biodegradable break down quickly in landfills.', example_ko_3 = '생분해성이라고 표시된 모든 제품이 매립지에서 빠르게 분해되는 것은 아니에요.', example_en_4 = 'Using biodegradable materials reduces the burden on landfills and oceans.', example_ko_4 = '생분해성 재료를 사용하면 매립지와 바다에 가해지는 부담이 줄어들어요.', example_en_5 = 'Switching to biodegradable cleaning products helps protect waterways.', example_ko_5 = '생분해성 세정 제품으로 전환하면 수로를 보호하는 데 도움이 돼요.' WHERE id = 'w_environment_B2_07';
UPDATE words SET example_en_2 = 'Fine particulate matter from traffic causes serious respiratory health problems.', example_ko_2 = '교통에서 나오는 미세먼지는 심각한 호흡기 건강 문제를 유발해요.', example_en_3 = 'Particulate matter in the air is invisible but extremely harmful to the lungs.', example_ko_3 = '공기 중 미세먼지는 눈에 보이지 않지만 폐에 매우 해로워요.', example_en_4 = 'Industrial facilities must install filters to reduce particulate matter emissions.', example_ko_4 = '산업 시설은 미세먼지 배출을 줄이기 위해 필터를 설치해야 해요.', example_en_5 = 'Cities with high particulate matter levels suffer from poor air quality.', example_ko_5 = '미세먼지 수준이 높은 도시들은 열악한 대기 질로 고통받아요.' WHERE id = 'w_environment_B2_08';
UPDATE words SET example_en_2 = 'The ecological impact of building a new road through the forest must be assessed.', example_ko_2 = '숲을 관통하는 새 도로 건설의 생태적 영향을 평가해야 해요.', example_en_3 = 'Ecological restoration helps damaged habitats recover their natural function.', example_ko_3 = '생태 복원은 손상된 서식지가 자연적 기능을 회복하는 데 도움이 돼요.', example_en_4 = 'An ecological survey was conducted before the construction project began.', example_ko_4 = '건설 프로젝트가 시작되기 전에 생태 조사가 실시되었어요.', example_en_5 = 'The company was criticised for ignoring the ecological consequences of its operations.', example_ko_5 = '그 회사는 운영의 생태적 결과를 무시했다는 비판을 받았어요.' WHERE id = 'w_environment_B2_09';
UPDATE words SET example_en_2 = 'Sustainable development ensures that economic growth does not come at nature''s expense.', example_ko_2 = '지속 가능한 발전은 경제 성장이 자연을 희생하며 이루어지지 않도록 보장해요.', example_en_3 = 'The UN Sustainable Development Goals provide a framework for a better future.', example_ko_3 = 'UN 지속 가능한 발전 목표는 더 나은 미래를 위한 틀을 제공해요.', example_en_4 = 'Sustainable development requires cooperation between governments, businesses, and citizens.', example_ko_4 = '지속 가능한 발전은 정부, 기업, 시민 간의 협력이 필요해요.', example_en_5 = 'Without sustainable development, we risk depleting the resources future generations need.', example_ko_5 = '지속 가능한 발전 없이는 미래 세대가 필요로 하는 자원을 고갈시킬 위험이 있어요.' WHERE id = 'w_environment_B2_10';
UPDATE words SET example_en_2 = 'Carbon sequestration involves capturing CO2 and storing it underground.', example_ko_2 = '탄소 격리는 이산화탄소를 포집하여 지하에 저장하는 것을 포함해요.', example_en_3 = 'Forests act as natural carbon sequestration systems by absorbing CO2.', example_ko_3 = '숲은 이산화탄소를 흡수하여 자연적인 탄소 격리 시스템 역할을 해요.', example_en_4 = 'Carbon sequestration technology is being tested at power stations worldwide.', example_ko_4 = '탄소 격리 기술이 전 세계 발전소에서 테스트되고 있어요.', example_en_5 = 'Improving carbon sequestration in soils could help offset some emissions.', example_ko_5 = '토양의 탄소 격리 능력을 개선하면 일부 배출량을 상쇄하는 데 도움이 될 수 있어요.' WHERE id = 'w_environment_B2_11';
UPDATE words SET example_en_2 = 'Bioaccumulation causes toxins to concentrate in the tissues of animals higher in the food chain.', example_ko_2 = '생물 축적으로 독소가 먹이 사슬 상위에 있는 동물의 조직에 농축돼요.', example_en_3 = 'Mercury bioaccumulation in fish makes them unsafe for human consumption.', example_ko_3 = '물고기에서의 수은 생물 축적은 인간이 섭취하기에 안전하지 않게 만들어요.', example_en_4 = 'Pesticides that resist breakdown are particularly prone to bioaccumulation.', example_ko_4 = '분해에 저항하는 농약은 생물 축적이 특히 잘 돼요.', example_en_5 = 'The bioaccumulation of plastic-related chemicals is a growing concern for scientists.', example_ko_5 = '플라스틱 관련 화학물질의 생물 축적은 과학자들의 점점 커지는 우려사항이에요.' WHERE id = 'w_environment_B2_12';
UPDATE words SET example_en_2 = 'Wetlands act as natural filters that clean water before it reaches rivers.', example_ko_2 = '습지는 물이 강에 도달하기 전에 정화하는 자연 필터 역할을 해요.', example_en_3 = 'Many species of migratory birds depend on wetlands for food and shelter.', example_ko_3 = '많은 종의 철새들이 먹이와 피신처를 위해 습지에 의존해요.', example_en_4 = 'Wetlands store large amounts of carbon and help regulate local climate.', example_ko_4 = '습지는 많은 양의 탄소를 저장하고 지역 기후 조절을 도와요.', example_en_5 = 'The drainage of wetlands for farming has led to significant habitat loss.', example_ko_5 = '농업을 위한 습지 배수가 상당한 서식지 손실을 초래했어요.' WHERE id = 'w_environment_B2_13';
UPDATE words SET example_en_2 = 'Methane is a greenhouse gas that is 80 times more potent than carbon dioxide.', example_ko_2 = '메탄은 이산화탄소보다 80배 더 강력한 온실가스예요.', example_en_3 = 'Livestock farming produces large quantities of methane through animal digestion.', example_ko_3 = '가축 농업은 동물의 소화를 통해 많은 양의 메탄을 생성해요.', example_en_4 = 'Landfills release methane as organic waste decomposes underground.', example_ko_4 = '유기 폐기물이 지하에서 분해될 때 매립지에서 메탄이 방출돼요.', example_en_5 = 'Reducing methane emissions could slow global warming more quickly than cutting CO2 alone.', example_ko_5 = '메탄 배출을 줄이면 이산화탄소만 줄이는 것보다 지구 온난화를 더 빠르게 늦출 수 있어요.' WHERE id = 'w_environment_B2_14';
UPDATE words SET example_en_2 = 'Marine pollution from plastic is choking wildlife and damaging ecosystems.', example_ko_2 = '플라스틱으로 인한 해양 오염이 야생동물을 질식시키고 생태계를 손상시키고 있어요.', example_en_3 = 'Chemical runoff from farms contributes significantly to marine pollution.', example_ko_3 = '농장에서 나오는 화학물질 유출이 해양 오염에 크게 기여해요.', example_en_4 = 'Marine pollution affects the livelihoods of fishing communities worldwide.', example_ko_4 = '해양 오염은 전 세계 어업 공동체의 생계에 영향을 미쳐요.', example_en_5 = 'International treaties are needed to tackle marine pollution across national borders.', example_ko_5 = '국경을 넘는 해양 오염을 해결하기 위해 국제 조약이 필요해요.' WHERE id = 'w_environment_B2_15';
UPDATE words SET example_en_2 = 'A carbon tax makes fossil fuels more expensive, encouraging cleaner alternatives.', example_ko_2 = '탄소세는 화석 연료를 더 비싸게 만들어 더 깨끗한 대안을 장려해요.', example_en_3 = 'Critics argue that a carbon tax places an unfair burden on lower-income households.', example_ko_3 = '비평가들은 탄소세가 저소득 가정에 불공평한 부담을 준다고 주장해요.', example_en_4 = 'Revenue from a carbon tax can be reinvested in clean energy and public transport.', example_ko_4 = '탄소세 수입은 청정 에너지와 대중교통에 재투자될 수 있어요.', example_en_5 = 'Several countries have introduced a carbon tax as part of their climate policy.', example_ko_5 = '여러 나라들이 기후 정책의 일환으로 탄소세를 도입했어요.' WHERE id = 'w_environment_B2_16';
UPDATE words SET example_en_2 = 'The global deforestation rate has slowed but remains far too high.', example_ko_2 = '전 세계 삼림 벌채율이 느려졌지만 여전히 너무 높아요.', example_en_3 = 'Protecting existing forests is more effective than trying to reduce the deforestation rate later.', example_ko_3 = '기존 숲을 보호하는 것이 나중에 삼림 벌채율을 줄이려는 것보다 더 효과적이에요.', example_en_4 = 'Consumer demand for soy and palm oil is driving the high deforestation rate.', example_ko_4 = '대두와 팜유에 대한 소비자 수요가 높은 삼림 벌채율을 유발하고 있어요.', example_en_5 = 'Satellite data is used to track the deforestation rate in real time.', example_ko_5 = '위성 데이터를 사용하여 실시간으로 삼림 벌채율을 추적해요.' WHERE id = 'w_environment_B2_17';
UPDATE words SET example_en_2 = 'Habitat loss is the primary driver of species extinction worldwide.', example_ko_2 = '서식지 손실은 전 세계적으로 종 멸종의 주요 원인이에요.', example_en_3 = 'Urban sprawl is causing significant habitat loss for many native species.', example_ko_3 = '도시 팽창이 많은 토착종들에게 상당한 서식지 손실을 일으키고 있어요.', example_en_4 = 'Habitat loss makes it impossible for species to find enough food and shelter.', example_ko_4 = '서식지 손실은 종들이 충분한 먹이와 피신처를 찾는 것을 불가능하게 만들어요.', example_en_5 = 'Addressing habitat loss requires both legal protection and active restoration.', example_ko_5 = '서식지 손실을 해결하려면 법적 보호와 적극적인 복원이 모두 필요해요.' WHERE id = 'w_environment_B2_18';
UPDATE words SET example_en_2 = 'Invasive species can outcompete native animals and plants for resources.', example_ko_2 = '침입종은 자원을 두고 토착 동물과 식물보다 경쟁에서 이길 수 있어요.', example_en_3 = 'The introduction of invasive species has caused ecological disasters in many countries.', example_ko_3 = '침입종 도입이 많은 나라에서 생태적 재앙을 일으켰어요.', example_en_4 = 'Controlling invasive species is extremely costly and rarely completely successful.', example_ko_4 = '침입종을 통제하는 것은 비용이 매우 많이 들고 완전히 성공하는 경우는 드물어요.', example_en_5 = 'Strict biosecurity measures help prevent the spread of invasive species across borders.', example_ko_5 = '엄격한 생물 보안 조치는 국경을 넘는 침입종의 확산을 막는 데 도움이 돼요.' WHERE id = 'w_environment_B2_19';
UPDATE words SET example_en_2 = 'Reaching net zero requires removing as much carbon as we emit.', example_ko_2 = '탄소 중립 달성은 우리가 배출하는 만큼 탄소를 제거해야 해요.', example_en_3 = 'Many corporations have announced net zero targets but face scrutiny over their plans.', example_ko_3 = '많은 기업들이 탄소 중립 목표를 발표했지만 그 계획에 대한 검토를 받고 있어요.', example_en_4 = 'Net zero does not mean stopping all emissions but offsetting what remains.', example_ko_4 = '탄소 중립은 모든 배출을 중단하는 것이 아니라 남은 배출을 상쇄한다는 뜻이에요.', example_en_5 = 'Governments must put in place clear policies to achieve net zero by 2050.', example_ko_5 = '정부들은 2050년까지 탄소 중립을 달성하기 위한 명확한 정책을 마련해야 해요.' WHERE id = 'w_environment_B2_20';
UPDATE words SET example_en_2 = 'Plastic waste in the ocean harms marine animals that mistake it for food.', example_ko_2 = '바다의 플라스틱 폐기물은 먹이로 착각하는 해양 동물들에게 해를 끼쳐요.', example_en_3 = 'Reducing single-use plastic waste is one of the most urgent environmental priorities.', example_ko_3 = '일회용 플라스틱 폐기물을 줄이는 것은 가장 시급한 환경 우선 과제 중 하나예요.', example_en_4 = 'Plastic waste that reaches landfills can take hundreds of years to decompose.', example_ko_4 = '매립지에 도달하는 플라스틱 폐기물은 분해되는 데 수백 년이 걸릴 수 있어요.', example_en_5 = 'Companies are being pressured to redesign products to generate less plastic waste.', example_ko_5 = '기업들은 플라스틱 폐기물을 덜 생성하도록 제품을 재설계하라는 압박을 받고 있어요.' WHERE id = 'w_environment_B2_21';
UPDATE words SET example_en_2 = 'Agroforestry integrates trees into farmland to improve soil and sequester carbon.', example_ko_2 = '혼농임업은 토양을 개선하고 탄소를 격리하기 위해 농지에 나무를 통합해요.', example_en_3 = 'Agroforestry can increase farm productivity while reducing environmental damage.', example_ko_3 = '혼농임업은 환경 피해를 줄이면서 농장 생산성을 높일 수 있어요.', example_en_4 = 'Traditional agroforestry practices have been used for centuries in many cultures.', example_ko_4 = '전통적인 혼농임업 관행은 많은 문화에서 수 세기 동안 사용되어 왔어요.', example_en_5 = 'Expanding agroforestry could help countries meet both food and climate goals.', example_ko_5 = '혼농임업을 확대하면 국가들이 식량과 기후 목표를 동시에 달성하는 데 도움이 될 수 있어요.' WHERE id = 'w_environment_B2_22';
UPDATE words SET example_en_2 = 'Eutrophication occurs when excess nutrients cause algae to grow out of control.', example_ko_2 = '부영양화는 과도한 영양분이 조류를 통제 불가능하게 성장시킬 때 발생해요.', example_en_3 = 'Fertiliser runoff from farms is a major cause of eutrophication in lakes.', example_ko_3 = '농장에서 나오는 비료 유출은 호수 부영양화의 주요 원인이에요.', example_en_4 = 'Eutrophication depletes oxygen in the water and kills fish and other wildlife.', example_ko_4 = '부영양화는 물속의 산소를 고갈시켜 물고기와 다른 야생동물을 죽여요.', example_en_5 = 'Preventing eutrophication requires reducing the amount of nutrients entering waterways.', example_ko_5 = '부영양화를 예방하려면 수로로 유입되는 영양분의 양을 줄여야 해요.' WHERE id = 'w_environment_B2_23';
UPDATE words SET example_en_2 = 'Atmospheric carbon dioxide levels are measured daily at observatories worldwide.', example_ko_2 = '대기 중 이산화탄소 수준은 전 세계 관측소에서 매일 측정돼요.', example_en_3 = 'Atmospheric conditions affect weather, climate, and air quality everywhere.', example_ko_3 = '대기 조건은 모든 곳의 날씨, 기후, 대기 질에 영향을 미쳐요.', example_en_4 = 'Atmospheric pollution from industry crosses national borders and affects other countries.', example_ko_4 = '산업에서 나오는 대기 오염은 국경을 넘어 다른 나라들에 영향을 미쳐요.', example_en_5 = 'Understanding atmospheric dynamics is essential for accurate climate modelling.', example_ko_5 = '대기 역학을 이해하는 것은 정확한 기후 모델링에 필수적이에요.' WHERE id = 'w_environment_B2_24';
UPDATE words SET example_en_2 = 'A renewable portfolio standard requires utilities to source a fixed share from clean energy.', example_ko_2 = '재생 에너지 포트폴리오 기준은 유틸리티 회사들이 청정 에너지에서 일정 비율을 공급하도록 요구해요.', example_en_3 = 'The renewable portfolio helps diversify energy sources and reduce fossil fuel dependence.', example_ko_3 = '재생 에너지 포트폴리오는 에너지 원천을 다양화하고 화석 연료 의존도를 줄이는 데 도움이 돼요.', example_en_4 = 'Each state has set a different renewable portfolio target for its electricity sector.', example_ko_4 = '각 주는 전력 부문에 대해 서로 다른 재생 에너지 포트폴리오 목표를 설정했어요.', example_en_5 = 'Ambitious renewable portfolio goals are driving massive investment in solar and wind.', example_ko_5 = '야심찬 재생 에너지 포트폴리오 목표가 태양광과 풍력에 대한 대규모 투자를 이끌고 있어요.' WHERE id = 'w_environment_B2_25';
UPDATE words SET example_en_2 = 'Permafrost covers about a quarter of the land area in the Northern Hemisphere.', example_ko_2 = '영구 동토층은 북반구 육지 면적의 약 4분의 1을 덮고 있어요.', example_en_3 = 'As permafrost thaws, it releases large amounts of trapped methane and carbon dioxide.', example_ko_3 = '영구 동토층이 녹으면 갇혀 있던 많은 양의 메탄과 이산화탄소가 방출돼요.', example_en_4 = 'Communities in Arctic regions are losing their homes as permafrost melts beneath them.', example_ko_4 = '북극 지역의 지역 사회들이 아래의 영구 동토층이 녹으면서 집을 잃고 있어요.', example_en_5 = 'The thawing of permafrost could accelerate climate change beyond our current projections.', example_ko_5 = '영구 동토층의 해빙이 현재 예측을 넘어 기후 변화를 가속화할 수 있어요.' WHERE id = 'w_environment_B2_26';
UPDATE words SET example_en_2 = 'Dense smog settled over the city, reducing visibility to just a few metres.', example_ko_2 = '짙은 스모그가 도시를 뒤덮어 시계가 불과 몇 미터까지 줄었어요.', example_en_3 = 'Smog is formed when vehicle exhaust and industrial pollution react in sunlight.', example_ko_3 = '스모그는 차량 배기가스와 산업 오염이 햇빛에서 반응할 때 형성돼요.', example_en_4 = 'Breathing smog regularly increases the risk of asthma and other lung diseases.', example_ko_4 = '스모그를 정기적으로 마시면 천식 및 기타 폐 질환의 위험이 높아져요.', example_en_5 = 'Several Asian cities regularly issue smog warnings during winter months.', example_ko_5 = '여러 아시아 도시들이 겨울철에 정기적으로 스모그 경보를 발령해요.' WHERE id = 'w_environment_B2_27';
UPDATE words SET example_en_2 = 'A biome is a large region characterised by its climate, plants, and animals.', example_ko_2 = '생물군계는 기후, 식물, 동물로 특징지어지는 넓은 지역이에요.', example_en_3 = 'The tropical rainforest biome is the most biodiverse on Earth.', example_ko_3 = '열대 우림 생물군계는 지구에서 가장 생물 다양성이 높은 곳이에요.', example_en_4 = 'Climate change is shifting the boundaries of biomes around the world.', example_ko_4 = '기후 변화가 전 세계 생물군계의 경계를 변화시키고 있어요.', example_en_5 = 'Each biome has unique species that have adapted to its specific conditions.', example_ko_5 = '각 생물군계에는 특정 환경에 적응한 고유한 종들이 있어요.' WHERE id = 'w_environment_B2_28';
UPDATE words SET example_en_2 = 'Agricultural runoff containing fertilisers pollutes streams and rivers.', example_ko_2 = '비료가 포함된 농업 유출수가 개울과 강을 오염시켜요.', example_en_3 = 'Stormwater runoff from cities carries oil and chemicals into waterways.', example_ko_3 = '도시에서 나오는 우수 유출수가 오일과 화학물질을 수로로 옮겨요.', example_en_4 = 'Reducing runoff requires better management of land and drainage systems.', example_ko_4 = '유출수를 줄이려면 토지와 배수 시스템을 더 잘 관리해야 해요.', example_en_5 = 'Green roofs and permeable pavements help absorb runoff in urban areas.', example_ko_5 = '옥상 정원과 투수성 포장재는 도시 지역에서 유출수를 흡수하는 데 도움이 돼요.' WHERE id = 'w_environment_B2_29';
UPDATE words SET example_en_2 = 'Biomass energy is produced by burning organic materials such as wood and crop waste.', example_ko_2 = '바이오매스 에너지는 나무와 농작물 폐기물 같은 유기 재료를 태워 생산돼요.', example_en_3 = 'Using biomass as fuel can be carbon-neutral if the plants are regrown.', example_ko_3 = '식물이 다시 자라면 바이오매스를 연료로 사용하는 것이 탄소 중립이 될 수 있어요.', example_en_4 = 'Biomass provides a renewable source of heat and electricity in some countries.', example_ko_4 = '바이오매스는 일부 국가에서 재생 가능한 열과 전기의 원천이에요.', example_en_5 = 'Critics warn that large-scale biomass energy can compete with food production.', example_ko_5 = '비평가들은 대규모 바이오매스 에너지가 식량 생산과 경쟁할 수 있다고 경고해요.' WHERE id = 'w_environment_B2_30';
UPDATE words SET example_en_2 = 'Water scarcity affects billions of people and is worsening with climate change.', example_ko_2 = '물 부족은 수십억 명에게 영향을 미치며 기후 변화로 악화되고 있어요.', example_en_3 = 'Water scarcity can lead to conflict over access to rivers and groundwater.', example_ko_3 = '물 부족은 강과 지하수 접근을 둘러싼 갈등으로 이어질 수 있어요.', example_en_4 = 'Improving irrigation efficiency is critical to reducing agricultural water scarcity.', example_ko_4 = '관개 효율성을 개선하는 것은 농업의 물 부족을 줄이는 데 중요해요.', example_en_5 = 'Investing in water recycling and desalination can help address water scarcity.', example_ko_5 = '물 재활용과 담수화에 투자하면 물 부족 문제를 해결하는 데 도움이 돼요.' WHERE id = 'w_environment_B2_31';
UPDATE words SET example_en_2 = 'Food security requires reliable access to nutritious and affordable food for all.', example_ko_2 = '식량 안보는 모두에게 영양가 있고 저렴한 식품에 대한 안정적인 접근을 필요로 해요.', example_en_3 = 'Climate change threatens food security by disrupting agricultural production.', example_ko_3 = '기후 변화는 농업 생산을 방해하여 식량 안보를 위협해요.', example_en_4 = 'Reducing food waste is an important step towards improving global food security.', example_ko_4 = '음식 낭비를 줄이는 것은 전 세계 식량 안보를 개선하는 중요한 단계예요.', example_en_5 = 'Droughts and floods caused by climate change are the biggest threats to food security.', example_ko_5 = '기후 변화로 인한 가뭄과 홍수는 식량 안보에 대한 가장 큰 위협이에요.' WHERE id = 'w_environment_B2_32';
UPDATE words SET example_en_2 = 'Microplastics have been found in drinking water, seafood, and even human blood.', example_ko_2 = '미세플라스틱이 음료수, 해산물, 심지어 인간의 혈액에서도 발견되었어요.', example_en_3 = 'When plastic breaks down in the environment, it becomes tiny microplastics.', example_ko_3 = '플라스틱이 환경에서 분해되면 작은 미세플라스틱이 돼요.', example_en_4 = 'Microplastics have been detected in the most remote corners of the planet.', example_ko_4 = '미세플라스틱이 지구의 가장 외진 곳에서도 발견되었어요.', example_en_5 = 'Scientists are still studying the long-term health effects of microplastics on humans.', example_ko_5 = '과학자들은 미세플라스틱이 인간에게 미치는 장기적인 건강 영향을 아직 연구 중이에요.' WHERE id = 'w_environment_B2_33';
UPDATE words SET example_en_2 = 'Rewilding restores natural processes by reintroducing species that have disappeared.', example_ko_2 = '야생화 복원은 사라진 종들을 재도입하여 자연 과정을 회복시켜요.', example_en_3 = 'Rewilding large areas of land can help reverse biodiversity loss.', example_ko_3 = '넓은 땅을 야생화 복원하면 생물 다양성 손실을 역전시키는 데 도움이 돼요.', example_en_4 = 'The reintroduction of wolves to Yellowstone is a famous example of rewilding.', example_ko_4 = '옐로스톤에 늑대를 재도입한 것은 야생화 복원의 유명한 사례예요.', example_en_5 = 'Rewilding projects can also benefit local communities through eco-tourism.', example_ko_5 = '야생화 복원 프로젝트는 생태 관광을 통해 지역 사회에도 이익을 줄 수 있어요.' WHERE id = 'w_environment_B2_34';
UPDATE words SET example_en_2 = 'Emission trading allows companies to buy and sell the right to pollute.', example_ko_2 = '배출권 거래는 기업들이 오염 권리를 사고팔 수 있게 해요.', example_en_3 = 'Emission trading schemes create a financial incentive to reduce greenhouse gases.', example_ko_3 = '배출권 거래 제도는 온실가스를 줄이기 위한 재정적 인센티브를 만들어요.', example_en_4 = 'The EU Emissions Trading System is the world''s largest carbon market.', example_ko_4 = 'EU 배출권 거래 제도는 세계 최대의 탄소 시장이에요.', example_en_5 = 'Critics argue that emission trading can allow wealthy companies to keep polluting.', example_ko_5 = '비평가들은 배출권 거래가 부유한 기업들이 계속 오염시킬 수 있게 한다고 주장해요.' WHERE id = 'w_environment_B2_35';

-- C1 words

UPDATE words SET example_en_2 = 'The report concluded that anthropogenic warming is the dominant cause of recent temperature increases.', example_ko_2 = '그 보고서는 인위적 온난화가 최근 기온 상승의 주요 원인이라고 결론지었어요.', example_en_3 = 'Anthropogenic land use changes have fundamentally altered global carbon and water cycles.', example_ko_3 = '인위적 토지 이용 변화가 전 세계 탄소와 물의 순환을 근본적으로 변화시켰어요.', example_en_4 = 'Distinguishing anthropogenic climate signals from natural variability requires sophisticated analysis.', example_ko_4 = '인위적 기후 신호를 자연 변동성과 구별하려면 정교한 분석이 필요해요.', example_en_5 = 'Anthropogenic pressures on biodiversity are now comparable in scale to past mass extinction events.', example_ko_5 = '생물 다양성에 대한 인위적 압박은 이제 과거 대량 멸종 사건과 비슷한 규모예요.' WHERE id = 'w_environment_C1_01';
UPDATE words SET example_en_2 = 'Biogeochemical cycles describe how elements move through living and non-living systems.', example_ko_2 = '생지화학적 순환은 원소들이 살아있는 시스템과 비생물 시스템을 통해 어떻게 이동하는지를 설명해요.', example_en_3 = 'Human activity is disrupting biogeochemical cycles at an unprecedented rate.', example_ko_3 = '인간 활동이 전례 없는 속도로 생지화학적 순환을 교란시키고 있어요.', example_en_4 = 'The nitrogen biogeochemical cycle has been severely altered by synthetic fertiliser use.', example_ko_4 = '질소 생지화학적 순환은 합성 비료 사용으로 심각하게 변화했어요.', example_en_5 = 'Understanding biogeochemical feedbacks is critical for projecting future climate trajectories.', example_ko_5 = '생지화학적 피드백을 이해하는 것은 미래 기후 궤적을 예측하는 데 중요해요.' WHERE id = 'w_environment_C1_02';
UPDATE words SET example_en_2 = 'Paleoclimatology uses ice cores and sediment records to reconstruct past climates.', example_ko_2 = '고기후학은 빙하 코어와 퇴적물 기록을 사용하여 과거 기후를 재구성해요.', example_en_3 = 'Paleoclimatology shows that today''s rate of warming is exceptional in Earth''s history.', example_ko_3 = '고기후학은 오늘날의 온난화 속도가 지구 역사에서 예외적임을 보여 줘요.', example_en_4 = 'The field of paleoclimatology helps scientists understand the sensitivity of climate to CO2.', example_ko_4 = '고기후학 분야는 과학자들이 이산화탄소에 대한 기후 민감성을 이해하는 데 도움이 돼요.', example_en_5 = 'Paleoclimatology research increasingly corroborates the projections of modern climate models.', example_ko_5 = '고기후학 연구는 현대 기후 모델의 예측을 점점 더 뒷받침하고 있어요.' WHERE id = 'w_environment_C1_03';
UPDATE words SET example_en_2 = 'Decarbonization of heavy industry remains one of the most technically challenging aspects of climate action.', example_ko_2 = '중공업의 탈탄소화는 기후 행동의 가장 기술적으로 어려운 측면 중 하나로 남아 있어요.', example_en_3 = 'Decarbonization requires transforming how we produce energy, food, and manufactured goods.', example_ko_3 = '탈탄소화는 에너지, 식품, 제조 상품을 생산하는 방식을 변환해야 해요.', example_en_4 = 'Faster decarbonization of electricity grids creates opportunities for electrifying transport and heating.', example_ko_4 = '전력망의 빠른 탈탄소화는 교통과 난방의 전기화 기회를 만들어요.', example_en_5 = 'Policy instruments such as carbon pricing accelerate decarbonization across multiple sectors.', example_ko_5 = '탄소 가격제와 같은 정책 수단이 여러 부문에 걸쳐 탈탄소화를 가속화해요.' WHERE id = 'w_environment_C1_04';
UPDATE words SET example_en_2 = 'Geoengineering proposals include injecting aerosols into the stratosphere to reflect sunlight.', example_ko_2 = '지구공학 제안에는 햇빛을 반사하기 위해 성층권에 에어로졸을 주입하는 것이 포함돼요.', example_en_3 = 'Critics warn that geoengineering could have severe unintended consequences for ecosystems.', example_ko_3 = '비평가들은 지구공학이 생태계에 심각한 의도치 않은 결과를 초래할 수 있다고 경고해요.', example_en_4 = 'The governance of geoengineering research is a major ethical and geopolitical challenge.', example_ko_4 = '지구공학 연구의 거버넌스는 주요한 윤리적, 지정학적 도전이에요.', example_en_5 = 'Most climate scientists argue that geoengineering must not distract from deep emissions cuts.', example_ko_5 = '대부분의 기후 과학자들은 지구공학이 근본적인 배출 감축에서 주의를 분산시켜서는 안 된다고 주장해요.' WHERE id = 'w_environment_C1_05';
UPDATE words SET example_en_2 = 'The biosphere includes all living organisms and their interactions with the environment.', example_ko_2 = '생물권에는 모든 생물과 환경과의 상호작용이 포함돼요.', example_en_3 = 'Human pressures on the biosphere are now so intense that scientists speak of a biosphere crisis.', example_ko_3 = '생물권에 대한 인간의 압박이 이제 너무 심각하여 과학자들은 생물권 위기를 이야기해요.', example_en_4 = 'The health of the biosphere is intimately connected to human health and wellbeing.', example_ko_4 = '생물권의 건강은 인간의 건강과 복지와 긴밀하게 연결되어 있어요.', example_en_5 = 'Climate change is altering fundamental processes within the biosphere at an alarming speed.', example_ko_5 = '기후 변화가 생물권 내의 근본적인 과정들을 놀라운 속도로 변화시키고 있어요.' WHERE id = 'w_environment_C1_06';
UPDATE words SET example_en_2 = 'Ecological resilience refers to an ecosystem''s ability to recover after disturbance.', example_ko_2 = '생태적 회복력은 교란 이후 생태계가 회복하는 능력을 말해요.', example_en_3 = 'Biodiversity is a key driver of ecological resilience in natural systems.', example_ko_3 = '생물 다양성은 자연 시스템에서 생태적 회복력의 핵심 동력이에요.', example_en_4 = 'Loss of ecological resilience makes ecosystems more vulnerable to future shocks.', example_ko_4 = '생태적 회복력 손실은 생태계를 미래 충격에 더 취약하게 만들어요.', example_en_5 = 'Restoring degraded habitats can rebuild ecological resilience over time.', example_ko_5 = '훼손된 서식지를 복원하면 시간이 지남에 따라 생태적 회복력을 재건할 수 있어요.' WHERE id = 'w_environment_C1_07';
UPDATE words SET example_en_2 = 'The reintroduction of wolves triggered a trophic cascade that transformed the entire ecosystem.', example_ko_2 = '늑대 재도입이 전체 생태계를 변화시키는 영양단계 연쇄를 촉발했어요.', example_en_3 = 'A trophic cascade occurs when changes at one level of a food web ripple through others.', example_ko_3 = '영양단계 연쇄는 먹이 그물의 한 수준에서의 변화가 다른 수준으로 파급될 때 발생해요.', example_en_4 = 'Understanding trophic cascades is essential for predicting the effects of species loss.', example_ko_4 = '영양단계 연쇄를 이해하는 것은 종 손실의 영향을 예측하는 데 필수적이에요.', example_en_5 = 'Trophic cascades demonstrate why protecting apex predators matters for whole ecosystems.', example_ko_5 = '영양단계 연쇄는 최상위 포식자를 보호하는 것이 전체 생태계에 왜 중요한지를 보여 줘요.' WHERE id = 'w_environment_C1_08';
UPDATE words SET example_en_2 = 'Protecting existing carbon sinks such as forests and peatlands is urgently needed.', example_ko_2 = '숲과 이탄지 같은 기존 탄소 흡수원을 보호하는 것이 시급하게 필요해요.', example_en_3 = 'If carbon sinks are degraded, the climate system loses a key buffer against warming.', example_ko_3 = '탄소 흡수원이 훼손되면 기후 시스템은 온난화에 대한 핵심 완충재를 잃어요.', example_en_4 = 'Oceans are major carbon sinks but are becoming less effective as they warm and acidify.', example_ko_4 = '바다는 주요 탄소 흡수원이지만 온도가 오르고 산성화되면서 덜 효과적이 되고 있어요.', example_en_5 = 'Enhancing natural carbon sinks through restoration is a cost-effective climate strategy.', example_ko_5 = '복원을 통해 자연 탄소 흡수원을 강화하는 것은 비용 효율적인 기후 전략이에요.' WHERE id = 'w_environment_C1_09';
UPDATE words SET example_en_2 = 'Sea otters are a keystone species because they control sea urchin populations.', example_ko_2 = '해달은 성게 개체 수를 조절하기 때문에 핵심 종이에요.', example_en_3 = 'Removing a keystone species can trigger the collapse of an entire ecosystem.', example_ko_3 = '핵심 종을 제거하면 전체 생태계가 붕괴될 수 있어요.', example_en_4 = 'Conservationists prioritise protecting keystone species due to their outsized ecological influence.', example_ko_4 = '자연보호론자들은 핵심 종의 엄청난 생태적 영향력 때문에 그들을 보호하는 것을 우선시해요.', example_en_5 = 'Identifying keystone species in an ecosystem helps guide conservation priorities effectively.', example_ko_5 = '생태계에서 핵심 종을 식별하면 보전 우선순위를 효과적으로 안내하는 데 도움이 돼요.' WHERE id = 'w_environment_C1_10';
UPDATE words SET example_en_2 = 'The Earth''s albedo decreases as white ice is replaced by darker ocean or land.', example_ko_2 = '흰 얼음이 더 어두운 바다나 육지로 대체되면서 지구의 알베도가 감소해요.', example_en_3 = 'A lower albedo means the Earth absorbs more solar radiation and warms faster.', example_ko_3 = '알베도가 낮을수록 지구가 더 많은 태양 복사에너지를 흡수하고 더 빨리 따뜻해져요.', example_en_4 = 'Scientists study albedo changes in the Arctic as a critical climate feedback mechanism.', example_ko_4 = '과학자들은 중요한 기후 피드백 메커니즘으로서 북극의 알베도 변화를 연구해요.', example_en_5 = 'Geoengineering proposals involving aerosols aim to artificially increase the Earth''s albedo.', example_ko_5 = '에어로졸을 사용하는 지구공학 제안은 지구의 알베도를 인위적으로 높이는 것을 목표로 해요.' WHERE id = 'w_environment_C1_11';
UPDATE words SET example_en_2 = 'Phenology tracks when plants flower and birds migrate in relation to seasonal changes.', example_ko_2 = '생물계절학은 계절 변화와 관련하여 식물이 언제 꽃을 피우고 새들이 언제 이동하는지 추적해요.', example_en_3 = 'Climate change is disrupting phenology, causing species to act out of sync with each other.', example_ko_3 = '기후 변화가 생물계절학을 교란하여 종들이 서로 맞지 않게 행동하도록 만들고 있어요.', example_en_4 = 'Long-term phenology records reveal how species are responding to a warmer climate.', example_ko_4 = '장기적인 생물계절학 기록은 종들이 더 따뜻한 기후에 어떻게 반응하는지를 보여 줘요.', example_en_5 = 'Phenology data is used by farmers to adjust planting schedules as seasons shift.', example_ko_5 = '생물계절학 데이터는 농부들이 계절이 바뀜에 따라 파종 일정을 조정하는 데 사용돼요.' WHERE id = 'w_environment_C1_12';
UPDATE words SET example_en_2 = 'Soil remediation techniques can restore contaminated land to productive use.', example_ko_2 = '토양 복원 기법은 오염된 토지를 생산적인 용도로 회복시킬 수 있어요.', example_en_3 = 'Remediation of polluted waterways requires the removal or neutralisation of contaminants.', example_ko_3 = '오염된 수로의 복원에는 오염 물질의 제거 또는 중화가 필요해요.', example_en_4 = 'Environmental remediation projects can be extremely costly and take many years.', example_ko_4 = '환경 복원 프로젝트는 비용이 매우 많이 들고 수년이 걸릴 수 있어요.', example_en_5 = 'Bioremediation uses living organisms to break down and remove environmental pollutants.', example_ko_5 = '생물복원은 살아있는 유기체를 사용하여 환경 오염 물질을 분해하고 제거해요.' WHERE id = 'w_environment_C1_13';
UPDATE words SET example_en_2 = 'Ecosystem services include clean water, pollination, climate regulation, and soil formation.', example_ko_2 = '생태계 서비스에는 깨끗한 물, 수분 매개, 기후 조절, 토양 형성이 포함돼요.', example_en_3 = 'Valuing ecosystem services economically helps make the case for conservation investment.', example_ko_3 = '생태계 서비스를 경제적으로 평가하면 보전 투자의 필요성을 주장하는 데 도움이 돼요.', example_en_4 = 'The degradation of ecosystem services threatens agriculture, human health, and livelihoods.', example_ko_4 = '생태계 서비스의 훼손은 농업, 인간 건강, 생계를 위협해요.', example_en_5 = 'Healthy forests provide enormous ecosystem services that have no easy economic substitute.', example_ko_5 = '건강한 숲은 쉽게 경제적으로 대체할 수 없는 엄청난 생태계 서비스를 제공해요.' WHERE id = 'w_environment_C1_14';
UPDATE words SET example_en_2 = 'Stratospheric ozone absorbs the ultraviolet radiation that would otherwise harm life on Earth.', example_ko_2 = '성층권 오존은 그렇지 않으면 지구 생명체에 해를 끼칠 자외선을 흡수해요.', example_en_3 = 'Stratospheric aerosol injection is a controversial form of solar geoengineering.', example_ko_3 = '성층권 에어로졸 주입은 논란이 많은 형태의 태양 지구공학이에요.', example_en_4 = 'Stratospheric wind patterns affect how pollutants and aerosols are distributed globally.', example_ko_4 = '성층권 바람 패턴은 오염 물질과 에어로졸이 전 세계적으로 어떻게 분포하는지에 영향을 미쳐요.', example_en_5 = 'Recovery of stratospheric ozone is one of the few environmental success stories of recent decades.', example_ko_5 = '성층권 오존 회복은 최근 수십 년간 몇 안 되는 환경 성공 사례 중 하나예요.' WHERE id = 'w_environment_C1_15';
UPDATE words SET example_en_2 = 'The nutrient cycle ensures that essential elements are recycled through ecosystems.', example_ko_2 = '영양 순환은 필수 원소들이 생태계를 통해 재활용되도록 보장해요.', example_en_3 = 'Human activity has significantly disrupted the nitrogen and phosphorus nutrient cycles.', example_ko_3 = '인간 활동이 질소와 인의 영양 순환을 크게 교란시켰어요.', example_en_4 = 'Decomposers play a vital role in returning nutrients to the nutrient cycle.', example_ko_4 = '분해자들은 영양분을 영양 순환으로 되돌리는 데 중요한 역할을 해요.', example_en_5 = 'Fertiliser application disrupts the natural nutrient cycle in soils and waterways.', example_ko_5 = '비료 사용은 토양과 수로의 자연 영양 순환을 교란해요.' WHERE id = 'w_environment_C1_16';
UPDATE words SET example_en_2 = 'Phytoplankton form the base of the marine food web and produce much of the world''s oxygen.', example_ko_2 = '식물성 플랑크톤은 해양 먹이 그물의 기초를 형성하고 세계 산소의 많은 부분을 생산해요.', example_en_3 = 'Changes in ocean temperature are affecting the distribution of phytoplankton worldwide.', example_ko_3 = '해양 온도 변화가 전 세계 식물성 플랑크톤의 분포에 영향을 미치고 있어요.', example_en_4 = 'Phytoplankton absorb large amounts of CO2 from the atmosphere through photosynthesis.', example_ko_4 = '식물성 플랑크톤은 광합성을 통해 대기에서 많은 양의 이산화탄소를 흡수해요.', example_en_5 = 'Ocean acidification caused by rising CO2 levels threatens the health of phytoplankton.', example_ko_5 = '이산화탄소 수준 상승으로 인한 해양 산성화가 식물성 플랑크톤의 건강을 위협해요.' WHERE id = 'w_environment_C1_17';
UPDATE words SET example_en_2 = 'Some legal scholars argue that ecocide should be recognised as an international crime.', example_ko_2 = '일부 법학자들은 생태계 파괴가 국제 범죄로 인정되어야 한다고 주장해요.', example_en_3 = 'Ecocide encompasses the mass destruction of ecosystems through human activity.', example_ko_3 = '생태계 파괴는 인간 활동을 통한 생태계의 대규모 파괴를 포함해요.', example_en_4 = 'Campaigners are pushing for ecocide to be added to the Rome Statute of the ICC.', example_ko_4 = '활동가들은 생태계 파괴를 국제형사재판소의 로마 규정에 추가하도록 추진하고 있어요.', example_en_5 = 'The concept of ecocide challenges the idea that nature exists purely for human use.', example_ko_5 = '생태계 파괴의 개념은 자연이 순전히 인간의 사용을 위해 존재한다는 생각에 도전해요.' WHERE id = 'w_environment_C1_18';
UPDATE words SET example_en_2 = 'Biochar is produced by heating organic material without oxygen and burying it in soil.', example_ko_2 = '바이오차는 산소 없이 유기 재료를 가열하고 토양에 묻어 생산해요.', example_en_3 = 'Adding biochar to agricultural soil can improve fertility and sequester carbon for centuries.', example_ko_3 = '농업 토양에 바이오차를 추가하면 수 세기 동안 비옥도를 개선하고 탄소를 격리할 수 있어요.', example_en_4 = 'Biochar is considered a promising negative emissions technology because it stores carbon stably.', example_ko_4 = '바이오차는 탄소를 안정적으로 저장하기 때문에 유망한 탄소 흡수 기술로 여겨져요.', example_en_5 = 'Research into biochar is expanding as interest in carbon removal strategies grows.', example_ko_5 = '탄소 제거 전략에 대한 관심이 높아짐에 따라 바이오차 연구가 확대되고 있어요.' WHERE id = 'w_environment_C1_19';
UPDATE words SET example_en_2 = 'Lithostratigraphy uses layers of rock to establish the chronological sequence of geological events.', example_ko_2 = '암층서학은 암석층을 사용하여 지질학적 사건의 연대순 순서를 확립해요.', example_en_3 = 'Lithostratigraphy provides evidence of past environmental changes preserved in rock records.', example_ko_3 = '암층서학은 암석 기록에 보존된 과거 환경 변화의 증거를 제공해요.', example_en_4 = 'Advances in lithostratigraphy have helped refine our understanding of Earth''s deep history.', example_ko_4 = '암층서학의 발전이 지구의 깊은 역사에 대한 이해를 정교화하는 데 도움이 되었어요.', example_en_5 = 'Lithostratigraphy is combined with other dating methods to create accurate geological timelines.', example_ko_5 = '암층서학은 정확한 지질학적 연대표를 만들기 위해 다른 연대 측정 방법들과 결합돼요.' WHERE id = 'w_environment_C1_20';
UPDATE words SET example_en_2 = 'Endocrine disruptors are chemicals that interfere with the body''s hormonal systems.', example_ko_2 = '내분비 교란물질은 신체의 호르몬 시스템을 방해하는 화학물질이에요.', example_en_3 = 'Some plastics release endocrine disruptors when they break down in the environment.', example_ko_3 = '일부 플라스틱은 환경에서 분해될 때 내분비 교란물질을 방출해요.', example_en_4 = 'Exposure to endocrine disruptors has been linked to reproductive and developmental problems.', example_ko_4 = '내분비 교란물질 노출은 생식 및 발달 문제와 관련이 있어요.', example_en_5 = 'Regulators are working to restrict the use of known endocrine disruptors in consumer products.', example_ko_5 = '규제 당국은 소비자 제품에서 알려진 내분비 교란물질의 사용을 제한하기 위해 노력하고 있어요.' WHERE id = 'w_environment_C1_21';
UPDATE words SET example_en_2 = 'Transboundary pollution from one country affects the air and water quality in neighbouring states.', example_ko_2 = '한 나라에서 발생한 초국경 오염이 이웃 국가들의 대기와 수질에 영향을 미쳐요.', example_en_3 = 'Transboundary pollution requires diplomatic solutions and multilateral environmental agreements.', example_ko_3 = '초국경 오염은 외교적 해결책과 다자간 환경 협약이 필요해요.', example_en_4 = 'International law on transboundary pollution has strengthened significantly in recent decades.', example_ko_4 = '초국경 오염에 관한 국제법이 최근 수십 년간 크게 강화되었어요.', example_en_5 = 'Transboundary pollution from industrial zones creates tension between neighbouring countries.', example_ko_5 = '산업 지대에서 발생하는 초국경 오염이 이웃 국가들 사이에 긴장을 만들어요.' WHERE id = 'w_environment_C1_22';
UPDATE words SET example_en_2 = 'A cradle-to-grave assessment measures environmental impacts across the full product life cycle.', example_ko_2 = '요람에서 무덤까지 평가는 전체 제품 수명 주기에 걸친 환경적 영향을 측정해요.', example_en_3 = 'Cradle-to-grave thinking encourages designers to consider disposal from the very beginning.', example_ko_3 = '요람에서 무덤까지 사고는 설계자들이 처음부터 폐기를 고려하도록 장려해요.', example_en_4 = 'Companies use cradle-to-grave analysis to identify where their products cause the most harm.', example_ko_4 = '기업들은 요람에서 무덤까지 분석을 사용하여 제품이 가장 큰 피해를 주는 곳을 파악해요.', example_en_5 = 'A cradle-to-cradle approach goes further by designing products for complete reuse or recycling.', example_ko_5 = '요람에서 요람까지 접근법은 완전한 재사용이나 재활용을 위해 제품을 설계함으로써 더 나아가요.' WHERE id = 'w_environment_C1_23';
UPDATE words SET example_en_2 = 'The cryosphere includes all forms of frozen water on Earth, from glaciers to sea ice.', example_ko_2 = '빙권에는 빙하부터 해빙까지 지구상의 모든 형태의 얼어있는 물이 포함돼요.', example_en_3 = 'Rapid changes in the cryosphere are one of the clearest signs of global warming.', example_ko_3 = '빙권의 급격한 변화는 지구 온난화의 가장 명확한 징후 중 하나예요.', example_en_4 = 'Monitoring the cryosphere helps scientists predict future sea level rise.', example_ko_4 = '빙권을 모니터링하면 과학자들이 미래 해수면 상승을 예측하는 데 도움이 돼요.', example_en_5 = 'Loss of cryosphere components disrupts freshwater availability for millions of people.', example_ko_5 = '빙권 구성 요소의 손실은 수백만 명의 담수 이용 가능성을 교란해요.' WHERE id = 'w_environment_C1_24';
UPDATE words SET example_en_2 = 'The urban heat island effect makes cities several degrees hotter than surrounding rural areas.', example_ko_2 = '도시 열섬 효과는 도시를 주변 농촌 지역보다 몇 도 더 뜨겁게 만들어요.', example_en_3 = 'Green roofs and urban trees can help reduce the urban heat island effect.', example_ko_3 = '옥상 정원과 도시 나무들은 도시 열섬 효과를 줄이는 데 도움이 돼요.', example_en_4 = 'The urban heat island effect worsens heat stress during heatwaves, especially for vulnerable people.', example_ko_4 = '도시 열섬 효과는 폭염 동안, 특히 취약한 사람들에게 열 스트레스를 악화시켜요.', example_en_5 = 'Replacing dark asphalt with light-coloured surfaces can reduce the urban heat island effect.', example_ko_5 = '어두운 아스팔트를 밝은 색 표면으로 교체하면 도시 열섬 효과를 줄일 수 있어요.' WHERE id = 'w_environment_C1_25';
UPDATE words SET example_en_2 = 'The precautionary principle argues that we should act on environmental risks even without full scientific proof.', example_ko_2 = '사전예방 원칙은 완전한 과학적 증거가 없어도 환경 위험에 대해 행동해야 한다고 주장해요.', example_en_3 = 'Applying the precautionary principle justifies banning substances before their harm is fully proven.', example_ko_3 = '사전예방 원칙을 적용하면 해로움이 완전히 증명되기 전에 물질을 금지하는 것이 정당화돼요.', example_en_4 = 'Critics argue that an excessive reliance on the precautionary principle can stifle innovation.', example_ko_4 = '비평가들은 사전예방 원칙에 과도하게 의존하면 혁신을 저해할 수 있다고 주장해요.', example_en_5 = 'The precautionary principle is embedded in many international environmental agreements.', example_ko_5 = '사전예방 원칙은 많은 국제 환경 협약에 내재되어 있어요.' WHERE id = 'w_environment_C1_26';
UPDATE words SET example_en_2 = 'Phytoremediation uses plants to absorb and neutralise toxins in contaminated soil or water.', example_ko_2 = '식물복원은 식물을 사용하여 오염된 토양이나 물에서 독소를 흡수하고 중화해요.', example_en_3 = 'Certain plants are especially effective in phytoremediation of heavy metal contamination.', example_ko_3 = '특정 식물들은 중금속 오염의 식물복원에 특히 효과적이에요.', example_en_4 = 'Phytoremediation is a low-cost and environmentally friendly approach to pollution control.', example_ko_4 = '식물복원은 오염 통제를 위한 저비용의 환경 친화적 접근법이에요.', example_en_5 = 'Research into phytoremediation is expanding as demand for sustainable land restoration grows.', example_ko_5 = '지속 가능한 토지 복원에 대한 수요가 증가함에 따라 식물복원 연구가 확대되고 있어요.' WHERE id = 'w_environment_C1_27';
UPDATE words SET example_en_2 = 'Bioremediation harnesses microorganisms to degrade pollutants in contaminated environments.', example_ko_2 = '생물복원은 오염된 환경에서 오염 물질을 분해하기 위해 미생물을 활용해요.', example_en_3 = 'Oil spill bioremediation involves introducing bacteria that break down hydrocarbons.', example_ko_3 = '기름 유출 생물복원은 탄화수소를 분해하는 박테리아를 도입하는 것을 포함해요.', example_en_4 = 'Bioremediation is generally more sustainable than excavating and disposing of contaminated soil.', example_ko_4 = '생물복원은 일반적으로 오염된 토양을 굴착하고 처리하는 것보다 더 지속 가능해요.', example_en_5 = 'Advances in synthetic biology are expanding the potential applications of bioremediation.', example_ko_5 = '합성 생물학의 발전이 생물복원의 잠재적 응용 가능성을 확대하고 있어요.' WHERE id = 'w_environment_C1_28';
UPDATE words SET example_en_2 = 'An ecological footprint measures how much of the Earth''s resources a population consumes.', example_ko_2 = '생태 발자국은 한 집단이 지구의 자원을 얼마나 소비하는지를 측정해요.', example_en_3 = 'Reducing your ecological footprint can involve changing diet, travel habits, and energy use.', example_ko_3 = '생태 발자국을 줄이는 것은 식단, 여행 습관, 에너지 사용 변화를 포함할 수 있어요.', example_en_4 = 'The ecological footprint of high-income countries vastly exceeds their fair share of global resources.', example_ko_4 = '고소득 국가들의 생태 발자국은 전 세계 자원의 공정한 몫을 훨씬 초과해요.', example_en_5 = 'Tracking ecological footprint data helps governments design more sustainable consumption policies.', example_ko_5 = '생태 발자국 데이터를 추적하면 정부가 더 지속 가능한 소비 정책을 설계하는 데 도움이 돼요.' WHERE id = 'w_environment_C1_29';
UPDATE words SET example_en_2 = 'Planetary health recognises that human health depends on the health of natural systems.', example_ko_2 = '지구 건강은 인간의 건강이 자연 시스템의 건강에 달려 있음을 인식해요.', example_en_3 = 'The concept of planetary health is reshaping how medicine and public policy are approached.', example_ko_3 = '지구 건강의 개념이 의학과 공공 정책이 접근되는 방식을 재편하고 있어요.', example_en_4 = 'Investing in planetary health means protecting ecosystems as a foundation for human prosperity.', example_ko_4 = '지구 건강에 투자하는 것은 인간 번영의 기반으로서 생태계를 보호하는 것을 의미해요.', example_en_5 = 'Planetary health frameworks integrate ecology, medicine, and social justice into policy.', example_ko_5 = '지구 건강 프레임워크는 생태학, 의학, 사회적 정의를 정책에 통합해요.' WHERE id = 'w_environment_C1_30';
UPDATE words SET example_en_2 = 'An atmospheric river can carry as much water vapour as the Amazon river carries water.', example_ko_2 = '대기 강은 아마존 강이 운반하는 물만큼 많은 수증기를 운반할 수 있어요.', example_en_3 = 'Atmospheric rivers are responsible for most of the rainfall in coastal California.', example_ko_3 = '대기 강은 캘리포니아 해안 지역 강수량의 대부분을 담당해요.', example_en_4 = 'As the climate warms, atmospheric rivers are expected to intensify and cause more flooding.', example_ko_4 = '기후가 따뜻해짐에 따라 대기 강이 강해지고 더 많은 홍수를 일으킬 것으로 예상돼요.', example_en_5 = 'Scientists are improving atmospheric river forecasting to give earlier flood warnings.', example_ko_5 = '과학자들은 더 일찍 홍수 경보를 주기 위해 대기 강 예보를 개선하고 있어요.' WHERE id = 'w_environment_C1_31';
UPDATE words SET example_en_2 = 'A carbon budget defines the maximum amount of CO2 that can be emitted to stay within a temperature target.', example_ko_2 = '탄소 예산은 온도 목표 내에 머물기 위해 배출할 수 있는 최대 이산화탄소 양을 정의해요.', example_en_3 = 'At current emission rates, the global carbon budget for 1.5°C will be exhausted within years.', example_ko_3 = '현재 배출 속도에서 1.5도에 대한 전 세계 탄소 예산은 몇 년 안에 소진될 거예요.', example_en_4 = 'Allocating a carbon budget fairly between countries is a major geopolitical challenge.', example_ko_4 = '국가 간 탄소 예산을 공정하게 배분하는 것은 주요한 지정학적 도전이에요.', example_en_5 = 'The concept of a carbon budget helps translate abstract climate goals into concrete targets.', example_ko_5 = '탄소 예산의 개념은 추상적인 기후 목표를 구체적인 목표로 변환하는 데 도움이 돼요.' WHERE id = 'w_environment_C1_32';
UPDATE words SET example_en_2 = 'Deep ecology argues that nature has intrinsic value beyond its usefulness to humans.', example_ko_2 = '심층 생태학은 자연이 인간에 대한 유용성을 넘어 본질적인 가치를 지닌다고 주장해요.', example_en_3 = 'Deep ecology challenges industrial societies to rethink their relationship with the natural world.', example_ko_3 = '심층 생태학은 산업 사회에 자연 세계와의 관계를 재고하도록 도전해요.', example_en_4 = 'Proponents of deep ecology advocate for legal rights for ecosystems and species.', example_ko_4 = '심층 생태학 지지자들은 생태계와 종에 대한 법적 권리를 옹호해요.', example_en_5 = 'Deep ecology has influenced environmental philosophy, activism, and policy debates worldwide.', example_ko_5 = '심층 생태학은 전 세계적으로 환경 철학, 행동주의, 정책 토론에 영향을 미쳤어요.' WHERE id = 'w_environment_C1_33';
UPDATE words SET example_en_2 = 'Ocean acidification makes it harder for corals and shellfish to build their calcium carbonate structures.', example_ko_2 = '해양 산성화는 산호와 조개류가 탄산칼슘 구조를 만들기 어렵게 해요.', example_en_3 = 'The rate of ocean acidification is faster now than at any point in the past 300 million years.', example_ko_3 = '현재 해양 산성화 속도는 지난 3억 년 중 어느 때보다 빠릅니다.', example_en_4 = 'Ocean acidification threatens not only marine biodiversity but also global food security.', example_ko_4 = '해양 산성화는 해양 생물 다양성뿐만 아니라 전 세계 식량 안보도 위협해요.', example_en_5 = 'Reducing CO2 emissions is the only way to halt ongoing ocean acidification.', example_ko_5 = '이산화탄소 배출을 줄이는 것이 진행 중인 해양 산성화를 멈추는 유일한 방법이에요.' WHERE id = 'w_environment_C1_34';
UPDATE words SET example_en_2 = 'Solar radiation management aims to reduce warming by reflecting more sunlight back into space.', example_ko_2 = '태양 복사 관리는 더 많은 햇빛을 우주로 반사하여 온난화를 줄이는 것을 목표로 해요.', example_en_3 = 'Solar radiation management does not address the root causes of climate change or ocean acidification.', example_ko_3 = '태양 복사 관리는 기후 변화나 해양 산성화의 근본 원인을 해결하지 못해요.', example_en_4 = 'Governance frameworks for solar radiation management research are still in early development.', example_ko_4 = '태양 복사 관리 연구를 위한 거버넌스 프레임워크는 아직 초기 개발 단계에 있어요.', example_en_5 = 'Unilateral deployment of solar radiation management could have serious consequences for other nations.', example_ko_5 = '태양 복사 관리의 일방적 배포는 다른 나라들에 심각한 결과를 초래할 수 있어요.' WHERE id = 'w_environment_C1_35';

-- C2 words

UPDATE words SET example_en_2 = 'Radiative forcing quantifies the energy imbalance caused by greenhouse gas accumulation.', example_ko_2 = '복사 강제력은 온실가스 축적으로 인한 에너지 불균형을 정량화해요.', example_en_3 = 'A positive radiative forcing warms the climate while a negative value has a cooling effect.', example_ko_3 = '양의 복사 강제력은 기후를 따뜻하게 하고 음의 값은 냉각 효과를 가져요.', example_en_4 = 'Aerosols can produce negative radiative forcing by scattering incoming solar radiation.', example_ko_4 = '에어로졸은 들어오는 태양 복사를 산란시켜 음의 복사 강제력을 만들 수 있어요.', example_en_5 = 'Climate models must accurately represent radiative forcing to project future temperatures.', example_ko_5 = '기후 모델은 미래 기온을 예측하기 위해 복사 강제력을 정확하게 나타내야 해요.' WHERE id = 'w_environment_C2_01';
UPDATE words SET example_en_2 = 'Thermohaline circulation transports heat and nutrients around the global ocean.', example_ko_2 = '열염 순환은 전 세계 바다에 열과 영양분을 운반해요.', example_en_3 = 'A slowdown of thermohaline circulation could dramatically alter European climate.', example_ko_3 = '열염 순환의 둔화는 유럽 기후를 극적으로 바꿀 수 있어요.', example_en_4 = 'Freshwater from melting ice sheets is weakening thermohaline circulation patterns.', example_ko_4 = '녹는 빙상에서 나오는 담수가 열염 순환 패턴을 약화시키고 있어요.', example_en_5 = 'Disruptions to thermohaline circulation could have cascading effects on global weather patterns.', example_ko_5 = '열염 순환의 교란은 전 세계 날씨 패턴에 연쇄적인 영향을 미칠 수 있어요.' WHERE id = 'w_environment_C2_02';
UPDATE words SET example_en_2 = 'The albedo feedback is a self-reinforcing cycle where warming reduces ice cover, which absorbs more heat.', example_ko_2 = '알베도 피드백은 온난화가 열을 더 흡수하는 얼음 덮개를 줄이는 자기 강화 사이클이에요.', example_en_3 = 'Arctic amplification is largely driven by the ice-albedo feedback mechanism.', example_ko_3 = '북극 증폭은 주로 얼음-알베도 피드백 메커니즘에 의해 구동돼요.', example_en_4 = 'Understanding albedo feedback is essential for accurate climate sensitivity estimates.', example_ko_4 = '알베도 피드백을 이해하는 것은 정확한 기후 민감도 추정에 필수적이에요.', example_en_5 = 'Albedo feedback could amplify warming beyond levels projected by current models.', example_ko_5 = '알베도 피드백이 현재 모델이 예측하는 수준을 넘어 온난화를 증폭시킬 수 있어요.' WHERE id = 'w_environment_C2_03';
UPDATE words SET example_en_2 = 'Cryosphere dynamics encompasses the interactions between ice sheets, sea ice, permafrost, and climate.', example_ko_2 = '빙권 역학은 빙상, 해빙, 영구 동토층과 기후 사이의 상호작용을 포함해요.', example_en_3 = 'Studying cryosphere dynamics helps scientists predict how quickly sea levels will rise.', example_ko_3 = '빙권 역학을 연구하면 과학자들이 해수면이 얼마나 빨리 상승할지 예측하는 데 도움이 돼요.', example_en_4 = 'Advances in satellite technology have transformed our ability to monitor cryosphere dynamics.', example_ko_4 = '위성 기술의 발전이 빙권 역학을 모니터링하는 우리의 능력을 변화시켰어요.', example_en_5 = 'Non-linear cryosphere dynamics make accurate long-term climate projections extremely challenging.', example_ko_5 = '비선형적 빙권 역학이 정확한 장기 기후 예측을 극히 어렵게 만들어요.' WHERE id = 'w_environment_C2_04';
UPDATE words SET example_en_2 = 'Permafrost thaw releases carbon that has been frozen for thousands of years.', example_ko_2 = '영구 동토층 해빙은 수천 년 동안 얼어 있던 탄소를 방출해요.', example_en_3 = 'Permafrost thaw is destabilising infrastructure in Arctic communities.', example_ko_3 = '영구 동토층 해빙이 북극 지역 사회의 기반시설을 불안정하게 만들고 있어요.', example_en_4 = 'Permafrost thaw represents a potential tipping point that could accelerate climate change.', example_ko_4 = '영구 동토층 해빙은 기후 변화를 가속화할 수 있는 잠재적 전환점을 나타내요.', example_en_5 = 'Scientists are urgently studying the rate and volume of carbon released by permafrost thaw.', example_ko_5 = '과학자들은 영구 동토층 해빙으로 방출되는 탄소의 속도와 양을 긴급하게 연구하고 있어요.' WHERE id = 'w_environment_C2_05';
UPDATE words SET example_en_2 = 'A climate tipping point is a threshold beyond which change becomes self-perpetuating and irreversible.', example_ko_2 = '기후 전환점은 변화가 자기 지속적이고 되돌릴 수 없게 되는 임계값이에요.', example_en_3 = 'Scientists warn that we may already be close to triggering several critical tipping points.', example_ko_3 = '과학자들은 우리가 이미 몇 가지 중요한 전환점을 촉발하는 것에 가까울 수 있다고 경고해요.', example_en_4 = 'Crossing a tipping point in the Amazon could trigger a rapid shift to savanna.', example_ko_4 = '아마존의 전환점을 넘으면 사바나로 급격한 전환이 촉발될 수 있어요.', example_en_5 = 'Understanding tipping points is crucial for setting credible climate policy targets.', example_ko_5 = '전환점을 이해하는 것은 신뢰할 수 있는 기후 정책 목표를 설정하는 데 중요해요.' WHERE id = 'w_environment_C2_06';
UPDATE words SET example_en_2 = 'Teleconnections link climate anomalies in one region to distant atmospheric patterns.', example_ko_2 = '원격연결은 한 지역의 기후 이상을 먼 대기 패턴과 연결해요.', example_en_3 = 'The El Nino teleconnection influences rainfall and temperature on multiple continents.', example_ko_3 = '엘니뇨 원격연결은 여러 대륙의 강수량과 기온에 영향을 미쳐요.', example_en_4 = 'Understanding teleconnections improves the accuracy of seasonal weather forecasts.', example_ko_4 = '원격연결을 이해하면 계절 기상 예보의 정확도가 향상돼요.', example_en_5 = 'Climate change is altering established teleconnection patterns in unpredictable ways.', example_ko_5 = '기후 변화가 확립된 원격연결 패턴을 예측 불가능한 방식으로 변화시키고 있어요.' WHERE id = 'w_environment_C2_07';
UPDATE words SET example_en_2 = 'A planetary boundary defines the safe operating space for humanity within the Earth system.', example_ko_2 = '지구 한계는 지구 시스템 내에서 인류의 안전한 운영 공간을 정의해요.', example_en_3 = 'Scientists have identified nine planetary boundaries, several of which have already been exceeded.', example_ko_3 = '과학자들은 아홉 가지 지구 한계를 확인했으며 그 중 몇 가지는 이미 초과되었어요.', example_en_4 = 'Crossing multiple planetary boundaries simultaneously risks destabilising the entire Earth system.', example_ko_4 = '여러 지구 한계를 동시에 넘으면 전체 지구 시스템을 불안정하게 할 위험이 있어요.', example_en_5 = 'The planetary boundary framework provides a scientific basis for sustainable development goals.', example_ko_5 = '지구 한계 프레임워크는 지속 가능한 발전 목표를 위한 과학적 기반을 제공해요.' WHERE id = 'w_environment_C2_08';
UPDATE words SET example_en_2 = 'The Holocene was characterised by relatively stable climate conditions that enabled human civilisation.', example_ko_2 = '홀로세는 인류 문명을 가능하게 한 비교적 안정적인 기후 조건으로 특징지어졌어요.', example_en_3 = 'Some scientists argue we have entered a new epoch beyond the Holocene called the Anthropocene.', example_ko_3 = '일부 과학자들은 우리가 인류세라고 불리는 홀로세를 넘어 새로운 시대에 접어들었다고 주장해요.', example_en_4 = 'Holocene climate variability was modest compared to changes projected for the coming century.', example_ko_4 = '홀로세 기후 변동성은 다가오는 세기에 예측된 변화에 비해 미미했어요.', example_en_5 = 'Paleoclimatic records from the Holocene provide benchmarks for evaluating modern climate models.', example_ko_5 = '홀로세의 고기후 기록은 현대 기후 모델을 평가하기 위한 기준점을 제공해요.' WHERE id = 'w_environment_C2_09';
UPDATE words SET example_en_2 = 'The technosphere includes all the material and informational structures created by human civilisation.', example_ko_2 = '기술권에는 인류 문명이 만들어 낸 모든 물질적, 정보적 구조물이 포함돼요.', example_en_3 = 'The technosphere now rivals the biosphere in terms of mass and complexity.', example_ko_3 = '기술권은 이제 질량과 복잡성 면에서 생물권에 필적해요.', example_en_4 = 'Making the technosphere sustainable requires redesigning entire industrial systems.', example_ko_4 = '기술권을 지속 가능하게 만들려면 전체 산업 시스템을 재설계해야 해요.', example_en_5 = 'The concept of the technosphere challenges us to think about technology as a geological force.', example_ko_5 = '기술권의 개념은 우리에게 기술을 지질학적 힘으로 생각하도록 도전해요.' WHERE id = 'w_environment_C2_10';
UPDATE words SET example_en_2 = 'Stratospheric aerosol injection could cool the planet but carries significant unknown risks.', example_ko_2 = '성층권 에어로졸 주입은 지구를 냉각시킬 수 있지만 상당한 미지의 위험을 내포해요.', example_en_3 = 'Stratospheric aerosol injection mimics the temporary cooling effect of large volcanic eruptions.', example_ko_3 = '성층권 에어로졸 주입은 대형 화산 폭발의 일시적 냉각 효과를 모방해요.', example_en_4 = 'Termination shock could occur if stratospheric aerosol injection is suddenly halted.', example_ko_4 = '성층권 에어로졸 주입이 갑자기 중단되면 종료 충격이 발생할 수 있어요.', example_en_5 = 'Stratospheric aerosol injection research requires international governance to prevent unilateral action.', example_ko_5 = '성층권 에어로졸 주입 연구는 일방적인 행동을 막기 위해 국제 거버넌스가 필요해요.' WHERE id = 'w_environment_C2_11';
UPDATE words SET example_en_2 = 'Eddy diffusivity describes how turbulent mixing spreads tracers through the ocean or atmosphere.', example_ko_2 = '와류 확산율은 난류 혼합이 추적자를 해양이나 대기를 통해 어떻게 퍼뜨리는지를 설명해요.', example_en_3 = 'Accurate eddy diffusivity parameterisation is critical for reliable climate model simulations.', example_ko_3 = '정확한 와류 확산율 매개변수화는 신뢰할 수 있는 기후 모델 시뮬레이션에 중요해요.', example_en_4 = 'Ocean eddy diffusivity influences the rate at which heat is transported to deeper layers.', example_ko_4 = '해양 와류 확산율은 열이 더 깊은 층으로 운반되는 속도에 영향을 미쳐요.', example_en_5 = 'Satellite observations are helping scientists improve eddy diffusivity estimates in ocean models.', example_ko_5 = '위성 관측이 과학자들이 해양 모델에서 와류 확산율 추정을 개선하는 데 도움이 되고 있어요.' WHERE id = 'w_environment_C2_12';
UPDATE words SET example_en_2 = 'Isotopic fractionation allows scientists to reconstruct ancient temperatures from ice cores.', example_ko_2 = '동위원소 분별은 과학자들이 빙하 코어에서 고대 기온을 재구성할 수 있게 해요.', example_en_3 = 'Isotopic fractionation of carbon is used to distinguish fossil fuel emissions from natural sources.', example_ko_3 = '탄소의 동위원소 분별은 화석 연료 배출과 자연 원천을 구별하는 데 사용돼요.', example_en_4 = 'Understanding isotopic fractionation has transformed palaeoclimate research over the past century.', example_ko_4 = '동위원소 분별을 이해하는 것이 지난 세기 동안 고기후 연구를 변화시켰어요.', example_en_5 = 'Oxygen isotopic fractionation in carbonate shells records ancient sea surface temperatures.', example_ko_5 = '탄산염 껍질에서의 산소 동위원소 분별은 고대 해수 표면 온도를 기록해요.' WHERE id = 'w_environment_C2_13';
UPDATE words SET example_en_2 = 'Milankovitch cycles describe how variations in Earth''s orbit drive long-term climate change.', example_ko_2 = '밀란코비치 주기는 지구 궤도의 변화가 어떻게 장기적인 기후 변화를 이끄는지를 설명해요.', example_en_3 = 'Milankovitch cycles operate over timescales of tens of thousands to hundreds of thousands of years.', example_ko_3 = '밀란코비치 주기는 수만 년에서 수십만 년의 시간 규모에서 작동해요.', example_en_4 = 'Current anthropogenic warming is occurring far faster than any Milankovitch cycle-driven change.', example_ko_4 = '현재 인위적 온난화는 어떤 밀란코비치 주기 주도 변화보다 훨씬 빠르게 발생하고 있어요.', example_en_5 = 'Ice age cycles documented in polar ice cores correspond closely to Milankovitch cycle predictions.', example_ko_5 = '극지방 빙하 코어에 기록된 빙하기 주기는 밀란코비치 주기 예측과 밀접하게 일치해요.' WHERE id = 'w_environment_C2_14';
UPDATE words SET example_en_2 = 'Biogeography explores how geographical features shape the distribution of species and ecosystems.', example_ko_2 = '생물지리학은 지리적 특성이 종과 생태계의 분포를 어떻게 형성하는지를 탐구해요.', example_en_3 = 'Island biogeography has provided key insights into species richness and extinction dynamics.', example_ko_3 = '섬 생물지리학은 종 풍부도와 멸종 역학에 관한 핵심 통찰을 제공했어요.', example_en_4 = 'Climate change is altering biogeography by shifting species ranges toward the poles.', example_ko_4 = '기후 변화가 종의 분포 범위를 극지방으로 이동시켜 생물지리학을 변화시키고 있어요.', example_en_5 = 'Understanding biogeography is essential for predicting which species are most at risk.', example_ko_5 = '생물지리학을 이해하는 것은 어떤 종이 가장 위험에 처해 있는지 예측하는 데 필수적이에요.' WHERE id = 'w_environment_C2_15';
UPDATE words SET example_en_2 = 'An anthrome is a biome that has been significantly transformed by human land use.', example_ko_2 = '인간생태권은 인간의 토지 이용으로 크게 변화된 생물군계예요.', example_en_3 = 'Anthromes now dominate much of Earth''s terrestrial surface, replacing natural biomes.', example_ko_3 = '인간생태권이 이제 자연 생물군계를 대체하며 지구 육지 표면의 많은 부분을 지배해요.', example_en_4 = 'Mapping anthromes reveals the full extent of human transformation of the land surface.', example_ko_4 = '인간생태권을 매핑하면 토지 표면에 대한 인간 변환의 전체 범위가 드러나요.', example_en_5 = 'The concept of anthromes challenges the traditional dichotomy between nature and human society.', example_ko_5 = '인간생태권의 개념은 자연과 인간 사회 사이의 전통적인 이분법에 도전해요.' WHERE id = 'w_environment_C2_16';
UPDATE words SET example_en_2 = 'Methanogenesis is carried out by archaea in anaerobic environments such as swamps and landfills.', example_ko_2 = '메탄 생성은 늪지와 매립지 같은 무산소 환경에서 고세균에 의해 수행돼요.', example_en_3 = 'Methanogenesis in rice paddies contributes significantly to global methane emissions.', example_ko_3 = '논에서의 메탄 생성이 전 세계 메탄 배출에 상당히 기여해요.', example_en_4 = 'Understanding methanogenesis pathways is important for developing strategies to reduce emissions.', example_ko_4 = '메탄 생성 경로를 이해하는 것은 배출을 줄이는 전략을 개발하는 데 중요해요.', example_en_5 = 'Permafrost thaw accelerates methanogenesis by exposing frozen organic matter to microbial activity.', example_ko_5 = '영구 동토층 해빙은 얼어있는 유기물을 미생물 활동에 노출시켜 메탄 생성을 가속화해요.' WHERE id = 'w_environment_C2_17';
UPDATE words SET example_en_2 = 'Dendroclimatology uses tree ring patterns to reconstruct past climate conditions.', example_ko_2 = '연륜기후학은 나무 나이테 패턴을 사용하여 과거 기후 조건을 재구성해요.', example_en_3 = 'Dendroclimatology records extend our climate knowledge back thousands of years before instrumental data.', example_ko_3 = '연륜기후학 기록은 기후 지식을 기기 데이터 이전 수천 년 전까지 확장해요.', example_en_4 = 'Combining dendroclimatology with other proxy data improves the reliability of palaeoclimate reconstructions.', example_ko_4 = '연륜기후학을 다른 대리 데이터와 결합하면 고기후 재구성의 신뢰성이 향상돼요.', example_en_5 = 'Dendroclimatology has confirmed that recent warming is unprecedented over the past millennium.', example_ko_5 = '연륜기후학은 최근 온난화가 지난 천 년 동안 전례가 없음을 확인했어요.' WHERE id = 'w_environment_C2_18';
UPDATE words SET example_en_2 = 'Xenobiotics are foreign chemical compounds not naturally present in living organisms.', example_ko_2 = '외래 생체이물은 살아있는 유기체에 자연적으로 존재하지 않는 외래 화합물이에요.', example_en_3 = 'The persistence of xenobiotics in the environment is a major concern for ecosystem health.', example_ko_3 = '환경에서 외래 생체이물의 지속성은 생태계 건강에 대한 주요 우려사항이에요.', example_en_4 = 'Some xenobiotics accumulate in food chains and reach toxic levels in top predators.', example_ko_4 = '일부 외래 생체이물은 먹이 사슬에 축적되어 최상위 포식자에서 독성 수준에 도달해요.', example_en_5 = 'Regulatory agencies assess the risk of xenobiotics before approving new chemicals for commercial use.', example_ko_5 = '규제 기관은 새로운 화학물질을 상업적 사용으로 승인하기 전에 외래 생체이물의 위험을 평가해요.' WHERE id = 'w_environment_C2_19';
UPDATE words SET example_en_2 = 'Geomorphology examines how climate and geology shape the landforms we see today.', example_ko_2 = '지형학은 기후와 지질학이 오늘날 우리가 보는 지형을 어떻게 형성하는지를 검토해요.', example_en_3 = 'Coastal geomorphology is increasingly important as sea level rise alters shoreline dynamics.', example_ko_3 = '해안 지형학은 해수면 상승이 해안선 역학을 변화시키면서 점점 더 중요해지고 있어요.', example_en_4 = 'Geomorphology helps engineers predict how rivers and coastlines will respond to climate change.', example_ko_4 = '지형학은 엔지니어들이 강과 해안선이 기후 변화에 어떻게 반응할지 예측하는 데 도움이 돼요.', example_en_5 = 'Rapid geomorphology changes in permafrost regions signal the pace of ongoing climate change.', example_ko_5 = '영구 동토층 지역의 급격한 지형 변화는 진행 중인 기후 변화의 속도를 나타내요.' WHERE id = 'w_environment_C2_20';
UPDATE words SET example_en_2 = 'Limnology is concerned with the physics, chemistry, and biology of freshwater lakes and rivers.', example_ko_2 = '호소학은 담수 호수와 강의 물리학, 화학, 생물학을 다뤄요.', example_en_3 = 'Limnology research shows that lake temperatures are rising faster than air temperatures.', example_ko_3 = '호소학 연구는 호수 온도가 기온보다 더 빠르게 상승하고 있음을 보여 줘요.', example_en_4 = 'Advances in limnology have improved our ability to detect early signs of eutrophication.', example_ko_4 = '호소학의 발전이 부영양화의 초기 징후를 감지하는 우리의 능력을 향상시켰어요.', example_en_5 = 'Limnology provides critical data for managing freshwater resources under climate stress.', example_ko_5 = '호소학은 기후 스트레스 하에서 담수 자원을 관리하기 위한 중요한 데이터를 제공해요.' WHERE id = 'w_environment_C2_21';
UPDATE words SET example_en_2 = 'Photodegradation breaks down plastic polymers into microplastics when exposed to UV radiation.', example_ko_2 = '광분해는 자외선에 노출될 때 플라스틱 폴리머를 미세플라스틱으로 분해해요.', example_en_3 = 'Photodegradation of certain pesticides in soil reduces their long-term toxicity.', example_ko_3 = '토양에서 특정 농약의 광분해는 장기적 독성을 줄여요.', example_en_4 = 'Understanding photodegradation rates is important for predicting the environmental persistence of chemicals.', example_ko_4 = '광분해율을 이해하는 것은 화학물질의 환경 지속성을 예측하는 데 중요해요.', example_en_5 = 'Photodegradation of atmospheric pollutants can produce secondary compounds that are even more harmful.', example_ko_5 = '대기 오염 물질의 광분해는 더 해로울 수 있는 이차 화합물을 생성할 수 있어요.' WHERE id = 'w_environment_C2_22';
UPDATE words SET example_en_2 = 'Carrying capacity is the maximum population size an environment can sustainably support.', example_ko_2 = '수용 능력은 환경이 지속 가능하게 지원할 수 있는 최대 개체 수예요.', example_en_3 = 'Human populations have temporarily exceeded the Earth''s carrying capacity by depleting natural capital.', example_ko_3 = '인류는 자연 자본을 고갈시켜 지구의 수용 능력을 일시적으로 초과했어요.', example_en_4 = 'When a species exceeds carrying capacity, it typically experiences a sharp population decline.', example_ko_4 = '종이 수용 능력을 초과하면 일반적으로 개체 수가 급감해요.', example_en_5 = 'The concept of carrying capacity helps frame debates about sustainable resource use and population.', example_ko_5 = '수용 능력의 개념은 지속 가능한 자원 이용과 인구에 대한 토론을 구성하는 데 도움이 돼요.' WHERE id = 'w_environment_C2_23';
UPDATE words SET example_en_2 = 'Ecological stoichiometry examines how the ratio of elements affects organisms and ecosystems.', example_ko_2 = '생태 화학양론은 원소의 비율이 유기체와 생태계에 어떻게 영향을 미치는지를 검토해요.', example_en_3 = 'Stoichiometry in aquatic systems determines which nutrients limit the growth of algae.', example_ko_3 = '수생 시스템에서의 화학양론은 어떤 영양분이 조류의 성장을 제한하는지를 결정해요.', example_en_4 = 'Imbalanced stoichiometry caused by pollution can disrupt food web dynamics.', example_ko_4 = '오염으로 인한 불균형한 화학양론이 먹이 그물 역학을 교란할 수 있어요.', example_en_5 = 'Applying stoichiometry principles can improve the efficiency of nutrient use in agriculture.', example_ko_5 = '화학양론 원칙을 적용하면 농업에서 영양분 사용 효율을 개선할 수 있어요.' WHERE id = 'w_environment_C2_24';
UPDATE words SET example_en_2 = 'Macroecology examines statistical patterns in species distribution across large spatial scales.', example_ko_2 = '거시생태학은 넓은 공간 규모에 걸쳐 종 분포의 통계적 패턴을 검토해요.', example_en_3 = 'Macroecology has revealed consistent relationships between body size and geographical range.', example_ko_3 = '거시생태학은 체체 크기와 지리적 분포 범위 사이의 일관된 관계를 밝혔어요.', example_en_4 = 'Macroecological analysis of biodiversity loss data informs global conservation policy.', example_ko_4 = '생물 다양성 손실 데이터의 거시생태학적 분석이 전 세계 보전 정책을 알려 줘요.', example_en_5 = 'Macroecology bridges evolutionary biology, biogeography, and conservation science.', example_ko_5 = '거시생태학은 진화 생물학, 생물지리학, 보전 과학을 연결해요.' WHERE id = 'w_environment_C2_25';
UPDATE words SET example_en_2 = 'Exergy measures the useful work potential of an energy system in a given environment.', example_ko_2 = '엑서지는 주어진 환경에서 에너지 시스템의 유용한 일 잠재력을 측정해요.', example_en_3 = 'Maximising exergy efficiency reduces waste heat and improves the sustainability of industrial processes.', example_ko_3 = '엑서지 효율을 최대화하면 폐열을 줄이고 산업 공정의 지속 가능성을 개선해요.', example_en_4 = 'Exergy analysis identifies where energy is being degraded and wasted in a system.', example_ko_4 = '엑서지 분석은 시스템에서 에너지가 어디서 저하되고 낭비되는지를 식별해요.', example_en_5 = 'Applying exergy principles to building design can significantly cut energy consumption.', example_ko_5 = '엑서지 원칙을 건물 설계에 적용하면 에너지 소비를 크게 줄일 수 있어요.' WHERE id = 'w_environment_C2_26';
UPDATE words SET example_en_2 = 'Palaeoecology reconstructs past ecosystems from fossil pollen, seeds, and other biological remains.', example_ko_2 = '고생태학은 화석 꽃가루, 씨앗, 기타 생물학적 잔재에서 과거 생태계를 재구성해요.', example_en_3 = 'Palaeoecology reveals how ecosystems have responded to past climate change and disturbance.', example_ko_3 = '고생태학은 생태계가 과거 기후 변화와 교란에 어떻게 반응했는지를 보여 줘요.', example_en_4 = 'Palaeoecology provides long-term baselines for assessing the current state of biodiversity.', example_ko_4 = '고생태학은 현재 생물 다양성 상태를 평가하기 위한 장기 기준점을 제공해요.', example_en_5 = 'Palaeoecological data increasingly informs conservation and ecological restoration targets.', example_ko_5 = '고생태학적 데이터가 점점 더 보전과 생태 복원 목표를 알려 주고 있어요.' WHERE id = 'w_environment_C2_27';
UPDATE words SET example_en_2 = 'Abiogenesis describes the process by which life first emerged from non-living chemical matter.', example_ko_2 = '생명 기원은 생명이 처음 비생물적 화학 물질에서 어떻게 생겨났는지를 설명해요.', example_en_3 = 'Abiogenesis research seeks to understand the chemical conditions that allowed life to begin.', example_ko_3 = '생명 기원 연구는 생명이 시작할 수 있게 한 화학적 조건을 이해하려고 해요.', example_en_4 = 'Understanding abiogenesis is fundamental to assessing the likelihood of life on other planets.', example_ko_4 = '생명 기원을 이해하는 것은 다른 행성에서 생명의 가능성을 평가하는 데 근본적이에요.', example_en_5 = 'Laboratory simulations of abiogenesis have succeeded in producing amino acids from simple chemicals.', example_ko_5 = '생명 기원의 실험실 시뮬레이션은 간단한 화학물질에서 아미노산을 생성하는 데 성공했어요.' WHERE id = 'w_environment_C2_28';
UPDATE words SET example_en_2 = 'Endosymbiosis theory proposes that mitochondria evolved from bacteria engulfed by early cells.', example_ko_2 = '내부공생 이론은 미토콘드리아가 초기 세포에 흡수된 박테리아에서 진화했다고 주장해요.', example_en_3 = 'Endosymbiosis events were transformative moments in the evolution of complex life.', example_ko_3 = '내부공생 사건은 복잡한 생명의 진화에서 변혁적인 순간들이었어요.', example_en_4 = 'The endosymbiosis that produced chloroplasts was fundamental to the evolution of plants and algae.', example_ko_4 = '엽록체를 만들어 낸 내부공생은 식물과 조류의 진화에 근본적이었어요.', example_en_5 = 'Endosymbiosis demonstrates how cooperation between organisms can drive major evolutionary leaps.', example_ko_5 = '내부공생은 유기체 간의 협력이 어떻게 주요 진화적 도약을 이끌 수 있는지를 보여 줘요.' WHERE id = 'w_environment_C2_29';
UPDATE words SET example_en_2 = 'Photochemical smog forms when vehicle emissions react with sunlight to create ozone and other pollutants.', example_ko_2 = '광화학 스모그는 차량 배기가스가 햇빛과 반응하여 오존과 다른 오염 물질을 만들 때 형성돼요.', example_en_3 = 'Photochemical smog is most severe in warm, sunny cities with heavy traffic.', example_ko_3 = '광화학 스모그는 교통량이 많고 따뜻하고 햇볕이 잘 드는 도시에서 가장 심각해요.', example_en_4 = 'Breathing photochemical smog over many years increases the risk of chronic respiratory disease.', example_ko_4 = '광화학 스모그를 수년간 마시면 만성 호흡기 질환의 위험이 높아져요.', example_en_5 = 'Stricter vehicle emission standards have helped reduce photochemical smog in many cities.', example_ko_5 = '더 엄격한 차량 배기가스 기준이 많은 도시에서 광화학 스모그를 줄이는 데 도움이 되었어요.' WHERE id = 'w_environment_C2_30';
UPDATE words SET example_en_2 = 'Volatile organic compounds from paint and solvents contribute to indoor air pollution.', example_ko_2 = '페인트와 용제에서 나오는 휘발성 유기 화합물은 실내 공기 오염에 기여해요.', example_en_3 = 'Volatile organic compounds react with nitrogen oxides to form ground-level ozone.', example_ko_3 = '휘발성 유기 화합물은 질소산화물과 반응하여 지상 수준의 오zone을 형성해요.', example_en_4 = 'Regulations limiting volatile organic compound emissions have improved air quality in many regions.', example_ko_4 = '휘발성 유기 화합물 배출을 제한하는 규제가 많은 지역에서 공기 질을 개선했어요.', example_en_5 = 'Natural sources such as forests also emit volatile organic compounds that influence atmospheric chemistry.', example_ko_5 = '숲과 같은 자연 원천도 대기 화학에 영향을 미치는 휘발성 유기 화합물을 배출해요.' WHERE id = 'w_environment_C2_31';
UPDATE words SET example_en_2 = 'Coccolithophores play a critical role in the marine carbon cycle by forming calcium carbonate shells.', example_ko_2 = '원석조류는 탄산칼슘 껍질을 형성하여 해양 탄소 순환에서 중요한 역할을 해요.', example_en_3 = 'Ocean acidification threatens the ability of coccolithophores to build their protective shells.', example_ko_3 = '해양 산성화가 원석조류가 보호 껍질을 만드는 능력을 위협해요.', example_en_4 = 'Coccolithophore blooms are large enough to be detected from satellites in space.', example_ko_4 = '원석조류 대번식은 우주의 위성에서 감지될 만큼 커요.', example_en_5 = 'Changes in coccolithophore populations signal shifts in ocean chemistry and productivity.', example_ko_5 = '원석조류 개체 수의 변화는 해양 화학과 생산성의 변화를 나타내요.' WHERE id = 'w_environment_C2_32';
UPDATE words SET example_en_2 = 'Negative emissions technology includes direct air capture and bioenergy with carbon capture.', example_ko_2 = '탄소 흡수 기술에는 직접 공기 포집과 탄소 포집을 동반한 바이오에너지가 포함돼요.', example_en_3 = 'Scaling negative emissions technology is essential for meeting the most ambitious climate targets.', example_ko_3 = '탄소 흡수 기술을 확장하는 것은 가장 야심찬 기후 목표를 달성하는 데 필수적이에요.', example_en_4 = 'Critics warn that reliance on future negative emissions technology may delay needed emissions cuts today.', example_ko_4 = '비평가들은 미래의 탄소 흡수 기술에 의존하면 오늘날 필요한 배출 감축을 지연시킬 수 있다고 경고해요.', example_en_5 = 'The cost of negative emissions technology needs to fall dramatically for it to be widely deployed.', example_ko_5 = '탄소 흡수 기술이 널리 보급되려면 비용이 크게 낮아져야 해요.' WHERE id = 'w_environment_C2_33';
UPDATE words SET example_en_2 = 'Earth system science integrates atmosphere, ocean, land, and biosphere into a unified framework.', example_ko_2 = '지구 시스템 과학은 대기, 해양, 육지, 생물권을 통합된 프레임워크로 통합해요.', example_en_3 = 'Earth system science shows that human activity has become a geological force of planetary significance.', example_ko_3 = '지구 시스템 과학은 인간 활동이 행성적 중요성을 지닌 지질학적 힘이 되었음을 보여 줘요.', example_en_4 = 'Earth system science provides the foundation for understanding feedbacks and tipping points.', example_ko_4 = '지구 시스템 과학은 피드백과 전환점을 이해하기 위한 기반을 제공해요.', example_en_5 = 'International Earth system science programmes coordinate data collection and modelling across nations.', example_ko_5 = '국제 지구 시스템 과학 프로그램이 국가 간 데이터 수집과 모델링을 조율해요.' WHERE id = 'w_environment_C2_34';
UPDATE words SET example_en_2 = 'A refugium is an area where species survive during unfavourable climatic conditions.', example_ko_2 = '피난처는 불리한 기후 조건 동안 종들이 살아남는 지역이에요.', example_en_3 = 'Tropical refugia during ice ages contributed to the high biodiversity seen in these regions today.', example_ko_3 = '빙하기 동안의 열대 피난처가 오늘날 이 지역에서 보이는 높은 생물 다양성에 기여했어요.', example_en_4 = 'Climate change may force species to survive only in isolated refugia as habitats shift.', example_ko_4 = '기후 변화로 서식지가 이동함에 따라 종들이 고립된 피난처에서만 살아남도록 강요받을 수 있어요.', example_en_5 = 'Identifying future refugia is increasingly important for conservation planning under climate change.', example_ko_5 = '미래 피난처를 식별하는 것은 기후 변화 하에서 보전 계획에 점점 더 중요해지고 있어요.' WHERE id = 'w_environment_C2_35';

-- ── health ──
-- Health topic: example_en_2~5 + example_ko_2~5
-- A1

UPDATE words SET example_en_2 = 'She looked sick and went home early.', example_ko_2 = '그녀는 아파 보여서 일찍 집에 갔어요.', example_en_3 = 'The sick child stayed in bed all day.', example_ko_3 = '아픈 아이는 하루 종일 침대에 누워 있었어요.', example_en_4 = 'He called in sick this morning.', example_ko_4 = '그는 오늘 아침 아프다고 전화했어요.', example_en_5 = 'Are you feeling sick again?', example_ko_5 = '또 아프신가요?' WHERE id = 'w_health_A1_01';
UPDATE words SET example_en_2 = 'There is a sharp pain in my chest.', example_ko_2 = '가슴에 날카로운 통증이 있어요.', example_en_3 = 'The pain went away after I rested.', example_ko_3 = '쉬고 나서 통증이 사라졌어요.', example_en_4 = 'She cried out in pain.', example_ko_4 = '그녀는 통증으로 소리를 질렀어요.', example_en_5 = 'How long have you had this pain?', example_ko_5 = '이 통증이 얼마나 됐나요?' WHERE id = 'w_health_A1_02';
UPDATE words SET example_en_2 = 'The doctor gave me some medicine.', example_ko_2 = '의사가 약을 처방해 줬어요.', example_en_3 = 'My doctor told me to drink more water.', example_ko_3 = '의사가 물을 더 많이 마시라고 했어요.', example_en_4 = 'I need to see a doctor today.', example_ko_4 = '오늘 의사를 만나야 해요.', example_en_5 = 'Is there a doctor on call tonight?', example_ko_5 = '오늘 밤 당직 의사가 있나요?' WHERE id = 'w_health_A1_03';
UPDATE words SET example_en_2 = 'The hospital is open 24 hours.', example_ko_2 = '병원은 24시간 운영해요.', example_en_3 = 'She spent three days in hospital.', example_ko_3 = '그녀는 3일간 입원해 있었어요.', example_en_4 = 'The nearest hospital is two kilometers away.', example_ko_4 = '가장 가까운 병원은 2킬로미터 거리에 있어요.', example_en_5 = 'He was taken to hospital by ambulance.', example_ko_5 = '그는 구급차로 병원에 이송됐어요.' WHERE id = 'w_health_A1_04';
UPDATE words SET example_en_2 = 'Please take this medicine with food.', example_ko_2 = '이 약은 식후에 드세요.', example_en_3 = 'The medicine worked quickly.', example_ko_3 = '약이 빨리 효과가 있었어요.', example_en_4 = 'Do not mix this medicine with alcohol.', example_ko_4 = '이 약을 알코올과 함께 복용하지 마세요.', example_en_5 = 'Where can I buy this medicine?', example_ko_5 = '이 약은 어디서 살 수 있나요?' WHERE id = 'w_health_A1_05';
UPDATE words SET example_en_2 = 'I could not sleep at all last night.', example_ko_2 = '어젯밤에 전혀 잠을 잘 수 없었어요.', example_en_3 = 'Try to sleep for at least eight hours.', example_ko_3 = '최소 여덟 시간은 주무시려고 해 보세요.', example_en_4 = 'She fell asleep on the sofa.', example_ko_4 = '그녀는 소파에서 잠이 들었어요.', example_en_5 = 'Good sleep helps your body heal.', example_ko_5 = '충분한 수면은 몸을 회복시키는 데 도움이 돼요.' WHERE id = 'w_health_A1_06';
UPDATE words SET example_en_2 = 'I feel tired even after sleeping.', example_ko_2 = '자고 나서도 피곤해요.', example_en_3 = 'He was too tired to eat dinner.', example_ko_3 = '그는 너무 피곤해서 저녁을 먹지 못했어요.', example_en_4 = 'Working long hours makes me tired.', example_ko_4 = '오래 일하면 피곤해져요.', example_en_5 = 'You look very tired today.', example_ko_5 = '오늘 많이 피곤해 보이세요.' WHERE id = 'w_health_A1_07';
