UPDATE words SET example_en_2 = 'The endocrine system controls hormones in the body.', example_ko_2 = '내분비 체계는 체내 호르몬을 조절해요.', example_en_3 = 'An endocrine disorder can affect metabolism and mood.', example_ko_3 = '내분비 장애는 신진대사와 기분에 영향을 줄 수 있어요.', example_en_4 = 'She was referred to an endocrine specialist.', example_ko_4 = '그녀는 내분비 전문의에게 의뢰됐어요.', example_en_5 = 'The thyroid is one of the key endocrine glands.', example_ko_5 = '갑상선은 주요 내분비 기관 중 하나예요.' WHERE id = 'w_health_B2_22';
