UPDATE words SET example_en_2 = 'The mutation made the virus harder to treat.', example_ko_2 = '돌연변이로 인해 바이러스 치료가 더 어려워졌어요.', example_en_3 = 'Some genetic mutations increase the risk of cancer.', example_ko_3 = '일부 유전자 돌연변이는 암 위험을 높여요.', example_en_4 = 'Scientists are studying how the mutation affects the protein.', example_ko_4 = '과학자들은 돌연변이가 단백질에 어떤 영향을 미치는지 연구하고 있어요.', example_en_5 = 'The mutation was identified through DNA testing.', example_ko_5 = '돌연변이는 DNA 검사를 통해 확인됐어요.' WHERE id = 'w_health_B2_24';
UPDATE words SET example_en_2 = 'She was referred to a neurological specialist after the seizure.', example_ko_2 = '그녀는 발작 후 신경과 전문의에게 의뢰됐어요.', example_en_3 = 'Neurological damage can result from severe head trauma.', example_ko_3 = '신경학적 손상은 심각한 두부 외상으로 인해 발생할 수 있어요.', example_en_4 = 'The MRI revealed a neurological abnormality.', example_ko_4 = 'MRI에서 신경학적 이상이 발견됐어요.', example_en_5 = 'He experienced neurological symptoms including numbness.', example_ko_5 = '그는 마비를 포함한 신경학적 증상을 경험했어요.' WHERE id = 'w_health_B2_25';
UPDATE words SET example_en_2 = 'Prediabetes can often be reversed with lifestyle changes.', example_ko_2 = '당뇨 전 단계는 생활 습관을 바꿔서 되돌릴 수 있는 경우가 많아요.', example_en_3 = 'He was diagnosed with prediabetes during a routine checkup.', example_ko_3 = '그는 정기 검진 중 당뇨 전 단계 진단을 받았어요.', example_en_4 = 'Prediabetes is a serious warning sign that should not be ignored.', example_ko_4 = '당뇨 전 단계는 무시해서는 안 되는 심각한 경고 신호예요.', example_en_5 = 'Diet and exercise are the best ways to prevent prediabetes from progressing.', example_ko_5 = '식단과 운동은 당뇨 전 단계가 진행되는 것을 막는 가장 좋은 방법이에요.' WHERE id = 'w_health_B2_26';
UPDATE words SET example_en_2 = 'She visited an ophthalmology clinic for her blurry vision.', example_ko_2 = '그녀는 흐릿한 시력 때문에 안과 클리닉에 방문했어요.', example_en_3 = 'Ophthalmology covers conditions such as glaucoma and cataracts.', example_ko_3 = '안과는 녹내장과 백내장 같은 질환을 다뤄요.', example_en_4 = 'He studied ophthalmology to become an eye surgeon.', example_ko_4 = '그는 안과 외과 의사가 되기 위해 안과학을 공부했어요.', example_en_5 = 'The ophthalmology department is on the fourth floor.', example_ko_5 = '안과는 4층에 있어요.' WHERE id = 'w_health_B2_27';
UPDATE words SET example_en_2 = 'Pulmonary hypertension affects the arteries in the lungs.', example_ko_2 = '폐 고혈압은 폐의 동맥에 영향을 미쳐요.', example_en_3 = 'She underwent a pulmonary function test.', example_ko_3 = '그녀는 폐 기능 검사를 받았어요.', example_en_4 = 'Smoking is the leading cause of pulmonary disease.', example_ko_4 = '흡연은 폐 질환의 주요 원인이에요.', example_en_5 = 'His pulmonary condition required long-term oxygen therapy.', example_ko_5 = '그의 폐 상태는 장기적인 산소 치료가 필요했어요.' WHERE id = 'w_health_B2_28';
UPDATE words SET example_en_2 = 'Athletes undergo hypertrophy training to build muscle.', example_ko_2 = '운동선수들은 근육을 키우기 위해 비대 훈련을 해요.', example_en_3 = 'Cardiac hypertrophy can be a sign of heart disease.', example_ko_3 = '심장 비대는 심장 질환의 징후일 수 있어요.', example_en_4 = 'Hypertrophy of the muscles occurs through consistent training.', example_ko_4 = '근육 비대는 꾸준한 훈련을 통해 발생해요.', example_en_5 = 'Left ventricular hypertrophy was detected on the ECG.', example_ko_5 = '심전도에서 좌심실 비대가 감지됐어요.' WHERE id = 'w_health_B2_29';
UPDATE words SET example_en_2 = 'The pathogen was identified as a new strain of bacteria.', example_ko_2 = '병원체는 새로운 균주의 박테리아로 확인됐어요.', example_en_3 = 'Washing hands prevents the spread of pathogens.', example_ko_3 = '손 씻기는 병원체의 확산을 예방해요.', example_en_4 = 'The pathogen was resistant to standard antibiotics.', example_ko_4 = '병원체는 표준 항생제에 내성이 있었어요.', example_en_5 = 'Scientists are working to develop vaccines for new pathogens.', example_ko_5 = '과학자들은 새로운 병원체에 대한 백신을 개발하기 위해 노력하고 있어요.' WHERE id = 'w_health_B2_30';
UPDATE words SET example_en_2 = 'Immunization programs have eradicated several diseases.', example_ko_2 = '예방 접종 프로그램이 여러 질병을 근절했어요.', example_en_3 = 'She made sure her children were up to date on immunization.', example_ko_3 = '그녀는 아이들의 예방 접종이 최신 상태인지 확인했어요.', example_en_4 = 'Immunization is one of the most cost-effective health interventions.', example_ko_4 = '예방 접종은 가장 비용 효율적인 건강 개입 중 하나예요.', example_en_5 = 'The immunization schedule varies by country.', example_ko_5 = '예방 접종 일정은 나라마다 달라요.' WHERE id = 'w_health_B2_31';
UPDATE words SET example_en_2 = 'Iron-deficiency anemia is common in women.', example_ko_2 = '철분 결핍성 빈혈은 여성에게 흔해요.', example_en_3 = 'She felt constantly tired due to her anemia.', example_ko_3 = '그녀는 빈혈로 인해 항상 피곤함을 느꼈어요.', example_en_4 = 'The doctor prescribed iron supplements for her anemia.', example_ko_4 = '의사가 빈혈 치료를 위해 철분 보충제를 처방했어요.', example_en_5 = 'Anemia can be diagnosed through a simple blood test.', example_ko_5 = '빈혈은 간단한 혈액 검사로 진단할 수 있어요.' WHERE id = 'w_health_B2_32';
UPDATE words SET example_en_2 = 'Fibromyalgia causes widespread pain and fatigue.', example_ko_2 = '섬유근육통은 전신 통증과 피로를 유발해요.', example_en_3 = 'She was finally diagnosed with fibromyalgia after years of searching.', example_ko_3 = '그녀는 수년간의 검사 끝에 마침내 섬유근육통 진단을 받았어요.', example_en_4 = 'There is no single cure for fibromyalgia.', example_ko_4 = '섬유근육통에는 단일 치료법이 없어요.', example_en_5 = 'Exercise and sleep management help people with fibromyalgia.', example_ko_5 = '운동과 수면 관리는 섬유근육통 환자에게 도움이 돼요.' WHERE id = 'w_health_B2_33';
UPDATE words SET example_en_2 = 'Inflammatory bowel disease causes chronic digestive issues.', example_ko_2 = '염증성 장 질환은 만성 소화 문제를 유발해요.', example_en_3 = 'She avoids certain foods to manage her inflammatory condition.', example_ko_3 = '그녀는 염증성 질환을 관리하기 위해 특정 음식을 피해요.', example_en_4 = 'Anti-inflammatory drugs are commonly used for arthritis.', example_ko_4 = '항염증제는 관절염에 일반적으로 사용돼요.', example_en_5 = 'The inflammatory markers in his blood were elevated.', example_ko_5 = '혈액 속 염증 수치가 높았어요.' WHERE id = 'w_health_B2_34';
UPDATE words SET example_en_2 = 'Palliative care focuses on comfort rather than a cure.', example_ko_2 = '완화 치료는 치료보다 편안함에 초점을 맞춰요.', example_en_3 = 'She received palliative care in her final months.', example_ko_3 = '그녀는 마지막 몇 달 동안 완화 치료를 받았어요.', example_en_4 = 'Palliative treatment helped manage his pain effectively.', example_ko_4 = '완화 치료가 그의 통증을 효과적으로 관리하는 데 도움이 됐어요.', example_en_5 = 'The palliative care team provided emotional support to the family.', example_ko_5 = '완화 치료 팀이 가족에게 정서적 지원을 제공했어요.' WHERE id = 'w_health_B2_35';

