UPDATE words SET example_en_2 = 'The etiology of this disease is not yet fully understood.', example_ko_2 = '이 질병의 원인은 아직 완전히 밝혀지지 않았어요.', example_en_3 = 'Researchers are investigating the etiology of the syndrome.', example_ko_3 = '연구자들이 이 증후군의 원인을 조사하고 있어요.', example_en_4 = 'Understanding the etiology helps guide treatment strategies.', example_ko_4 = '원인을 이해하면 치료 전략을 수립하는 데 도움이 돼요.', example_en_5 = 'The etiology may involve both genetic and environmental factors.', example_ko_5 = '원인에는 유전적 요인과 환경적 요인이 모두 관여할 수 있어요.' WHERE id = 'w_health_C1_01';
UPDATE words SET example_en_2 = 'Comorbidity complicates treatment planning significantly.', example_ko_2 = '동반 질환은 치료 계획을 크게 복잡하게 만들어요.', example_en_3 = 'His comorbidity included both hypertension and diabetes.', example_ko_3 = '그의 동반 질환에는 고혈압과 당뇨병이 모두 포함됐어요.', example_en_4 = 'Patients with comorbidity often require specialist referral.', example_ko_4 = '동반 질환이 있는 환자는 종종 전문의 의뢰가 필요해요.', example_en_5 = 'Researchers studied the impact of comorbidity on recovery outcomes.', example_ko_5 = '연구자들이 동반 질환이 회복 결과에 미치는 영향을 연구했어요.' WHERE id = 'w_health_C1_02';
UPDATE words SET example_en_2 = 'Pharmacology explores how drugs interact with the body.', example_ko_2 = '약리학은 약물이 신체와 어떻게 상호 작용하는지 탐구해요.', example_en_3 = 'She studied pharmacology before becoming a clinical researcher.', example_ko_3 = '그녀는 임상 연구원이 되기 전에 약리학을 공부했어요.', example_en_4 = 'Advances in pharmacology have led to more effective treatments.', example_ko_4 = '약리학의 발전으로 더 효과적인 치료법이 생겼어요.', example_en_5 = 'The pharmacology of the new drug is well understood.', example_ko_5 = '새 약물의 약리학은 잘 이해되고 있어요.' WHERE id = 'w_health_C1_03';
UPDATE words SET example_en_2 = 'Endocrinology focuses on hormonal disorders.', example_ko_2 = '내분비학은 호르몬 장애에 집중해요.', example_en_3 = 'He trained in endocrinology to treat thyroid conditions.', example_ko_3 = '그는 갑상선 질환을 치료하기 위해 내분비학을 전공했어요.', example_en_4 = 'She was referred to the endocrinology department.', example_ko_4 = '그녀는 내분비학과로 의뢰됐어요.', example_en_5 = 'Endocrinology and metabolism are closely linked fields.', example_ko_5 = '내분비학과 신진대사는 밀접하게 연결된 분야예요.' WHERE id = 'w_health_C1_04';
UPDATE words SET example_en_2 = 'She specializes in neurology with a focus on movement disorders.', example_ko_2 = '그녀는 운동 장애에 초점을 맞춘 신경학을 전문으로 해요.', example_en_3 = 'Neurology covers conditions like epilepsy and multiple sclerosis.', example_ko_3 = '신경학은 간질과 다발성 경화증 같은 질환을 다뤄요.', example_en_4 = 'He was admitted to the neurology ward for observation.', example_ko_4 = '그는 관찰을 위해 신경학과 병동에 입원했어요.', example_en_5 = 'Neurology is one of the most complex medical specialties.', example_ko_5 = '신경학은 가장 복잡한 의학 전문 분야 중 하나예요.' WHERE id = 'w_health_C1_05';
UPDATE words SET example_en_2 = 'Prophylactic antibiotics are given before certain surgeries.', example_ko_2 = '일부 수술 전에 예방적 항생제를 투여해요.', example_en_3 = 'She takes a prophylactic medication to prevent migraines.', example_ko_3 = '그녀는 편두통을 예방하기 위해 예방적 약물을 복용해요.', example_en_4 = 'Prophylactic treatment is recommended for high-risk patients.', example_ko_4 = '고위험 환자에게는 예방적 치료를 권장해요.', example_en_5 = 'A prophylactic vaccine was developed to prevent the outbreak.', example_ko_5 = '발병을 예방하기 위해 예방 백신이 개발됐어요.' WHERE id = 'w_health_C1_06';
UPDATE words SET example_en_2 = 'Rheumatoid arthritis is an autoimmune condition.', example_ko_2 = '류마티스 관절염은 자가 면역 질환이에요.', example_en_3 = 'Autoimmune diseases are difficult to diagnose accurately.', example_ko_3 = '자가 면역 질환은 정확하게 진단하기가 어려워요.', example_en_4 = 'She manages her autoimmune condition with medication and diet.', example_ko_4 = '그녀는 약물과 식단으로 자가 면역 질환을 관리해요.', example_en_5 = 'Research into autoimmune diseases is advancing rapidly.', example_ko_5 = '자가 면역 질환에 대한 연구가 빠르게 발전하고 있어요.' WHERE id = 'w_health_C1_07';
UPDATE words SET example_en_2 = 'Elevated biomarkers may indicate early disease.', example_ko_2 = '상승된 생체 지표는 초기 질환을 나타낼 수 있어요.', example_en_3 = 'The biomarker levels returned to normal after treatment.', example_ko_3 = '치료 후 생체 지표 수치가 정상으로 돌아왔어요.', example_en_4 = 'Researchers identified a new biomarker for Alzheimer''s disease.', example_ko_4 = '연구자들이 알츠하이머병에 대한 새로운 생체 지표를 발견했어요.', example_en_5 = 'Blood tests can measure a range of important biomarkers.', example_ko_5 = '혈액 검사를 통해 다양한 중요한 생체 지표를 측정할 수 있어요.' WHERE id = 'w_health_C1_08';
UPDATE words SET example_en_2 = 'She has been in remission from lymphoma for two years.', example_ko_2 = '그녀는 2년 동안 림프종 완화 상태에 있어요.', example_en_3 = 'The patient achieved full remission after chemotherapy.', example_ko_3 = '환자는 항암 치료 후 완전한 완화 상태에 도달했어요.', example_en_4 = 'Remission does not always mean the disease is cured.', example_ko_4 = '완화가 항상 질병이 완치됐다는 것을 의미하지는 않아요.', example_en_5 = 'He monitors his health closely to detect any return from remission.', example_ko_5 = '그는 완화 상태에서 재발을 감지하기 위해 건강을 면밀히 모니터링해요.' WHERE id = 'w_health_C1_09';
UPDATE words SET example_en_2 = 'Deep vein thrombosis is a risk during long flights.', example_ko_2 = '심부정맥 혈전증은 장거리 비행 중 위험 요소예요.', example_en_3 = 'Anticoagulant drugs are used to treat thrombosis.', example_ko_3 = '항응고제는 혈전증 치료에 사용돼요.', example_en_4 = 'Thrombosis can lead to stroke or heart attack if untreated.', example_ko_4 = '혈전증은 치료하지 않으면 뇌졸중이나 심장마비로 이어질 수 있어요.', example_en_5 = 'Signs of thrombosis include swelling and pain in the leg.', example_ko_5 = '혈전증의 징후에는 다리의 붓기와 통증이 포함돼요.' WHERE id = 'w_health_C1_10';
UPDATE words SET example_en_2 = 'The oncology team met to discuss his case.', example_ko_2 = '종양학 팀이 그의 사례를 논의하기 위해 모였어요.', example_en_3 = 'She trained in oncology to specialize in cancer treatment.', example_ko_3 = '그녀는 암 치료를 전문으로 하기 위해 종양학을 전공했어요.', example_en_4 = 'Oncology research is advancing rapidly with new therapies.', example_ko_4 = '종양학 연구가 새로운 치료법으로 빠르게 발전하고 있어요.', example_en_5 = 'He was referred to the oncology department after the biopsy.', example_ko_5 = '그는 조직 검사 후 종양학과로 의뢰됐어요.' WHERE id = 'w_health_C1_11';
UPDATE words SET example_en_2 = 'Anaphylaxis requires immediate treatment with epinephrine.', example_ko_2 = '아나필락시스는 에피네프린으로 즉각적인 치료가 필요해요.', example_en_3 = 'She carries an EpiPen in case of anaphylaxis.', example_ko_3 = '그녀는 아나필락시스에 대비해 에피펜을 갖고 다녀요.', example_en_4 = 'Anaphylaxis can be triggered by food, insect stings, or medication.', example_ko_4 = '아나필락시스는 음식, 벌레 쏘임, 약물에 의해 유발될 수 있어요.', example_en_5 = 'Medical staff are trained to respond to anaphylaxis quickly.', example_ko_5 = '의료진은 아나필락시스에 신속하게 대응하도록 훈련받아요.' WHERE id = 'w_health_C1_12';
UPDATE words SET example_en_2 = 'She is studying hematology to become a blood specialist.', example_ko_2 = '그녀는 혈액 전문가가 되기 위해 혈액학을 공부하고 있어요.', example_en_3 = 'Hematology tests revealed an abnormally high white blood cell count.', example_ko_3 = '혈액학 검사에서 비정상적으로 높은 백혈구 수치가 나타났어요.', example_en_4 = 'Hematology disorders include anemia, leukemia, and hemophilia.', example_ko_4 = '혈액학적 장애에는 빈혈, 백혈병, 혈우병이 포함돼요.', example_en_5 = 'The hematology report showed no signs of malignancy.', example_ko_5 = '혈액학 보고서에는 악성 징후가 없었어요.' WHERE id = 'w_health_C1_13';
UPDATE words SET example_en_2 = 'Immunotherapy has transformed cancer treatment in recent years.', example_ko_2 = '면역 치료는 최근 몇 년간 암 치료를 변화시켰어요.', example_en_3 = 'She responded well to immunotherapy and entered remission.', example_ko_3 = '그녀는 면역 치료에 잘 반응해 완화 상태에 들어갔어요.', example_en_4 = 'Immunotherapy works by activating the body''s own immune defenses.', example_ko_4 = '면역 치료는 신체 자체의 면역 방어를 활성화해 작동해요.', example_en_5 = 'Side effects of immunotherapy vary widely between patients.', example_ko_5 = '면역 치료의 부작용은 환자마다 크게 다를 수 있어요.' WHERE id = 'w_health_C1_14';
UPDATE words SET example_en_2 = 'The catheter was inserted to drain the excess fluid.', example_ko_2 = '과잉 체액을 빼내기 위해 카테터를 삽입했어요.', example_en_3 = 'A urinary catheter was placed after the surgery.', example_ko_3 = '수술 후 요도 카테터를 삽입했어요.', example_en_4 = 'The nurse carefully cleaned the area around the catheter.', example_ko_4 = '간호사가 카테터 주변을 조심스럽게 소독했어요.', example_en_5 = 'He was uncomfortable but relieved once the catheter was removed.', example_ko_5 = '그는 불편했지만 카테터가 제거되자 안도했어요.' WHERE id = 'w_health_C1_15';
UPDATE words SET example_en_2 = 'Tachycardia can cause palpitations and shortness of breath.', example_ko_2 = '빈맥은 두근거림과 숨 가쁨을 유발할 수 있어요.', example_en_3 = 'She was diagnosed with supraventricular tachycardia.', example_ko_3 = '그녀는 상심실성 빈맥 진단을 받았어요.', example_en_4 = 'Stress and caffeine can trigger episodes of tachycardia.', example_ko_4 = '스트레스와 카페인은 빈맥 발작을 유발할 수 있어요.', example_en_5 = 'The cardiologist monitored his tachycardia with a wearable device.', example_ko_5 = '심장 전문의가 웨어러블 기기로 그의 빈맥을 모니터링했어요.' WHERE id = 'w_health_C1_16';
UPDATE words SET example_en_2 = 'Hemostasis is essential to prevent excessive bleeding.', example_ko_2 = '지혈은 과도한 출혈을 막는 데 필수예요.', example_en_3 = 'The surgeon achieved hemostasis before closing the wound.', example_ko_3 = '외과 의사는 상처를 봉합하기 전에 지혈을 완료했어요.', example_en_4 = 'Disorders of hemostasis can lead to dangerous bleeding.', example_ko_4 = '지혈 장애는 위험한 출혈로 이어질 수 있어요.', example_en_5 = 'The body initiates hemostasis within seconds of an injury.', example_ko_5 = '신체는 부상 후 몇 초 안에 지혈을 시작해요.' WHERE id = 'w_health_C1_17';
UPDATE words SET example_en_2 = 'Sepsis requires immediate hospitalization and treatment.', example_ko_2 = '패혈증은 즉각적인 입원과 치료가 필요해요.', example_en_3 = 'She developed sepsis following a post-surgical infection.', example_ko_3 = '그녀는 수술 후 감염으로 패혈증이 생겼어요.', example_en_4 = 'Sepsis can be life-threatening if not treated promptly.', example_ko_4 = '패혈증은 신속하게 치료하지 않으면 생명을 위협할 수 있어요.', example_en_5 = 'Early recognition of sepsis is critical for patient survival.', example_ko_5 = '패혈증의 조기 인식은 환자 생존에 중요해요.' WHERE id = 'w_health_C1_18';
UPDATE words SET example_en_2 = 'A pulmonary embolism can be fatal if not treated quickly.', example_ko_2 = '폐색전증은 신속하게 치료하지 않으면 치명적일 수 있어요.', example_en_3 = 'The embolism was detected on a CT scan.', example_ko_3 = 'CT 스캔에서 색전증이 발견됐어요.', example_en_4 = 'Anticoagulant therapy is used to treat embolism.', example_ko_4 = '항응고 요법은 색전증 치료에 사용돼요.', example_en_5 = 'Prevention of embolism includes early movement after surgery.', example_ko_5 = '색전증 예방에는 수술 후 조기 움직임이 포함돼요.' WHERE id = 'w_health_C1_19';
UPDATE words SET example_en_2 = 'Vasodilation increases blood flow to the muscles.', example_ko_2 = '혈관 확장은 근육으로의 혈류를 증가시켜요.', example_en_3 = 'The medication causes vasodilation and lowers blood pressure.', example_ko_3 = '이 약은 혈관 확장을 유발하고 혈압을 낮춰요.', example_en_4 = 'Vasodilation occurs naturally during exercise.', example_ko_4 = '혈관 확장은 운동 중 자연스럽게 발생해요.', example_en_5 = 'Heat causes vasodilation, which is why skin looks red.', example_ko_5 = '열은 혈관 확장을 유발하는데, 그래서 피부가 붉어 보여요.' WHERE id = 'w_health_C1_20';
UPDATE words SET example_en_2 = 'Cytokines play a key role in regulating immune responses.', example_ko_2 = '사이토카인은 면역 반응을 조절하는 데 핵심적인 역할을 해요.', example_en_3 = 'A cytokine storm can cause severe organ damage.', example_ko_3 = '사이토카인 폭풍은 심각한 장기 손상을 유발할 수 있어요.', example_en_4 = 'Scientists measured cytokine levels during the clinical trial.', example_ko_4 = '과학자들이 임상 시험 중 사이토카인 수치를 측정했어요.', example_en_5 = 'Inflammation is partly driven by the release of cytokines.', example_ko_5 = '염증은 부분적으로 사이토카인 방출에 의해 유발돼요.' WHERE id = 'w_health_C1_21';
UPDATE words SET example_en_2 = 'Histamine is released during an allergic reaction.', example_ko_2 = '히스타민은 알레르기 반응 중에 방출돼요.', example_en_3 = 'Antihistamines block the effects of histamine in the body.', example_ko_3 = '항히스타민제는 체내 히스타민의 효과를 차단해요.', example_en_4 = 'High histamine levels cause itching, swelling, and redness.', example_ko_4 = '높은 히스타민 수치는 가려움, 붓기, 발적을 유발해요.', example_en_5 = 'Some foods are naturally high in histamine.', example_ko_5 = '일부 음식에는 히스타민이 자연적으로 많이 들어 있어요.' WHERE id = 'w_health_C1_22';
UPDATE words SET example_en_2 = 'The swollen lymph node was biopsied for analysis.', example_ko_2 = '부어오른 림프절을 분석을 위해 생검했어요.', example_en_3 = 'Lymph nodes are part of the body''s immune defense system.', example_ko_3 = '림프절은 신체 면역 방어 시스템의 일부예요.', example_en_4 = 'Enlarged lymph nodes can indicate an infection or cancer.', example_ko_4 = '비대해진 림프절은 감염이나 암을 나타낼 수 있어요.', example_en_5 = 'The surgeon removed the affected lymph nodes during the operation.', example_ko_5 = '외과 의사가 수술 중 영향받은 림프절을 제거했어요.' WHERE id = 'w_health_C1_23';
UPDATE words SET example_en_2 = 'Fibrin forms a mesh that stops bleeding at a wound.', example_ko_2 = '피브린은 상처 부위에서 출혈을 막는 그물망을 형성해요.', example_en_3 = 'Without fibrin, blood clotting would not occur.', example_ko_3 = '피브린이 없으면 혈액 응고가 일어나지 않아요.', example_en_4 = 'Scientists are studying fibrin''s role in wound healing.', example_ko_4 = '과학자들이 상처 치유에서 피브린의 역할을 연구하고 있어요.', example_en_5 = 'Excess fibrin in the blood can lead to clotting disorders.', example_ko_5 = '혈액 속 과도한 피브린은 응고 장애로 이어질 수 있어요.' WHERE id = 'w_health_C1_24';
UPDATE words SET example_en_2 = 'There is a contraindication for this drug in pregnant women.', example_ko_2 = '임산부에게 이 약은 금기 사항이에요.', example_en_3 = 'The doctor checked for contraindications before prescribing.', example_ko_3 = '의사가 처방하기 전에 금기 사항을 확인했어요.', example_en_4 = 'Alcohol is a contraindication for many medications.', example_ko_4 = '알코올은 많은 약물의 금기 사항이에요.', example_en_5 = 'She read the label carefully for any contraindications.', example_ko_5 = '그녀는 금기 사항을 확인하기 위해 라벨을 주의 깊게 읽었어요.' WHERE id = 'w_health_C1_25';
UPDATE words SET example_en_2 = 'Her platelet count was dangerously low.', example_ko_2 = '그녀의 혈소판 수치가 위험할 정도로 낮았어요.', example_en_3 = 'Platelets help the blood clot after an injury.', example_ko_3 = '혈소판은 부상 후 혈액이 응고되도록 도와요.', example_en_4 = 'A platelet transfusion was required during surgery.', example_ko_4 = '수술 중 혈소판 수혈이 필요했어요.', example_en_5 = 'Low platelets can cause excessive bruising and bleeding.', example_ko_5 = '혈소판이 낮으면 과도한 멍과 출혈이 생길 수 있어요.' WHERE id = 'w_health_C1_26';
UPDATE words SET example_en_2 = 'Intubation was necessary to secure the patient''s airway.', example_ko_2 = '환자의 기도를 확보하기 위해 기관 삽관이 필요했어요.', example_en_3 = 'The medical team performed rapid intubation in the emergency room.', example_ko_3 = '의료팀이 응급실에서 신속한 기관 삽관을 시행했어요.', example_en_4 = 'Intubation is performed under sedation to reduce discomfort.', example_ko_4 = '기관 삽관은 불편함을 줄이기 위해 진정 상태에서 시행해요.', example_en_5 = 'The patient was removed from intubation after her condition improved.', example_ko_5 = '상태가 호전된 후 환자의 기관 삽관을 제거했어요.' WHERE id = 'w_health_C1_27';
UPDATE words SET example_en_2 = 'The lesion on his skin was removed and examined.', example_ko_2 = '그의 피부 병변을 제거하고 검사했어요.', example_en_3 = 'A lesion was found in the frontal lobe of her brain.', example_ko_3 = '그녀의 뇌 전두엽에서 병변이 발견됐어요.', example_en_4 = 'The lesion appeared benign on the initial scan.', example_ko_4 = '초기 스캔에서 병변은 양성으로 보였어요.', example_en_5 = 'Multiple lesions can indicate widespread disease.', example_ko_5 = '다발성 병변은 광범위한 질환을 나타낼 수 있어요.' WHERE id = 'w_health_C1_28';
UPDATE words SET example_en_2 = 'Hypoglycemia causes shakiness, sweating, and confusion.', example_ko_2 = '저혈당은 떨림, 발한, 혼란을 유발해요.', example_en_3 = 'He experienced hypoglycemia after skipping meals.', example_ko_3 = '그는 식사를 거른 후 저혈당을 경험했어요.', example_en_4 = 'Diabetic patients must monitor for signs of hypoglycemia.', example_ko_4 = '당뇨 환자들은 저혈당 징후를 모니터링해야 해요.', example_en_5 = 'Eating a small snack quickly resolves mild hypoglycemia.', example_ko_5 = '작은 간식을 빨리 먹으면 가벼운 저혈당이 빠르게 해소돼요.' WHERE id = 'w_health_C1_29';
UPDATE words SET example_en_2 = 'Prion diseases are rare but always fatal.', example_ko_2 = '프리온 질환은 드물지만 항상 치명적이에요.', example_en_3 = 'Scientists are studying how prions cause brain damage.', example_ko_3 = '과학자들이 프리온이 어떻게 뇌 손상을 유발하는지 연구하고 있어요.', example_en_4 = 'A prion is an abnormally folded protein that can spread.', example_ko_4 = '프리온은 퍼질 수 있는 비정상적으로 접힌 단백질이에요.', example_en_5 = 'There is currently no treatment for prion diseases.', example_ko_5 = '현재 프리온 질환에 대한 치료법이 없어요.' WHERE id = 'w_health_C1_30';
UPDATE words SET example_en_2 = 'She underwent renal dialysis three times per week.', example_ko_2 = '그녀는 일주일에 세 번 신장 투석을 받았어요.', example_en_3 = 'Renal function tests were included in the blood panel.', example_ko_3 = '신장 기능 검사가 혈액 패널에 포함됐어요.', example_en_4 = 'Chronic renal failure requires long-term management.', example_ko_4 = '만성 신부전은 장기적인 관리가 필요해요.', example_en_5 = 'The renal specialist adjusted her medication dosage.', example_ko_5 = '신장 전문의가 그녀의 약물 투여량을 조정했어요.' WHERE id = 'w_health_C1_31';
UPDATE words SET example_en_2 = 'He survived a myocardial infarction thanks to quick treatment.', example_ko_2 = '그는 신속한 치료 덕분에 심근경색에서 살아났어요.', example_en_3 = 'A myocardial infarction occurs when blood supply to the heart is blocked.', example_ko_3 = '심근경색은 심장으로의 혈액 공급이 차단될 때 발생해요.', example_en_4 = 'Immediate care after a myocardial infarction is critical.', example_ko_4 = '심근경색 후 즉각적인 처치가 매우 중요해요.', example_en_5 = 'Stents are often placed following a myocardial infarction.', example_ko_5 = '심근경색 후 스텐트를 삽입하는 경우가 많아요.' WHERE id = 'w_health_C1_32';
UPDATE words SET example_en_2 = 'A cerebrospinal fluid leak was detected after the injury.', example_ko_2 = '부상 후 뇌척수액 누출이 발견됐어요.', example_en_3 = 'The doctor performed a lumbar puncture to collect cerebrospinal fluid.', example_ko_3 = '의사가 뇌척수액을 채취하기 위해 요추 천자를 시행했어요.', example_en_4 = 'Cerebrospinal fluid analysis helps diagnose meningitis.', example_ko_4 = '뇌척수액 분석은 수막염 진단에 도움이 돼요.', example_en_5 = 'The cerebrospinal fluid results came back normal.', example_ko_5 = '뇌척수액 검사 결과가 정상으로 나왔어요.' WHERE id = 'w_health_C1_33';
UPDATE words SET example_en_2 = 'The cancer had spread through metastasis to the liver.', example_ko_2 = '암이 전이를 통해 간으로 퍼졌어요.', example_en_3 = 'Metastasis makes cancer significantly harder to treat.', example_ko_3 = '전이는 암을 치료하기 훨씬 더 어렵게 만들어요.', example_en_4 = 'Imaging tests are used to check for metastasis.', example_ko_4 = '영상 검사는 전이 여부를 확인하는 데 사용돼요.', example_en_5 = 'She was told there was no evidence of metastasis.', example_ko_5 = '전이의 증거가 없다는 말을 들었어요.' WHERE id = 'w_health_C1_34';
