UPDATE words SET example_en_2 = 'Pharmacokinetics describes how the body absorbs and eliminates drugs.', example_ko_2 = '약동학은 신체가 약물을 흡수하고 제거하는 방식을 설명해요.', example_en_3 = 'Age and body weight affect pharmacokinetics significantly.', example_ko_3 = '나이와 체중은 약동학에 큰 영향을 미쳐요.', example_en_4 = 'The pharmacokinetics of this drug make once-daily dosing possible.', example_ko_4 = '이 약물의 약동학은 하루 한 번 복용을 가능하게 해요.', example_en_5 = 'She researched the pharmacokinetics of the new compound.', example_ko_5 = '그녀는 새로운 화합물의 약동학을 연구했어요.' WHERE id = 'w_health_C2_01';
UPDATE words SET example_en_2 = 'Histopathology confirmed the presence of malignant cells.', example_ko_2 = '조직 병리학이 악성 세포의 존재를 확인했어요.', example_en_3 = 'The histopathology results guided the oncologist''s treatment plan.', example_ko_3 = '조직 병리학 결과가 종양 전문의의 치료 계획을 이끌었어요.', example_en_4 = 'Histopathology involves examining tissue samples under a microscope.', example_ko_4 = '조직 병리학은 현미경으로 조직 샘플을 검사하는 것을 포함해요.', example_en_5 = 'A histopathology report takes several days to prepare.', example_ko_5 = '조직 병리학 보고서는 준비하는 데 며칠이 걸려요.' WHERE id = 'w_health_C2_02';
UPDATE words SET example_en_2 = 'Immunosuppression is needed to prevent organ rejection.', example_ko_2 = '장기 거부 반응을 막기 위해 면역 억제가 필요해요.', example_en_3 = 'She takes immunosuppression therapy after her transplant.', example_ko_3 = '그녀는 이식 후 면역 억제 요법을 받고 있어요.', example_en_4 = 'Immunosuppression increases vulnerability to infections.', example_ko_4 = '면역 억제는 감염에 대한 취약성을 높여요.', example_en_5 = 'The dosage of immunosuppression was carefully calibrated.', example_ko_5 = '면역 억제의 투여량은 신중하게 조정됐어요.' WHERE id = 'w_health_C2_03';
UPDATE words SET example_en_2 = 'Nosocomial infections are a major challenge in hospitals.', example_ko_2 = '병원 감염은 병원에서 큰 과제예요.', example_en_3 = 'She contracted a nosocomial infection during her stay.', example_ko_3 = '그녀는 입원 기간 중 병원 감염에 걸렸어요.', example_en_4 = 'Hand hygiene is the best defense against nosocomial infections.', example_ko_4 = '손 위생이 병원 감염에 대한 최선의 방어책이에요.', example_en_5 = 'Preventing nosocomial infections requires strict protocols.', example_ko_5 = '병원 감염을 예방하려면 엄격한 프로토콜이 필요해요.' WHERE id = 'w_health_C2_04';
